PROCEDURE SP_wenke_getpartition                                                 
is                                                                              
    stempsql varchar2(400);                                                     
spartionname varchar2(30);                                                      
spartionkey varchar2(30);                                                       
spartitiontablespace varchar2(100);                                             
nnumber number(9);                                                              
                                                                                
begin                                                                           
                                                                                
delete wenke_newpartition;                                                      
commit;                                                                         
nnumber:=0;                                                                     

                                                                                
for tablerec in (select distinct table_name from user_tab_partitions where parti
tion_name like '%'||to_char(sysdate,'yymm')||'%'  ) loop                        
                                                                                
begin                                                                           
                                                                                
spartionname:='';                                                               
spartionkey:='';                                                                
spartitiontablespace:='';                                                       
                                                                                
select substr(partition_name,instr(partition_name,'_',-1)+1,length(partition_nam
e)-instr(partition_name,'_',-1)),                                               
                                                                                

substr(partition_name,1,instr(partition_name,'_',-1)-1),tablespace_name into spa
rtionkey,spartionname,spartitiontablespace                                      
                                                                                
from user_tab_partitions where table_name=tablerec.table_name and partition_name
 like '%'||to_char(sysdate,'yymm')||'%' and rownum=1;                           
                                                                                
                                                                                
if (length(spartionkey)=4) then                                                 
                                                                                
for rec in (SELECT to_char(add_months(sysdate,12),'yy')||substr('0'||to_char(row
num),-2,2) yymm FROM DUAL CONNECT BY rownum<=12) loop                           
                                                                                
begin                                                                           

stempsql:='ALTER TABLE '||tablerec.table_name||' ADD PARTITION '||spartionname||
'_'||rec.yymm||' VALUES LESS THAN (TO_DATE('''||                                
                                                                                
to_char(add_months(to_date(rec.yymm,'yymm'),1),'yyyy-mm-dd')||' 00:00:00'',''yyy
y-mm-dd hh24:mi:ss'')) tablespace '||spartitiontablespace||';';                 
                                                                                
nnumber:=nnumber+1;                                                             
                                                                                
insert into wenke_newpartition (createsql,sequence) values (stempsql,nnumber);  
commit;                                                                         
                                                                                
end;                                                                            
end loop;                                                                       

end if;                                                                         
                                                                                
                                                                                
if (length(spartionkey)=6) then                                                 
                                                                                
for rec in (SELECT to_char(add_months(sysdate,12),'yyyy')||substr('0'||to_char(r
ownum),-2,2) yymm FROM DUAL CONNECT BY rownum<=12) loop                         
                                                                                
begin                                                                           
stempsql:='ALTER TABLE '||tablerec.table_name||' ADD PARTITION '||spartionname||
'_'||rec.yymm||' VALUES LESS THAN (TO_DATE('''||                                
                                                                                
to_char(add_months(to_date(rec.yymm,'yyyymm'),1),'yyyy-mm-dd')||' 00:00:00'',''y

yyy-mm-dd hh24:mi:ss'')) tablespace '||spartitiontablespace||';';               
                                                                                
nnumber:=nnumber+1;                                                             
                                                                                
insert into wenke_newpartition (createsql,sequence) values (stempsql,nnumber);  
commit;                                                                         
                                                                                
end;                                                                            
end loop;                                                                       
end if;                                                                         
                                                                                
if (length(spartionkey)=8) then                                                 
                                                                                

for recday in (select to_char(to_date(to_char(add_months(sysdate,12),'yyyy')||'0
101','YYYYMMDD')+level-1,'YYYYMMDD') as yyyymmdd from dual connect by level <366
) loop                                                                          
                                                                                
begin                                                                           
stempsql:='ALTER TABLE '||tablerec.table_name||' ADD PARTITION '||spartionname||
'_'||recday.yyyymmdd||' VALUES LESS THAN (TO_DATE('''||                         
                                                                                
to_char(to_date(recday.yyyymmdd,'yyyymmdd')+1,'yyyy-mm-dd')||' 00:00:00'',''yyyy
-mm-dd hh24:mi:ss'')) tablespace '||spartitiontablespace||';';                  
                                                                                
nnumber:=nnumber+1;                                                             
insert into wenke_newpartition (createsql,sequence) values (stempsql,nnumber);  

commit;                                                                         
                                                                                
end;                                                                            
end loop;                                                                       
end if;                                                                         
end;                                                                            
end loop;                                                                       
end;                                                                            
Procedure spSynProgramBitRate                                                   
(                                                                               
  cObjectType                           In Varchar2,            --1:Program,2:Se
ries                                                                            
                                                                                

  iObjectID                             In Number,                              
  iStaffID                              In Number,                              
  iIsCommit                             In Number,                              
  Result                                In Out Number,                          
  ResultDesc                            In Out Varchar2                         
)                                                                               
Is                                                                              
  iMediaContentID      MediaContent.MediaContentID%Type;                        
  cVideoBitRateName    ContentDef.Name%Type;                                    
Begin                                                                           
  Result := 0;                                                                  
  ResultDesc := 'Successful!';                                                  
                                                                                

  Select min(p.MediaContentID)                                                  
    Into iMediaContentID                                                        
    From ProgramMediaContent p, MediaContent m                                  
   Where p.ObjType = cObjectType                                                
     And p.ObjID = iObjectID                                                    
     And p.MediaContentID = m.MediaContentID                                    
     And m.Type = '1'                                                           
     And m.status <> '2';                                                       
                                                                                
  if (iMediaContentID is not null) then                                         
  Select c.Name                                                                 
    Into cVideoBitRateName                                                      
    From MediaContent m, ContentDef c                                           

   Where m.MediaContentID = iMediaContentID                                     
     And m.ContentDefID = c.ContentDefID;                                       
  end if;                                                                       
  Update Program                                                                
     Set VideoBitRateName = cVideoBitRateName                                   
   Where ProgramID = iObjectID;                                                 
                                                                                
  If iIsCommit = 1 Then                                                         
     Commit;                                                                    
  End If;                                                                       
                                                                                
  Result := 0;                                                                  
  ResultDesc := to_char(iObjectID);                                             

Exception                                                                       
  When OTHERS Then                                                              
    Null;                                                                       
End;                                                                            
procedure spseriesremove                                                        
(                                                                               
  lseriesid                             in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              

                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spseriesremove: ';                               
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from series where seriesid = lseriesid;         
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     

  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    delete from assetidmap where assettype = '7' and mamid=lseriesid;           
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_series                         
    and objectid=lseriesid;                                                     
                                                                                
    update series                                                               
    set status = '9',lastupdatetime=sysdate                                     

    where seriesid = lseriesid;                                                 
                                                                                
    delete from seriesdtl where seriesid = lseriesid;                           
                                                                                
    delete from favoriteobjects                                                 
    where staffid=lstaffid and objid=lseriesid;                                 
                                                                                
    delete from directorydtl                                                    
    where objtype='2' and objid=lseriesid;                                      
                                                                                
    delete from categorydtl where objid=lseriesid and objtype='1'               
    and categoryid in (select categoryid from category where domainid is null); 
                                                                                

    delete from bundledcontentdtl where objid=lseriesid and objtype='4'         
    and bundledcontentid in (select bundledcontentid from bundledcontent where d
omainid is null);                                                               
                                                                                
                                                                                
    delete from seriescasts where seriesid = lseriesid;                         
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          

    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  

  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
