  sKeywords                             in out varchar2,                        
  sRMediaCode                           in out varchar2,                        
  scid                                  in out varchar2,                        
  svid                                  in out varchar2,                        
	sKEYMAN                               in out varchar2,                         
	sTAGLIST 															in out varchar2,                                       
	sDIRECTORINFO													in out varchar2,                                     
	sSCREENWRITERINFO											in out varchar2,                                   
	sVIDEOID															in out varchar2,                                        
	sEXTENDFIELD1													in out varchar2,                                     
	sEXTENDFIELD2													in out varchar2,                                     
	sEXTENDFIELD3													in out varchar2,                                     

