)                                                                               
is                                                                              
                                                                                
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spseriesquery: ';                                
begin                                                                           

  result := 0;                                                                  
                                                                                
  begin                                                                         
    select count(1)                                                             
    into lcounter                                                               
    from series                                                                 
    where seriesid = lseriesid;                                                 
    if (lcounter != 1) then                                                     
