    end if;                                                                     
                                                                                
    select name,code,code2,status,vspid,alias,                                  
           title_sort_name,title_search_name,orgairdate,                        
           to_char(validthrough,'yyyymmddhh24miss'),to_char(validuntil,'yyyymmdd
hh24miss'),                                                                     
                                                                                
           price,volumcount,description,memo,                                   
           kpeople,director,scriptwriter,compere,guest,reporter,opincharge,genre
,releaseyear,labeltype,seriestype,copyright,contentprovider,type1,lockflag,origi
nalcountry,pgmcategory,pgmsndclass,editmode,labelids,autoflag,rating,newprice,ta
gs,viewpoint,starlevel,awards,contractnum,incomplete,                           
                                                                                

           cptag,cpactivetime,recycleflag,operater,to_char(joinrecycletime,'yyyy
mmddhh24miss'),overdueTime,cpdescription,cpstatus,needReleaseFlag,newprice2,newp
rice3,pgmcategoryid,pgmsndclassid,DefinitionFlag,Macrovision,Keywords,RMediaCode
,cid,vid,KEYMAN,TAGLIST,DIRECTORINFO,SCREENWRITERINFO,VIDEOID,EXTENDFIELD1,EXTEN
DFIELD2,EXTENDFIELD3,EXTENDFIELD4,EXTENDFIELD5,PGMCATEGORYDTLID,audioMsgType    
                                                                                
    into sname,scode,scode2,sstatus,lvspid,salias,                              
         stitle_sort_name,stitle_search_name,sorgairdate,                       
         dvalidthrough,dvaliduntil,                                             
         fprice,lvolumcount,sdescription,smemo,                                 
         skpeople,sdirector,sscriptwriter,scompere,sguest,sreporter,sopincharge,
sgenre,sreleaseyear,llabeltype,sseriestype,scopyright,scontentprovider,stype1,sl
ockflag,sOriginalCountry,spgmcategory,spgmsndclass,seditmode,slabelids,sautoflag

,srating,snewprice,stags,sviewpoint,sstarlevel,sawards,scontractnum,sIncomplete,
                                                                                
                                                                                
         scptag,scpactivetime,srecycleflag,soperater,djoinrecycletime,scpoverdue
time,scpdescription,scpstatus,sneedReleaseFlag,snewprice2,snewprice3,spgmcategor
yid,spgmsndclassid,sDefinitionFlag,sMacrovision,sKeywords,sRMediaCode,scid,svid,
sKEYMAN,sTAGLIST,sDIRECTORINFO,sSCREENWRITERINFO,sVIDEOID,sEXTENDFIELD1,sEXTENDF
IELD2,sEXTENDFIELD3,sEXTENDFIELD4,sEXTENDFIELD5,sPGMCATEGORYDTLID,sAudioMsgType 
                                                                                
    from series                                                                 
    where seriesid = lseriesid;                                                 
                                                                                
  exception                                                                     

  when others then                                                              
