PROCEDURE spSeriesModify                                                        
(                                                                               
  lseriesid                             in number,                              
  lvspid                                in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sstatus                               in varchar2,                            
  sIncomplete                           in varchar2,                            

  scontractnum                          in varchar2,                            
  scptag                                in varchar2,                            
  scpactivetime                         in varchar2,                            
  salias                                in varchar2,                            
  stitle_sort_name                      in varchar2,                            
  stitle_search_name                    in varchar2,                            
  sorgairdate                           in varchar2,                            
  dvalidthrough                         in varchar2,                            
  dvaliduntil                           in varchar2,                            
  fprice                                in number,                              
  lvolumcount                           in number,                              
  sdescription                          in varchar2,                            
  smemo                                 in varchar2,                            

  skpeople                              in varchar2,                            
  sdirector                             in varchar2,                            
  sscriptwriter                         in varchar2,                            
  scompere                              in varchar2,                            
  sguest                                in varchar2,                            
  sreporter                             in varchar2,                            
  sopincharge                           in varchar2,                            
  sgenre                                in varchar2,                            
  sreleaseyear                          in varchar2,                            
  llabeltype                            in number,                              
  sseriestype                           in varchar2,                            
  scopyright                            in varchar2,                            
  scontentprovider                      in varchar2,                            

  scolumnpath                           in varchar2,                            
  stype1                                in varchar2,                            
  slockflag                             in varchar2,                            
  spgmcategory                          in varchar2,                            
  spgmsndclass                          in varchar2,                            
  sOriginalCountry                      in varchar2,                            
  seditmode                             in varchar2,                            
  srating                               in varchar2,                            
  snewprice                             in varchar2,                            
  stags                                 in varchar2,                            
  sviewpoint                            in varchar2,                            
  sstarlevel                            in varchar2,                            
  sawards                               in varchar2,                            

  slabelids                             in varchar2,                            
  sautoflag                             in varchar2,                            
  srecycleflag                          in varchar2,                            
  soperater                             in varchar2,                            
  djoinrecycletime                      in varchar2,                            
  scpoverduetime                        in varchar2,                            
  scpdescription                        in varchar2,                            
  scpstatus                             in varchar2,                            
  sneedReleaseFlag                      in varchar2,                            
  snewprice2                            in varchar2,                            
  snewprice3                            in varchar2,                            
  spgmcategoryid                        in varchar2,                            
  spgmsndclassid                        in varchar2,                            

  sDefinitionFlag                       in varchar2,                            
  sMacrovision                          in varchar2,                            
  sKeywords                             in varchar2,                            
  sRMediaCode                           in varchar2,                            
  scid                                  in varchar2,                            
  svid                                  in varchar2,                            
  sKEYMAN                               in varchar2,                            
	sTAGLIST                              in varchar2,                             
	sDIRECTORINFO                          in varchar2,                            
	sSCREENWRITERINFO											in varchar2,                                       
	sVIDEOID                              in varchar2,                             
	sEXTENDFIELD1                          in varchar2,                            
	sEXTENDFIELD2													in varchar2,                                         

	sEXTENDFIELD3													in varchar2,                                         
	sEXTENDFIELD4													in varchar2,                                         
	sEXTENDFIELD5													in varchar2,                                         
	sPGMCATEGORYDTLID                     in varchar2,                             
	sAudioMsgType							in varchar2,                                               
  lstaffid                              in varchar2,                            
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  dvalidthrough_temp date;                                                      

  dvaliduntil_temp date;                                                        
  sstatus_temp char(1) := '1';                                                  
  fprice_temp number(12,2) := 0;                                                
  lcounter number(9);                                                           
  llabeltype_temp number(4) := 0;                                               
  llabeltype_counter number(9);                                                 
  sseriestype_temp varchar(160) := '0';                                         
  functionname varchar(40) := 'spseriesmodify: ';                               
  djoinrecycletime_temp date;                                                   
                                                                                
  cursor c_program is select * from program p                                   
  where exists (select sd.programid from seriesdtl sd where sd.seriesid = lserie
sid and sd.programid = p.programid);                                            

                                                                                
  c_row c_program%rowtype;                                                      
                                                                                
  str_list type_split := type_split();                                          
  l_row number(9);                                                              
  directory_counter number(9);                                                  
  parent_id number(9);                                                          
  directory_id_temp number(9);                                                  
  directory_last_id number(9);                                                  
  lcontentproviderid_temp number(9);                                            
  lcopyrighterid_temp number(9);                                                
                                                                                
begin                                                                           

  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from series where seriesid = lseriesid;         
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             

    into lcounter                                                               
    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('spid not exist in table vsp.');                     
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                

  if (sname is null) then                                                       
    result := -176004;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    if (dvalidthrough is not null) then                                         
      select to_date(dvalidthrough,'yyyymmddhh24miss')                          
      into dvalidthrough_temp                                                   
      from dual;                                                                

    else                                                                        
      dvalidthrough_temp := null;                                               
    end if;                                                                     
    if (djoinrecycletime is null) then                                          
      djoinrecycletime_temp := null;                                            
      else                                                                      
      select to_date(djoinrecycletime,'yyyymmddhh24miss')                       
      into djoinrecycletime_temp from dual;                                     
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            

    end if;                                                                     
    result := -176011;                                                          
    resultdesc := 'the format of validthrough is not correct.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of validthrough is not correct.');         
    return;                                                                     
  end;                                                                          
                                                                                
  begin                                                                         
    if (dvaliduntil is not null) then                                           
      select to_date(dvaliduntil,'yyyymmddhh24miss')                            
      into dvaliduntil_temp                                                     
      from dual;                                                                

    else                                                                        
      dvaliduntil_temp := null;                                                 
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -176011;                                                          
    resultdesc := 'the format of validuntil is not correct.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of validuntil is not correct.');           
    return;                                                                     

  end;                                                                          
                                                                                
  if (dvaliduntil_temp is not null and                                          
      dvalidthrough_temp is not null and                                        
      dvaliduntil_temp <= dvalidthrough_temp) then                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -176012;                                                          
    resultdesc := 'validuntil must later than validthrough.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('validuntil must later than validthrough.');           
    return;                                                                     

  end if;                                                                       
                                                                                
  if (fprice is not null) then                                                  
    fprice_temp := fprice;                                                      
  end if;                                                                       
                                                                                
  if (sstatus is not null) then                                                 
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from staff                                                                    

  where staffid = lstaffid;                                                     
  if (lcounter <= 0) then                                                       
    result := -176016;                                                          
    resultdesc := 'staffid not exist in table staff.';                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('staffid not exist in table staff.');                  
    return;                                                                     
  end if;                                                                       
                                                                                
  if (llabeltype is not null) then                                              
    select count(1)                                                             
    into llabeltype_counter                                                     
    from labeltype                                                              

    where labeltype = llabeltype;                                               
    if (llabeltype_counter <= 0) then                                           
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170401;                                                        
      resultdesc := 'labeltype not exist in table labeltype.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('labeltype not exist in table labeltype.');          
      return;                                                                   
    end if;                                                                     
    llabeltype_temp := llabeltype;                                              
  end if;                                                                       

                                                                                
  if (sseriestype is not null) then                                             
    sseriestype_temp := sseriestype;                                            
  end if;                                                                       
                                                                                
   if(scontentprovider is not null) then                                        
      select count(1)                                                           
      into lcounter                                                             
      from contentprovider                                                      
      where name = scontentprovider;                                            
      if(lcounter >= 1) then                                                    
         select contentproviderid                                               
         into lcontentproviderid_temp                                           

         from contentprovider                                                   
         where name = scontentprovider and rownum=1;                            
      else                                                                      
        select contentproviderid.nextval into lcontentproviderid_temp from dual;
                                                                                
                                                                                
        insert into contentprovider(contentproviderid,vspid,name,createdate,last
updatetime)                                                                     
                                                                                
        values(lcontentproviderid_temp,lvspid,scontentprovider,sysdate,sysdate);
                                                                                
                                                                                
        end if;                                                                 

    end if;                                                                     
                                                                                
    if(scopyright is not null) then                                             
      select count(1)                                                           
      into lcounter                                                             
      from copyrighter                                                          
      where name = scopyright;                                                  
      if(lcounter >= 1) then                                                    
         select copyrighterid                                                   
         into lcopyrighterid_temp                                               
         from copyrighter                                                       
         where name = scopyright;                                               
      else                                                                      

        select copyrighterid.nextval into lcopyrighterid_temp from dual;        
        insert into copyrighter(copyrighterid,name,createdate,lastupdatetime)   
        values(lcopyrighterid_temp,scopyright,sysdate,sysdate);                 
        end if;                                                                 
    end if;                                                                     
                                                                                
  begin                                                                         
                                                                                
    update globalcodemap                                                        
    set status = decode(sstatus_temp,'9','1','0')                               
    where objecttype=ctmsconstant_def.globaltype_series                         
    and objectid=lseriesid;                                                     
                                                                                

    update series                                                               
    set vspid = lvspid,                                                         
        name = sname,                                                           
        code2 = scode2,                                                         
        status = sstatus_temp,                                                  
        incomplete = sIncomplete,                                               
        alias = salias,                                                         
        title_sort_name = stitle_sort_name,                                     
        title_search_name = stitle_search_name,                                 
        orgairdate = sorgairdate,                                               
        validthrough = dvalidthrough_temp,                                      
        validuntil = dvaliduntil_temp,                                          
        price = fprice_temp,                                                    

        volumcount = lvolumcount,                                               
        description = sdescription,                                             
        memo = smemo,                                                           
        kpeople     = skpeople,                                                 
        director    = sdirector,                                                
        scriptwriter= sscriptwriter,                                            
        compere     = scompere,                                                 
        guest       = sguest,                                                   
        reporter    = sreporter,                                                
        opincharge  = sopincharge,                                              
        genre       = sgenre,                                                   
        releaseyear = sreleaseyear,                                             
        labeltype   = llabeltype_temp,                                          

        contractnum = scontractnum,                                             
        seriestype  = sseriestype_temp,                                         
        copyright = scopyright,                                                 
        contentprovider = scontentprovider,                                     
        lastupdatetime = sysdate,                                               
        type1         = stype1,                                                 
        lockflag      = slockflag,                                              
        pgmcategory   = spgmcategory,                                           
        pgmsndclass   = spgmsndclass,                                           
        ORIGINALCOUNTRY = sOriginalCountry,                                     
        contentproviderid = lcontentproviderid_temp,                            
        copyrighterid = lcopyrighterid_temp,                                    
        editmode = seditmode,                                                   

        labelids = slabelids,                                                   
        autoflag = sautoflag,                                                   
        rating = srating,                                                       
        newprice = snewprice,                                                   
        tags = stags,                                                           
        viewpoint = sviewpoint,                                                 
        starlevel = sstarlevel,                                                 
        awards = sawards,                                                       
        recycleflag = srecycleflag,                                             
        cptag = scptag,                                                         
        cpactivetime = scpactivetime,                                           
        operater = soperater,                                                   
        joinrecycletime = djoinrecycletime_temp,                                

        overdueTime = scpoverduetime,                                           
        cpdescription = scpdescription,                                         
        cpstatus = scpstatus,                                                   
        needReleaseFlag = sneedReleaseFlag,                                     
        newprice2 = snewprice2,                                                 
        newprice3 = snewprice3,                                                 
        pgmcategoryid = spgmcategoryid,                                         
        pgmsndclassid = spgmsndclassid,                                         
        DefinitionFlag = sDefinitionFlag,                                       
        Macrovision = sMacrovision,                                             
        Keywords = sKeywords,                                                   
        RMediaCode = sRMediaCode,                                               
        cid = scid,                                                             

        vid = svid,                                                             
		    KEYMAN = sKEYMAN,                                                         
				TAGLIST = sTAGLIST,                                                         
				DIRECTORINFO = sDIRECTORINFO,                                               
				SCREENWRITERINFO = sSCREENWRITERINFO,                                       
				VIDEOID = sVIDEOID,                                                         
				EXTENDFIELD1 = sEXTENDFIELD1,                                               
				EXTENDFIELD2 = sEXTENDFIELD2,                                               
				EXTENDFIELD3 = sEXTENDFIELD3,                                               
				EXTENDFIELD4 = sEXTENDFIELD4,                                               
				EXTENDFIELD5 = sEXTENDFIELD5,                                               
				PGMCATEGORYDTLID = sPGMCATEGORYDTLID,                                       
				audioMsgType = sAudioMsgType                                                

    where seriesid = lseriesid;                                                 
                                                                                
    for c_row in c_program loop                                                 
      update program set LICENSINGWINDOWSTART = dvalidthrough_temp, LICENSINGWIN
DOWEND = dvaliduntil_temp                                                       
                                                                                
      where programid = c_row.programid;                                        
    end loop;                                                                   
                                                                                
    if (scolumnpath is not null) then                                           
      str_list := split(scolumnpath, '@');                                      
      l_row := str_list.first;                                                  
      while (l_row is not null)                                                 

      loop                                                                      
        dbms_output.put_line(trim(str_list(l_row)));                            
        if (parent_id is null) then                                             
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid is null and vspid=lvspid;                         
                                                                                
          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),null,l_row-1,lvspid,sysdate
);                                                                              
                                                                                
          else                                                                  

            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid is null and vspid=lvspid;                    
                                                                                
          end if;                                                               
        else                                                                    
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid=parent_id and vspid=lvspid;                       
                                                                                
          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),parent_id,l_row-1,lvspid,sy
sdate);                                                                         

                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid=parent_id and vspid=lvspid;                  
                                                                                
          end if;                                                               
        end if;                                                                 
        parent_id := directory_id_temp;                                         
        l_row := str_list.next(l_row);                                          
      end loop;                                                                 
                                                                                
      l_row := str_list.last;                                                   
      if (l_row is not null) then                                               

        directory_last_id := directory_id_temp;                                 
        delete from directorydtl where objtype='2' and objid=lseriesid;         
        insert into directorydtl(directorydtlid,directoryid,objtype,objid,create
date) values(directorydtlid.nextval,directory_last_id,'2',lseriesid,sysdate);   
                                                                                
      end if;                                                                   
    end if;                                                                     
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
  exception                                                                     

  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     

  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spseriesdtlremove                                                     
(                                                                               
  lseriesdtlid                          in number,                              
  lseriesid                             in number,                              
  lprogramid                            in number,                              

  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lseriesdtlid_temp number(9);                                                  
  functionname varchar(40) := 'spseriesdtlremove: ';                            
begin                                                                           
  result := 0;                                                                  
                                                                                

  if (lseriesdtlid is null) then                                                
    select count(1)                                                             
    into lcounter                                                               
    from seriesdtl                                                              
    where seriesid = lseriesid and programid = lprogramid;                      
    if (lcounter != 1) then                                                     
      result := 0;                                                              
      resultdesc := 'no row affected.';                                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('no row affected.');                                 
      return;                                                                   
    end if;                                                                     
                                                                                

    select seriesdtlid                                                          
    into lseriesdtlid_temp                                                      
    from seriesdtl                                                              
    where seriesid = lseriesid and programid = lprogramid;                      
  else                                                                          
    lseriesdtlid_temp := lseriesdtlid;                                          
  end if;                                                                       
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   

    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from staff                                                                    
  where staffid = lstaffid;                                                     
  if (lcounter <= 0) then                                                       
    result := -176306;                                                          
    resultdesc := 'staffid not exist in table staff.';                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('staffid not exist in table staff.');                  
    return;                                                                     

  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    delete from assetidmap where assettype = 'I' and mamid=lseriesdtlid_temp;   
                                                                                
    delete from seriesdtl where seriesdtlid = lseriesdtlid_temp;                
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     

    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  if iiscommit = 1 then                                                         
    commit work;                                                                

  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spseriesdtlquery                                                      
(                                                                               
  lseriesdtlid                          in number,                              
  lseriesid                             in number,                              
  lprogramid                            in number,                              
  lseq                                  in out number,                          
  lstockoutflag                         in out varchar2,                        
  result                                in out number,                          

  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  functionname varchar(40) := 'spseriesdtlquery: ';                             
begin                                                                           
  result := 0;                                                                  
                                                                                
  begin                                                                         
  	if (lseriesdtlid is null) then                                               
    	select seq,stockoutflag into lseq, lstockoutflag from seriesdtl where serie
sid = lseriesid and programid = lprogramid;                                     
                                                                                

    else                                                                        
    	select seq,stockoutflag into lseq, lstockoutflag from seriesdtl where serie
sdtlid = lseriesdtlid;                                                          
                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr

( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  result := 0;                                                                  
  resultdesc := to_char(lseriesdtlid);                                          
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
