procedure spseriesdtladd                                                        
(                                                                               
  lseriesdtlid                          in number,                              
  lseriesid                             in number,                              
  lprogramid                            in number,                              
  lseq                                  in number,                              
  lstockoutflag                         in varchar2,                            
  lstaffid                              in number,                              

  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lseriesdtlid_temp number(9);                                                  
  lseq_temp number(9);                                                          
  lcounter number(9);                                                           
  supdateflag char(1);                                                          
  existmappingflag char(1);                                                     
  ContentProvider_temp VARCHAR2(100);                                           
  Copyright_temp       VARCHAR2(100);                                           

  ContentProviderID_temp number(9);                                             
  CopyrightID_temp       number(9);                                             
  OriginalCounttry_temp VARCHAR2(100);                                          
  functionname varchar(40) := 'spseriesdtladd: ';                               
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from series                                                                   
  where seriesid = lseriesid;                                                   
  if (lcounter != 1) then                                                       
    result := -176301;                                                          

    resultdesc := 'seriesid must exist in table series!';                       
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('seriesid must exist in table series!');               
    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from program                                                                  
  where programid = lprogramid;                                                 
  if (lcounter <= 0) then                                                       
    result := -176304;                                                          
    resultdesc := 'programid does not exist in table program.';                 

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('programid does not exist in table program.');         
    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from staff                                                                    
  where staffid = lstaffid;                                                     
  if (lcounter <= 0) then                                                       
    result := -176306;                                                          
    resultdesc := 'staffid not exist in table staff.';                          
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('staffid not exist in table staff');                   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lseq is null) then                                                        
    lseq_temp := 0;                                                             
  else                                                                          
    lseq_temp := lseq;                                                          
  end if;                                                                       
                                                                                
  supdateflag := '0';                                                           
  select count(1)                                                               
  into lcounter                                                                 

  from seriesdtl                                                                
  where seriesid = lseriesid                                                    
  and programid = lprogramid;                                                   
  if (lcounter > 0) then                                                        
    supdateflag := '1';                                                         
  end if;                                                                       
                                                                                
  existmappingflag := '0';                                                      
  select count(1)                                                               
  into lcounter                                                                 
  from seriesdtl                                                                
  where programid = lprogramid;                                                 
  if (lcounter > 0) then                                                        

    existmappingflag := '1';                                                    
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
  	if(supdateflag = '1') then                                                   
  		select seriesdtlid into lseriesdtlid_temp from seriesdtl                    
  		where seriesid = lseriesid and programid = lprogramid;                      
                                                                                
  		update seriesdtl set seq=lseq_temp where seriesdtlid = lseriesdtlid_temp;   
  	else                                                                         
  		if (lseriesdtlid is null) then                                              
  		  select seriesdtlid.nextval into lseriesdtlid_temp from dual;              

  		else                                                                        
  		  lseriesdtlid_temp := lseriesdtlid;                                        
  		end if;                                                                     
  		if(existmappingflag = '1') then                                             
  			  result := 0;                                                             
      		resultdesc := 'The programid already exists mapping.';                  
      		return;                                                                 
  		end if;                                                                     
  		insert into seriesdtl(seriesdtlid,seriesid,programid,seq,stockoutflag )     
  		values(lseriesdtlid_temp,lseriesid,lprogramid,lseq_temp ,lstockoutflag);    
                                                                                
		select CONTENTPROVIDER,COPYRIGHT,originalcountry,CONTENTPROVIDERID,COPYRIGHTER
ID into ContentProvider_temp ,Copyright_temp,OriginalCounttry_temp,ContentProvid

erID_temp,CopyrightID_temp                                                      
                                                                                
                from series where seriesid =lseriesid;                          
                                                                                
                update program set CONTENTPROVIDER = ContentProvider_temp ,COPYR
IGHT = Copyright_temp,originalcountry = OriginalCounttry_temp,CONTENTPROVIDERID=
ContentProviderID_temp,COPYRIGHTERID=CopyrightID_temp                           
                                                                                
                where programid = lprogramid;                                   
                                                                                
		update program set LICENSINGWINDOWSTART = (select s.VALIDTHROUGH from series s
 where s.seriesid = lseriesid),                                                 
                                                                                

		LICENSINGWINDOWEND = (select s.VALIDUNTIL from series s where s.seriesid = lse
riesid)                                                                         
                                                                                
		where programid = lprogramid;                                                 
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler

rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  

  resultdesc := to_char(lseriesdtlid_temp);                                     
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
PROCEDURE spSeriescastsRemove                                                   
(                                                                               
  lSERIESCASTID                         IN number,                              
  lSERIESID                             IN number,                              
  lCASTACTROLEID                        IN number,                              
  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               

IS                                                                              
  lCounter number(9);                                                           
  lSERIESCASTID_TEMP number(9);                                                 
  FunctionName varchar(40) := 'spSeriescastsRemove: ';                          
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  IF (lSERIESCASTID is null) THEN                                               
    select count(1)                                                             
    into lCounter                                                               
    from SERIESCASTS                                                            
    where SERIESID = lSERIESID                                                  
    and CASTACTROLEID = lCASTACTROLEID;                                         

    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    select SERIESCASTID                                                         
    into lSERIESCASTID_TEMP                                                     
    from SERIESCASTS                                                            
    where SERIESID = lSERIESID                                                  
    and CASTACTROLEID = lCASTACTROLEID;                                         

  ELSE                                                                          
    lSERIESCASTID_TEMP := lSERIESCASTID;                                        
  END IF;                                                                       
                                                                                
  BEGIN                                                                         
    select count(1) into lCounter from SERIESCASTS where SERIESCASTID = lSERIESC
ASTID_TEMP;                                                                     
                                                                                
    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 

      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    delete from SERIESCASTS where SERIESCASTID = lSERIESCASTID_TEMP;            
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                

    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            

PROCEDURE spSeriescastsAdd                                                      
(                                                                               
  lSERIESCASTID                         IN number,                              
  LSERIESID	                            IN number,                              
  lCASTACTROLEID                        IN number,                              
  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              
  lCounter number(9);                                                           
  lSERIESCASTID_TEMP number(9);                                                 

  FunctionName varchar(40) := 'spSeriescastsAdd: ';                             
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter FROM Castactrole                                
  where CASTACTROLEID = lCASTACTROLEID;                                         
  IF (lCounter <= 0) THEN                                                       
    result := -170611;                                                          
    ResultDesc := 'CASTACTROLEID not found.';                                   
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('CASTACTROLEID not found.');                           
    RETURN;                                                                     
  END IF;                                                                       

                                                                                
  select count(1) into lCounter FROM series                                     
  where SERIESID = LSERIESID;                                                   
  IF (lCounter <= 0) THEN                                                       
    result := -170613;                                                          
    ResultDesc := 'SERIESID not found.';                                        
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('SERIESID not found.');                                
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  BEGIN                                                                         
                                                                                

    select count(1) into lCounter FROM seriescasts                              
  where seriesid = LSERIESID and castactroleid = lCASTACTROLEID;                
  IF (lCounter = 0) THEN                                                        
   IF (lSERIESCASTID is null) THEN                                              
      select SERIESCASTID.nextval into lSERIESCASTID_TEMP from dual;            
    ELSE                                                                        
      lSERIESCASTID_TEMP := lSERIESCASTID;                                      
    END IF;                                                                     
                                                                                
    insert into seriescasts(seriescastid,seriesid,castactroleid)                
    values(lSERIESCASTID_TEMP,LSERIESID,lCASTACTROLEID);                        
  END IF;                                                                       
                                                                                

  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                

    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result := 0;                                                                  
  ResultDesc := to_char(lSERIESCASTID_TEMP);                                    
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
procedure spseriesadd                                                           
(                                                                               
  lseriesid                             in number,                              
  lvspid                                in number,                              

  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sstatus                               in varchar2,                            
  salias                                in varchar2,                            
  stitle_sort_name                      in varchar2,                            
  stitle_search_name                    in varchar2,                            
  sorgairdate                           in varchar2,                            
  dvalidthrough                         in varchar2,                            
  dvaliduntil                           in varchar2,                            
  fprice                                in number,                              
  lvolumcount                           in number,                              
  sdescription                          in varchar2,                            

  smemo                                 in varchar2,                            
  skpeople                              in varchar2,                            
  sdirector                             in varchar2,                            
  sscriptwriter                         in varchar2,                            
  scompere                              in varchar2,                            
  sguest                                in varchar2,                            
  sreporter                             in varchar2,                            
  sopincharge                           in varchar2,                            
  sgenre                                in varchar2,                            
  sreleaseyear                          in varchar2,                            
  llabeltype                            in number,                              
  sseriestype                           in varchar2,                            
  scopyright                            in varchar2,                            

  scontentprovider                      in varchar2,                            
  scolumnpath                           in varchar2,                            
  stype1                                in varchar2,                            
  slockflag                             in varchar2,                            
  spgmcategory                          in varchar2,                            
  spgmsndclass                          in varchar2,                            
  sOriginalCountry                      in varchar2,                            
  scontractnum                          in varchar2,                            
  scptag                                in varchar2,                            
  scpactivetime                         in varchar2,                            
  sIncomplete                           in varchar2,                            
  seditmode                             in varchar2,                            
  sRating                               in varchar2,                            

  sNewPrice                             in varchar2,                            
  stags                                 in varchar2,                            
  sviewpoint                            in varchar2,                            
  sstarlevel                            in varchar2,                            
  sawards                               in varchar2,                            
  slabelids                             in varchar2,                            
  sautoflag                             in varchar2,                            
  srecycleflag                          in varchar2,                            
  soperater                             in varchar2,                            
  djoinrecycletime                      in varchar2,                            
  scpoverduetime                        in varchar2,                            
  scpdescription                        in varchar2,                            
  scpstatus                             in varchar2,                            

  sneedReleaseFlag                      in varchar2,                            
  snewprice2                            in varchar2,                            
  snewprice3                            in varchar2,                            
  spgmcategoryid                        in varchar2,                            
  spgmsndclassid                        in varchar2,                            
  sDefinitionFlag                       in varchar2,                            
  sMacrovision                          in varchar2,                            
  sKeywords                             in varchar2,                            
  sRMediaCode                           in varchar2,                            
  scid                                  in varchar2,                            
  svid                                  in varchar2,                            
  sKEYMAN                               in varchar2,                            
	sTAGLIST                              in varchar2,                             

	sDIRECTORINFO                          in varchar2,                            
	sSCREENWRITERINFO											in varchar2,                                       
	sVIDEOID                              in varchar2,                             
	sEXTENDFIELD1                          in varchar2,                            
	sEXTENDFIELD2													in varchar2,                                         
	sEXTENDFIELD3													in varchar2,                                         
	sEXTENDFIELD4													in varchar2,                                         
	sEXTENDFIELD5													in varchar2,                                         
	sPGMCATEGORYDTLID                     in varchar2,                             
	sAudioMsgType							in varchar2,                                               
  lstaffid                              in varchar2,                            
  iiscommit                             in number,                              
  result                                in out number,                          

  resultdesc                            in out varchar2                         
                                                                                
)                                                                               
is                                                                              
                                                                                
  lseriesid_temp number(9);                                                     
  lcounter number(9);                                                           
  dvalidthrough_temp date;                                                      
  dvaliduntil_temp date;                                                        
  sstatus_temp char(1) := '2';                                                  
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sglobalcodemapstatus char(1) := '0';                                          

  fprice_temp number(12,2) := 0;                                                
  llabeltype_temp number(4) := 0;                                               
  llabeltype_counter number(9);                                                 
  sseriestype_temp varchar2(160) := '0';                                        
  functionname varchar(40) := 'spseriesadd: ';                                  
  djoinrecycletime_temp date;                                                   
                                                                                
  str_list type_split := type_split();                                          
  l_row number(9);                                                              
  directory_counter number(9);                                                  
  parent_id number(9);                                                          
  directory_id_temp number(9);                                                  
  directory_last_id number(9);                                                  

                                                                                
  lcontentproviderid_temp number(9);                                            
  lcopyrighterid_temp number(9);                                                
                                                                                
begin                                                                           
  result := 0;                                                                  
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               
    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                

    if (lcounter <= 0) then                                                     
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('spid not exist in table vsp.');                     
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sname is null) then                                                       
    result := -176004;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('name is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    if (dvalidthrough is not null) then                                         
      select to_date(dvalidthrough,'yyyymmddhh24miss')                          
      into dvalidthrough_temp                                                   
      from dual;                                                                
    else                                                                        
      dvalidthrough_temp := null;                                               
    end if;                                                                     
  exception                                                                     

  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -176011;                                                          
    resultdesc := 'the format of validthrough is not correct.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of validthrough is not correct.');         
    return;                                                                     
  end;                                                                          
                                                                                
  begin                                                                         
    if (dvaliduntil is not null) then                                           

      select to_date(dvaliduntil,'yyyymmddhh24miss')                            
      into dvaliduntil_temp                                                     
      from dual;                                                                
    else                                                                        
      dvaliduntil_temp := null;                                                 
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -176011;                                                          

    resultdesc := 'the format of validuntil is not correct.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of validuntil is not correct.');           
    return;                                                                     
  end;                                                                          
                                                                                
  if (dvaliduntil_temp is not null and                                          
      dvalidthrough_temp is not null and                                        
      dvaliduntil_temp <= dvalidthrough_temp) then                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -176012;                                                          

    resultdesc := 'validuntil must later than validthrough.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('validuntil must later than validthrough.');           
    return;                                                                     
  end if;                                                                       
                                                                                
  if (fprice is not null) then                                                  
    fprice_temp := fprice;                                                      
  end if;                                                                       
                                                                                
  if (sstatus is not null) then                                                 
    sstatus_temp := sstatus;                                                    
  end if;                                                                       

                                                                                
  if (sstatus_temp = '9') then                                                  
    sglobalcodemapstatus := '1';                                                
  end if;                                                                       
                                                                                
  if (djoinrecycletime is null) then                                            
      djoinrecycletime_temp :=null;                                             
    else                                                                        
      select to_date(djoinrecycletime,'yyyymmddhh24miss') into djoinrecycletime_
temp from dual;                                                                 
                                                                                
    end if;                                                                     
                                                                                

                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from staff                                                                    
  where staffid = lstaffid;                                                     
  if (lcounter <= 0) then                                                       
    result := -176016;                                                          
    resultdesc := 'staffid not exist in table staff.';                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('staffid not exist in table staff.');                  
    return;                                                                     
  end if;                                                                       
                                                                                

  if (llabeltype is not null) then                                              
    select count(1)                                                             
    into llabeltype_counter                                                     
    from labeltype                                                              
    where labeltype = llabeltype;                                               
    if (llabeltype_counter <= 0) then                                           
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170401;                                                        
      resultdesc := 'labeltype not exist in table labeltype.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('labeltype not exist in table labeltype.');          

      return;                                                                   
    end if;                                                                     
    llabeltype_temp := llabeltype;                                              
  end if;                                                                       
                                                                                
  if (sseriestype is not null) then                                             
    sseriestype_temp := sseriestype;                                            
  end if;                                                                       
                                                                                
  begin                                                                         
    if (lseriesid is null) then                                                 
      spgetobjectid(ctmsconstant_def.objectid_seriesid,lseriesid_temp,result,res
ultdesc);                                                                       

                                                                                
      if (result != 0) then                                                     
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('get objectid failed.');                           
        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        return;                                                                 
      end if;                                                                   
    else                                                                        
      lseriesid_temp := lseriesid;                                              
    end if;                                                                     
                                                                                

    scode_temp := scode;                                                        
    if (scode is null) then                                                     
      spgetglobalcode(lvspid,ctmsconstant_def.globalcode_series,lseriesid_temp,s
code_temp,result);                                                              
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                

    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                
    if(scontentprovider is not null) then                                       
      select count(1)                                                           
      into lcounter                                                             
      from contentprovider                                                      
      where name = scontentprovider;                                            
      if(lcounter >= 1) then                                                    
         select contentproviderid                                               
         into lcontentproviderid_temp                                           
         from contentprovider                                                   

         where name = scontentprovider and rownum = 1;                          
      else                                                                      
        select contentproviderid.nextval into lcontentproviderid_temp from dual;
                                                                                
                                                                                
        insert into contentprovider(contentproviderid,vspid,name,createdate,last
updatetime)                                                                     
                                                                                
        values(lcontentproviderid_temp,lvspid,scontentprovider,sysdate,sysdate);
                                                                                
                                                                                
        end if;                                                                 
    end if;                                                                     

                                                                                
    if(scopyright is not null) then                                             
      select count(1)                                                           
      into lcounter                                                             
      from copyrighter                                                          
      where name = scopyright;                                                  
      if(lcounter >= 1) then                                                    
         select copyrighterid                                                   
         into lcopyrighterid_temp                                               
         from copyrighter                                                       
         where name = scopyright;                                               
      else                                                                      
        select copyrighterid.nextval into lcopyrighterid_temp from dual;        

        insert into copyrighter(copyrighterid,name,createdate,lastupdatetime)   
        values(lcopyrighterid_temp,scopyright,sysdate,sysdate);                 
        end if;                                                                 
    end if;                                                                     
                                                                                
                                                                                
    insert into series(seriesid,name,code,code2,status,vspid,alias,             
                       title_sort_name,title_search_name,orgairdate,validthrough
,validuntil,                                                                    
                                                                                
                       price,volumcount,description,memo,createstaffid,         
                       kpeople,director,scriptwriter,compere,guest,reporter,opin
charge,                                                                         

                                                                                
                       genre,releaseyear,labeltype,seriestype,copyright,contentp
rovider,                                                                        
                                                                                
                       columnpath,type1,lockflag,pgmcategory,pgmsndclass,origina
lcountry,                                                                       
                                                                                
                       contentproviderid,copyrighterid,editmode,labelids,autofla
g,Rating,                                                                       
                                                                                
                       NewPrice,tags,viewpoint,starlevel,awards,contractnum,inco
mplete,                                                                         
                                                                                

                       recycleflag,cptag,cpactivetime,operater,joinrecycletime,o
verdueTime,                                                                     
                                                                                
					   cpdescription,cpstatus,needReleaseFlag,newprice2,newprice3,pgmcategoryid
,pgmsndclassid,                                                                 
                                                                                
					   DefinitionFlag,Macrovision,Keywords,RMediaCode,cid,vid,KEYMAN,TAGLIST,DI
RECTORINFO,SCREENWRITERINFO,VIDEOID,EXTENDFIELD1,EXTENDFIELD2,EXTENDFIELD3,EXTEN
DFIELD4,EXTENDFIELD5,PGMCATEGORYDTLID,audioMsgType)                             
                                                                                
    values(lseriesid_temp,sname,scode_temp,scode2_temp,sstatus_temp,lvspid,salia
s,                                                                              
                                                                                

           stitle_sort_name,stitle_search_name,sorgairdate,dvalidthrough_temp,dv
aliduntil_temp,                                                                 
                                                                                
           fprice_temp,lvolumcount,sdescription,smemo,lstaffid,                 
           skpeople,sdirector,sscriptwriter,scompere,sguest,sreporter,sopincharg
e,                                                                              
                                                                                
           sgenre,sreleaseyear,llabeltype_temp,sseriestype_temp,scopyright,scont
entprovider,                                                                    
                                                                                
           scolumnpath,stype1,slockflag,spgmcategory,spgmsndclass,sOriginalCount
ry,                                                                             
                                                                                

           lcontentproviderid_temp,lcopyrighterid_temp,seditmode,slabelids,sauto
flag,sRating,                                                                   
                                                                                
           sNewPrice,stags,sviewpoint,sstarlevel,sawards,scontractnum,sIncomplet
e,                                                                              
                                                                                
           srecycleflag,scptag,scpactivetime,soperater,djoinrecycletime_temp,scp
overduetime,                                                                    
                                                                                
		   scpdescription,scpstatus,sneedReleaseFlag,snewprice2,snewprice3,spgmcategor
yid,spgmsndclassid,                                                             
                                                                                
		   sDefinitionFlag,sMacrovision,sKeywords,sRMediaCode,scid,svid,sKEYMAN,sTAGLI

ST,sDIRECTORINFO,sSCREENWRITERINFO,sVIDEOID,sEXTENDFIELD1,sEXTENDFIELD2,sEXTENDF
IELD3,sEXTENDFIELD4,sEXTENDFIELD5,sPGMCATEGORYDTLID,sAudioMsgType);             
                                                                                
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_series,lseriesid_temp,scode_temp
,scode2_temp,sglobalcodemapstatus,null,null,null,result);                       
                                                                                
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                

                                                                                
    if (scolumnpath is not null) then                                           
      str_list := split(scolumnpath, '@');                                      
      l_row := str_list.first;                                                  
      while (l_row is not null)                                                 
      loop                                                                      
        dbms_output.put_line(trim(str_list(l_row)));                            
        if (parent_id is null) then                                             
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid is null and vspid=lvspid;                         
                                                                                
          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        

            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),null,l_row-1,lvspid,sysdate
);                                                                              
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid is null and vspid=lvspid;                    
                                                                                
          end if;                                                               
        else                                                                    
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid=parent_id and vspid=lvspid;                       
                                                                                

          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),parent_id,l_row-1,lvspid,sy
sdate);                                                                         
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid=parent_id and vspid=lvspid;                  
                                                                                
          end if;                                                               
        end if;                                                                 
        parent_id := directory_id_temp;                                         

        l_row := str_list.next(l_row);                                          
      end loop;                                                                 
                                                                                
      l_row := str_list.last;                                                   
      if (l_row is not null) then                                               
        directory_last_id := directory_id_temp;                                 
        insert into directorydtl(directorydtlid,directoryid,objtype,objid,create
date) values(directorydtlid.nextval,directory_last_id,'2',lseriesid_temp,sysdate
);                                                                              
                                                                                
      end if;                                                                   
    end if;                                                                     
    if (result != 0) then                                                       

      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lseriesid_temp);                                        
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
procedure spscheduleremove                                                      
(                                                                               
  lscheduleid                           in number,                              
  ldomainid                             in number,                              
  lreclaimdomainids                     in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  lchannelid                            in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              

                                                                                
  lcounter number(9);                                                           
  schanneltype char(1);                                                         
  sobjecttype_temp char(1);                                                     
  lobjectid_temp number(9);                                                     
  channeldomainidstr varchar2(2000);                                            
  functionname varchar(40) := 'spscheduleremove: ';                             
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from schedule where scheduleid = lscheduleid;   
  if (lcounter != 1) then                                                       
    result := 0;                                                                

    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  select NVL2(max(a.key), max(a.key)||',', '0') str  into channeldomainidstr fro
m (select wmsys.wm_concat(domainid) over (ORDER BY domainid) key from DOMAINOBJE
CTS where objtype='12' and objid=lchannelid) a;                                 
                                                                                
  update schedule set reclaimdomainids=lreclaimdomainids where  scheduleid = lsc
heduleid;                                                                       
                                                                                

  begin                                                                         
    if(ldomainid is null or (lreclaimdomainids is not null and channeldomainidst
r=lreclaimdomainids)) then                                                      
                                                                                
    delete from assetidmap where assettype = 'C' and mamid=lscheduleid;         
                                                                                
    delete from schedule where scheduleid = lscheduleid;                        
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     

    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       

  result := 0;                                                                  
  resultdesc := 'successful! ldomainid='||ldomainid||',lscheduleid='||lschedulei
d||',lchannelid='||lchannelid||',channeldomainidstr='||channeldomainidstr||',rec
laimdomainids='||lreclaimdomainids;                                             
                                                                                
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spschedulequery                                                       
(                                                                               
  lscheduleid                           in out number,                          
  lchannelid                            in out number,                          
  lvspid                                in out number,                          
  sairdate                              in out varchar2,                        

  sairtime                              in out varchar2,                        
  sduration                             in out varchar2,                        
  scode                                 in out varchar2,                        
  scode2                                in out varchar2,                        
  sobjecttype                           in out varchar2,                        
  lobjectid                             in out number,                          
  shotflag                              in out varchar2,                        
  sshowtimeflag                         in out varchar2,                        
  lstorageduration                      in out number,                          
  lplayoffset                           in out number,                          
  lplayduration                         in out number,                          
  sprogramname                          in out varchar2,                        
  ssearchname                           in out varchar2,                        

  smacrovision                          in out varchar2,                        
  sdescription                          in out varchar2,                        
  ssource                               in out varchar2,                        
  sviewpoint                            in out varchar2,                        
  sviewpointkey                         in out varchar2,                        
  stvodstartdate                        in out varchar2,                        
  stvodstarttime                        in out varchar2,                        
  sgenre                                in out varchar2,                        
  slabelids                             in out varchar2,                        
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              

                                                                                
  functionname varchar(40) := 'spschedulequery: ';                              
begin                                                                           
  result := 0;                                                                  
                                                                                
  begin                                                                         
    select channelid,vspid,objecttype,objectid,                                 
           code,code2,airdate,airtime,duration,                                 
           hotflag,showtimeflag,storageduration,playoffset,playduration,        
           to_char(tvodstarttime,'yyyymmdd'),to_char(tvodstarttime,'hh24miss'), 
           name,macrovision,title_search_name,source,description,viewpoint,genre
,labelids,viewpointkey                                                          
                                                                                

    into lchannelid,lvspid,sobjecttype,lobjectid,                               
         scode,scode2,sairdate,sairtime,sduration,                              
         shotflag,sshowtimeflag,lstorageduration,lplayoffset,lplayduration,     
         stvodstartdate,stvodstarttime,                                         
         sprogramname,smacrovision,ssearchname,ssource,sdescription,sviewpoint,s
genre,slabelids,sviewpointkey                                                   
                                                                                
    from schedule                                                               
    where scheduleid = lscheduleid;                                             
                                                                                
  exception                                                                     
  when others then                                                              
    result := -170001;                                                          

    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := to_char(lscheduleid);                                           
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
procedure spschedulemodify                                                      
(                                                                               
  lscheduleid                           in number,                              
  lchannelid                            in number,                              
  lvspid                                in number,                              
  sairdate                              in varchar2,                            
  sairtime                              in varchar2,                            
  sduration                             in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sobjecttype                           in varchar2,                            
  lobjectid                             in number,                              

  shotflag                              in varchar2,                            
  sshowtimeflag                         in varchar2,                            
  lstorageduration                      in number,                              
  lplayoffset                           in number,                              
  lplayduration                         in number,                              
  sprogramname                          in varchar2,                            
  ssearchname                           in varchar2,                            
  smacrovision                          in varchar2,                            
  sdescription                          in varchar2,                            
  ssource                               in varchar2,                            
  sviewpoint                            in varchar2,                            
  sviewpointkey                         in varchar2,                            
  soverwriteflag                        in varchar2,                            

  stvodstartdate                        in varchar2,                            
  stvodstarttime                        in varchar2,                            
  sgenre                                in varchar2,                            
  slabelids                             in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lobjectid_temp number(9);                                                     
  loldobjectid number(9);                                                       

  lchannelid_temp number(9);                                                    
  lcounter number(9);                   --counter                               
  schanneltype char(1);                 --type of the channel                   
  schannelsubtype char(1);              --subtype of the channel                
                                                                                
  lsetduration number(9);               --the duration you will set, unit:second
                                                                                
                                                                                
                                                                                
  v_dsetstarttime date;                  --start time of the schedule you set, f
ormat:date                                                                      
                                                                                
  v_dsetendtime date;                    --end time of the schedule you set, for

mat:date                                                                        
                                                                                
  v_dschedulestarttime date;             --start time of the schedule fetch from
 db for compare, format:date                                                    
                                                                                
  v_dscheduleendtime date;               --end time of the schedule fetch from d
b for compare, format:date                                                      
                                                                                
  v_lscheduleid number(9);               --scheduleid fetch from db for compare 
  v_sobjecttype char(1);                 --objecttype of the schedule fetch from
 db for compare                                                                 
                                                                                
  v_lobjectid number(9);                 --objectid of the schedule fetch from d

b for compare                                                                   
                                                                                
  v_soverlapflag char(1);                --overlap flag, temporary variable     
  v_lstorageduration number(9);          --storageduration fetch from db for com
pare                                                                            
                                                                                
                                                                                
  lplayoffset_temp number(9) := 0;                                              
  lplayduration_temp number(9) := 0;                                            
                                                                                
  shotflag_temp char(1) := '0';                                                 
  sshowtimeflag_temp char(1) := '1';                                            
  lstorageduration_temp number(9) := 0;                                         

  lrealstorageduration number(9) := 0;                                          
  lchannelstorageduration number(9);                                            
  sobjecttype_temp varchar2(2);                                                 
                                                                                
  lsourcechannelid number(9);                                                   
  dvodstarttime_temp date;                                                      
  lsourceoffsettime number(9);                                                  
                                                                                
  sname_temp varchar2(256);                                                     
  ssearchname_temp varchar2(256);                                               
  sdescription_temp varchar2(1024);                                             
  sschedulecheckflag number(9);                                                 
  --cursor for finding the schedule                                             

  cursor c_get_schedule is                                                      
  select scheduleid,airstarttime,airendtime,objecttype,objectid,nvl(storagedurat
ion,0)                                                                          
                                                                                
  from schedule                                                                 
  where channelid = lchannelid                                                  
  and airstarttime < v_dsetendtime                                              
  and airendtime > v_dsetstarttime                                              
  and scheduleid != lscheduleid                                                 
  order by airdate,airtime asc;                                                 
  -- cursor for finding the sensitivewords                                      
  cursor sensitiveword is select word from sensitivewords;                      
  ele sensitiveword%rowtype;                                                    

  functionname varchar(40) := 'spschedulemodify: ';                             
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from schedule where scheduleid = lscheduleid;   
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
  select schedulecheckflag into sschedulecheckflag from channel where channelid=

lchannelid;                                                                     
                                                                                
  if sschedulecheckflag=1 then                                                  
  for ele in sensitiveword loop                                                 
    if instr(sprogramname,ele.word) >0 then                                     
    result := -172411;                                                          
    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     
    if instr(sdescription,ele.word) >0 then                                     
     result := -172411;                                                         

    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     
    if instr(ssearchname,ele.word) >0 then                                      
     result := -172411;                                                         
    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     
    end loop;                                                                   

    end if;                                                                     
                                                                                
  --------------------------------------                                        
  --rule 1: channelid judgement                                                 
  --------------------------------------                                        
  select channelid,objectid                                                     
  into lchannelid_temp,loldobjectid                                             
  from schedule                                                                 
  where scheduleid = lscheduleid;                                               
  if (lchannelid != lchannelid_temp) then                                       
    result := -172423;                                                          
    resultdesc := 'can not modify the channelid of the schedule.';              
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('can not modify the channelid of the schedule.');      
    return;                                                                     
  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --check the input value                                                       
  --------------------------------------                                        
  -- now only live/virtual/importing/delay/monitor channel can add schedule     
  select count(1) into lcounter                                                 
  from channel                                                                  
  where channelid = lchannelid                                                  
  and type in ('1','2','8','A','0','B');                                        
  if (lcounter <= 0) then                                                       

    result := -172401;                                                          
    resultdesc := 'channelid not exists in table channel(tv/virtual/importing/de
lay/monitor).';                                                                 
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('channelid not exists in table channel(tv/virtual/impor
ting/delay/monitor).');                                                         
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  -- get the old values of channel                                              
  select type,nvl(storageduration,0),                                           

         nvl(subtype,'1'), nvl(offsettime,0), sourcechannelid                   
  into schanneltype,lchannelstorageduration,                                    
       schannelsubtype, lsourceoffsettime, lsourcechannelid                     
  from channel                                                                  
  where channelid = lchannelid;                                                 
                                                                                
  -- when objecttype is null, set the default value.                            
  sobjecttype_temp := sobjecttype;                                              
  if (sobjecttype is null) then                                                 
    if ((schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schan
neltype = 'B') and schannelsubtype != '2') then                                 
                                                                                
      sobjecttype_temp := '1';                                                  

    else                                                                        
      sobjecttype_temp := '2';                                                  
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schannel
type = 'B') then        --tv channel/importing channel/monitor channel          
                                                                                
    if (schannelsubtype = '2') then                                             
      if (sobjecttype_temp not in ('2','3','4')) then                           
        result := -172426;                                                      
        resultdesc := 'when the channel is virtual/vcss channel, objecttype must
 in (''2'',''3'',''4'').';                                                      

                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('when the channel is virtual/vcss channel, objectty
pe must in (''2'',''3'',''4'').');                                              
                                                                                
        return;                                                                 
      end if;                                                                   
    else                                                                        
      if (sobjecttype_temp not in ('1','4')) then                               
        result := -172426;                                                      
        resultdesc := 'when the channel is tv channel/importing channel, objectt
ype must in (''1'',''4'').';                                                    
                                                                                

        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('when the channel is tv channel/importing channel, 
objecttype must in (''1'',''4'').');                                            
                                                                                
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
  elsif (schanneltype = '2') then                                               
    if (sobjecttype_temp not in ('2','3','4')) then                             
      result := -172426;                                                        
      resultdesc := 'when the channel is virtual/vcss channel, objecttype must i
n (''2'',''3'',''4'').';                                                        
                                                                                

      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtual/vcss channel, objecttype
 must in (''2'',''3'',''4'').');                                                
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    lobjectid_temp := lobjectid;                                                
  end if;                                                                       
                                                                                
  -- object is valid? and set name/search name/description                      
  sname_temp := sprogramname;                                                   
  ssearchname_temp := ssearchname;                                              

  sdescription_temp := sdescription;                                            
  if (sobjecttype_temp = '1') then   --if tv program                            
    if (sprogramname is null) then                                              
      result := -172417;                                                        
      resultdesc := 'when the channel is tv channel/importing channel, programna
me is not allow empty.';                                                        
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is tv channel/importing channel, pr
ogramname is not allow empty.');                                                
                                                                                
      return;                                                                   
    end if;                                                                     

  elsif (sobjecttype_temp = '2') then   --if vod                                
    select count(1) into lcounter                                               
    from program                                                                
    where programid = lobjectid;                                                
    if (lcounter <= 0) then                                                     
      result := -172402;                                                        
      resultdesc := 'when the channel is virtual/vcss channel and objecttype is 
''2'', objectid must exists in table program.';                                 
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtual/vcss channel and objectt
ype is ''2'', objectid must exists in table program.');                         
                                                                                

      return;                                                                   
    end if;                                                                     
                                                                                
    select name,title_search_name,description                                   
    into sname_temp,ssearchname_temp,sdescription_temp                          
    from program where programid = lobjectid;                                   
  elsif (sobjecttype_temp = '3') then   --if channel                            
    select count(1) into lcounter                                               
    from channel                                                                
    where type in ('1','8','B')                                                 
    and channelid = lobjectid;                                                  
    if (lcounter <= 0) then                                                     
      result := -172402;                                                        

      resultdesc := 'when the channel is virtual/vcss channel and objecttype is 
''3'', objectid must be tv channel/importing channel id.';                      
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtual/vcss channel and objectt
ype is ''3'', objectid must be tv channel/importing channel id.');              
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    select name,'',description                                                  
    into sname_temp,ssearchname_temp,sdescription_temp                          
    from channel where channelid = lobjectid;                                   

  elsif (sobjecttype_temp = '5') then   --if tvod                               
    select count(1) into lcounter                                               
    from channel                                                                
    where channelid = lobjectid;                                                
    if (lcounter != 1) then                                                     
      result := -172429;                                                        
      resultdesc := 'objectid not exists in the table channel.';                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objectid not exists in the table channel.');        
      return;                                                                   
    end if;                                                                     
                                                                                
    select name,'',''                                                           

    into sname_temp,ssearchname_temp,sdescription_temp                          
    from channel where channelid = lobjectid;                                   
  end if;                                                                       
                                                                                
  --translate startime and endtime for char to date.                            
  spconvertdurationtodate(sairdate,sairtime,sduration,'0,',v_dsetstarttime,v_dse
tendtime,result,resultdesc);                                                    
                                                                                
  if (result != 0) then                                                         
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    return;                                                                     

  end if;                                                                       
                                                                                
  --set default values                                                          
  if (shotflag is not null) then                                                
    shotflag_temp := shotflag;                                                  
  end if;                                                                       
                                                                                
  if (sshowtimeflag is not null) then                                           
    sshowtimeflag_temp := sshowtimeflag;                                        
  end if;                                                                       
                                                                                
  if (lstorageduration is not null) then                                        
    lstorageduration_temp := lstorageduration;                                  

    lrealstorageduration := lstorageduration;                                   
  end if;                                                                       
                                                                                
  if (lplayoffset is not null) then                                             
    lplayoffset_temp := lplayoffset;                                            
  end if;                                                                       
                                                                                
  if (lplayduration is not null) then                                           
    lplayduration_temp := lplayduration;                                        
  end if;                                                                       
                                                                                
  if (lstorageduration_temp < lchannelstorageduration) then                     
    lstorageduration_temp := 0;                                                 

    lrealstorageduration := lchannelstorageduration;                            
  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --rule 2: duration judgement                                                  
  --------------------------------------                                        
  --judge the duration                                                          
  lsetduration := (v_dsetendtime-v_dsetstarttime)*24*60*60;                     
  if (lsetduration < ctmsconstant_def.scheduleminduration or                    
      (sobjecttype_temp != '4' and schanneltype != 'A' and                      
       lsetduration > ctmsconstant_def.schedulemaxduration)) then               
    result := -172416;                                                          
    resultdesc := 'duration over range.';                                       

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('duration over range.');                               
    return;                                                                     
  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --rule 4: overlap judgement                                                   
  --------------------------------------                                        
  --check overlap                                                               
  v_soverlapflag := '0';                                                        
  open c_get_schedule;                                                          
  loop                                                                          
    begin                                                                       

      fetch c_get_schedule into v_lscheduleid,v_dschedulestarttime,v_dscheduleen
dtime,v_sobjecttype,v_lobjectid,v_lstorageduration;                             
                                                                                
      exit when c_get_schedule%notfound;                                        
                                                                                
        if (v_lscheduleid != lscheduleid) then                                  
          if (soverwriteflag is null or soverwriteflag != '1') then             
            v_soverlapflag := '1';                                              
            exit;                                                               
          end if;                                                               
                                                                                
          delete from schedule where scheduleid = v_lscheduleid;                
        end if;                                                                 

    exception                                                                   
    when others then                                                            
      close c_get_schedule;                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170001;                                                        
      resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sql
errm,1,100);                                                                    
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||subs
tr( sqlerrm,1,100));                                                            

                                                                                
      return;                                                                   
    end;                                                                        
  end loop;                                                                     
  close c_get_schedule;                                                         
                                                                                
  if (v_soverlapflag = '1') then                                                
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -172410;                                                          
    resultdesc := 'period overlaped.';                                          
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('period overlaped.');                                  
    return;                                                                     
  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --delay channel judgement begin                                               
  --------------------------------------                                        
  begin                                                                         
    if (schanneltype = 'A') then                                                
      sobjecttype_temp := '5';                                                  
                                                                                
      select (v_dsetstarttime-(lsourceoffsettime/86400)) into dvodstarttime_temp
 from dual;                                                                     

                                                                                
    else                                                                        
      select to_date(stvodstartdate||stvodstarttime,'yyyymmddhh24miss') into dvo
dstarttime_temp from dual;                                                      
                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    dvodstarttime_temp := null;                                                 
  end;                                                                          
                                                                                
  lobjectid_temp := lobjectid;                                                  
  begin                                                                         

    if ((schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schan
neltype = 'B') and schannelsubtype != '2') then        --tv channel/importing ch
annel                                                                           
                                                                                
      if (lobjectid_temp is null) then                                          
        lobjectid_temp := loldobjectid;                                         
      end if;                                                                   
    elsif (schannelsubtype = 'A') then                                          
      lobjectid_temp := lsourcechannelid;                                       
    end if;                                                                     
                                                                                
                                                                                
    update schedule                                                             

    set channelid = lchannelid,                                                 
        vspid = lvspid,                                                         
        code2 = scode2,                                                         
        objecttype = sobjecttype_temp,                                          
        objectid = lobjectid_temp,                                              
        airdate = sairdate,                                                     
        airtime = sairtime,                                                     
        duration = sduration,                                                   
        airstarttime = v_dsetstarttime,                                         
        airendtime = v_dsetendtime,                                             
        hotflag = shotflag_temp,                                                
        showtimeflag = sshowtimeflag_temp,                                      
        storageduration = lstorageduration_temp,                                

        realstorageduration = lrealstorageduration,                             
        overduedate = v_dsetendtime+lrealstorageduration/24,                    
        playoffset = lplayoffset_temp,                                          
        playduration = lplayduration_temp,                                      
        deleteflag = null,                                                      
        tvodstarttime = dvodstarttime_temp,                                     
        name = sname_temp,                                                      
        title_search_name = ssearchname_temp,                                   
        macrovision = smacrovision,                                             
        source = ssource,                                                       
        viewpoint = sviewpoint,                                                 
        viewpointkey = sviewpointkey,                                           
        genre=sgenre,                                                           

        labelids=slabelids,                                                     
        description = sdescription,                                             
        lastupdatetime=sysdate                                                  
                                                                                
    where scheduleid = lscheduleid;                                             
  exception                                                                     
  when others then                                                              
      rollback work;                                                            
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spscheduleadd                                                         

(                                                                               
  lscheduleid                           in number,                              
  lchannelid                            in number,                              
  lvspid                                in number,                              
  sairdate                              in varchar2,                            
  sairtime                              in varchar2,                            
  sduration                             in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sobjecttype                           in varchar2,                            
  lobjectid                             in number,                              
  shotflag                              in varchar2,                            
  sshowtimeflag                         in varchar2,                            

  lstorageduration                      in number,                              
  lplayoffset                           in number,                              
  lplayduration                         in number,                              
  sprogramname                          in varchar2,                            
  ssearchname                           in varchar2,                            
  smacrovision                          in varchar2,                            
  sdescription                          in varchar2,                            
  ssource                               in varchar2,                            
  sviewpoint                            in varchar2,                            
  sviewpointkey                         in varchar2,                            
  soverwriteflag                        in varchar2,                            
  stvodstartdate                        in varchar2,                            
  stvodstarttime                        in varchar2,                            

  sgenre                                in varchar2,                            
  slabelids                             in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lscheduleid_temp number(9);                                                   
  lobjectid_temp number(9);                                                     
  lcounter number(9);                   --counter                               
  schanneltype char(1);                 --type of the channel                   

  schannelsubtype char(1);              --subtype of the channel                
                                                                                
  lsetduration number(9);               --the duration you will set, unit:second
                                                                                
                                                                                
  lplayoffset_temp number(9) := 0;      --the play off you will set, unit:second
                                                                                
                                                                                
  lplayduration_temp number(9) := 0;    --the play duration you will set, unit:s
econd                                                                           
                                                                                
                                                                                
  v_dsetstarttime date;                 --start time of the schedule you set, fo

rmat:date                                                                       
                                                                                
  v_dsetendtime date;                   --end time of the schedule you set, form
at:date                                                                         
                                                                                
  v_dschedulestarttime date;            --start time of the schedule fetch from 
db for compare, format:date                                                     
                                                                                
  v_dscheduleendtime date;              --end time of the schedule fetch from db
 for compare, format:date                                                       
                                                                                
  v_lscheduleid number(9);              --scheduleid fetch from db for compare  
                                                                                

  v_sobjecttype char(1);                --objecttype of the schedule fetch from 
db for compare                                                                  
                                                                                
  v_lobjectid number(9);                --objectid of the schedule fetch from db
 for compare                                                                    
                                                                                
  v_soverlapflag char(1);               --overlap flag, temporary variable      
  v_lstorageduration number(9);         --storageduration fetch from db for comp
are                                                                             
                                                                                
                                                                                
  shotflag_temp char(1) := '0';                                                 
  sshowtimeflag_temp char(1) := '1';                                            

  lstorageduration_temp number(9) := 0;                                         
  lrealstorageduration number(9) := 0;                                          
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  lchannelstorageduration number(9);                                            
  sobjecttype_temp varchar2(2);                                                 
                                                                                
  lsourcechannelid number(9);                                                   
  dvodstarttime_temp date;                                                      
  lsourceoffsettime number(9);                                                  
                                                                                
  sname_temp varchar2(256);                                                     
  ssearchname_temp varchar2(256);                                               

  sdescription_temp varchar2(1024);                                             
  ssource_temp varchar2(256);                                                   
                                                                                
  functionname varchar(40) := 'spscheduleadd: ';                                
  sschedulecheckflag number(9);                                                 
  --cursor for finding the schedule                                             
  cursor c_get_schedule is                                                      
  select scheduleid,airstarttime,airendtime,objecttype,objectid,nvl(storagedurat
ion,0)                                                                          
                                                                                
  from schedule                                                                 
  where channelid = lchannelid                                                  
  and airstarttime < v_dsetendtime                                              

  and airendtime > v_dsetstarttime                                              
  order by airdate,airtime asc;                                                 
  -- cursor for finding the sensitivewords                                      
  cursor sensitiveword is select word from sensitivewords;                      
  ele sensitiveword%rowtype;                                                    
begin                                                                           
  result := 0;                                                                  
                                                                                
  --------------------------------------                                        
  --check the input value                                                       
  --------------------------------------                                        
  select count(1) into lcounter                                                 
  from schedule                                                                 

  where scheduleid = lscheduleid;                                               
  if (lcounter > 0) then                                                        
    result := -172422;                                                          
    resultdesc := 'scheduleid is already exists in the table schedule.';        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('scheduleid is already exists in the table schedule.');
                                                                                
                                                                                
    return;                                                                     
  end if;                                                                       
  if sschedulecheckflag=1 then                                                  
  for ele in sensitiveword loop                                                 
    if instr(sprogramname,ele.word) >0 then                                     

    result := -172411;                                                          
    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     
    if instr(sdescription,ele.word) >0 then                                     
     result := -172411;                                                         
    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     

    if instr(ssearchname,ele.word) >0 then                                      
     result := -172411;                                                         
    resultdesc := 'There is an sensitiveword in the Schedule.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('There is an sensitiveword in the Schedule.');         
    return;                                                                     
    end if;                                                                     
    end loop;                                                                   
    end if;                                                                     
  -- now only liveirtual/importing/delay/monitor channel can add schedule       
  select count(1) into lcounter                                                 
  from channel                                                                  
  where channelid = lchannelid                                                  

  and type in ('1','2','8','A','0','B');                                        
  if (lcounter <= 0) then                                                       
    result := -172401;                                                          
    resultdesc := 'channelid not exists in table channel(tvirtual/importing/dela
y/monitor).';                                                                   
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('channelid not exists in table channel(tvirtual/importi
ng/delay/monitor).');                                                           
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                

  -- get the old values of channel                                              
  select type, nvl(storageduration,0),                                          
         nvl(subtype,'1'), nvl(offsettime,0), sourcechannelid,name              
  into schanneltype, lchannelstorageduration,                                   
       schannelsubtype, lsourceoffsettime, lsourcechannelid,ssource_temp        
  from channel                                                                  
  where channelid = lchannelid;                                                 
                                                                                
  if (ssource is not null) then                                                 
    ssource_temp := ssource;                                                    
  end if;                                                                       
                                                                                
  -- when objecttype is null, set the default value.                            

  sobjecttype_temp := sobjecttype;                                              
  if (sobjecttype is null) then                                                 
    if ((schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schan
neltype = 'B') and schannelsubtype != '2') then                                 
                                                                                
      sobjecttype_temp := '1';                                                  
    else                                                                        
      sobjecttype_temp := '2';                                                  
    end if;                                                                     
  end if;                                                                       
                                                                                
  -- whether type and objecttype is match.                                      
  if (schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schannel

type = 'B') then      --tv channel/importing channel/monitor channel            
                                                                                
    if (schannelsubtype = '2') then                                             
      if (sobjecttype_temp not in ('2','3','4')) then                           
        result := -172426;                                                      
        resultdesc := 'when the channel is virtualcss channel, objecttype must i
n (''2'',''3'',''4'').';                                                        
                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('when the channel is virtualcss channel, objecttype
 must in (''2'',''3'',''4'').');                                                
                                                                                
        return;                                                                 

      end if;                                                                   
    else                                                                        
      if (sobjecttype_temp not in ('1','4')) then                               
        result := -172426;                                                      
        resultdesc := 'when the channel is tv channel/importing channel, objectt
ype must in (''1'',''4'').';                                                    
                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('when the channel is tv channel/importing channel, 
objecttype must in (''1'',''4'').');                                            
                                                                                
        return;                                                                 
      end if;                                                                   

    end if;                                                                     
  elsif (schanneltype = '2') then                                               
    if (sobjecttype_temp not in ('2','3','4')) then                             
      result := -172426;                                                        
      resultdesc := 'when the channel is virtualcss channel, objecttype must in 
(''2'',''3'',''4'').';                                                          
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtualcss channel, objecttype m
ust in (''2'',''3'',''4'').');                                                  
                                                                                
      return;                                                                   
    end if;                                                                     

                                                                                
    lobjectid_temp := lobjectid;                                                
  end if;                                                                       
                                                                                
  -- object is valid? and set namearch name/description                         
  sname_temp := sprogramname;                                                   
  ssearchname_temp := ssearchname;                                              
  sdescription_temp := sdescription;                                            
  if (sobjecttype_temp = '1') then   --if tv program                            
    if (sprogramname is null) then                                              
      result := -172417;                                                        
      resultdesc := 'when the channel is tv channel/importing channel, programna
me is not allow empty.';                                                        

                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is tv channel/importing channel, pr
ogramname is not allow empty.');                                                
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
  elsif (sobjecttype_temp = '2') then   --if vod                                
    select count(1) into lcounter                                               
    from program                                                                
    where programid = lobjectid;                                                
    if (lcounter <= 0) then                                                     

      result := -172402;                                                        
      resultdesc := 'when the channel is virtualcss channel and objecttype is ''
2'', objectid must exists in table program.';                                   
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtualcss channel and objecttyp
e is ''2'', objectid must exists in table program.');                           
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    select name,title_search_name,description                                   
    into sname_temp,ssearchname_temp,sdescription_temp                          

    from program where programid = lobjectid;                                   
  elsif (sobjecttype_temp = '3') then   --if channel                            
    select count(1) into lcounter                                               
    from channel                                                                
    where type in ('1','8','B')                                                 
    and channelid = lobjectid;                                                  
    if (lcounter <= 0) then                                                     
      result := -172402;                                                        
      resultdesc := 'when the channel is virtualcss channel and objecttype is ''
3'', objectid must be tv channel/importing channel id.';                        
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when the channel is virtualcss channel and objecttyp

e is ''3'', objectid must be tv channel/importing channel id.');                
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    select name,'',description                                                  
    into sname_temp,ssearchname_temp,sdescription_temp                          
    from channel where channelid = lobjectid;                                   
  elsif (sobjecttype_temp = '5') then   --if tvod                               
    select count(1) into lcounter                                               
    from channel                                                                
    where channelid = lobjectid;                                                
    if (lcounter != 1) then                                                     

      result := -172429;                                                        
      resultdesc := 'objectid not exists in the table channel.';                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objectid not exists in the table channel.');        
      return;                                                                   
    end if;                                                                     
                                                                                
    select name,'',''                                                           
    into sname_temp,ssearchname_temp,sdescription_temp                          
    from channel where channelid = lobjectid;                                   
  end if;                                                                       
                                                                                
  --------------------------------------                                        

  --set default values                                                          
  --------------------------------------                                        
  if (shotflag is not null) then                                                
    shotflag_temp := shotflag;                                                  
  end if;                                                                       
                                                                                
  if (sshowtimeflag is not null) then                                           
    sshowtimeflag_temp := sshowtimeflag;                                        
  end if;                                                                       
                                                                                
  if (lstorageduration is not null) then                                        
    lstorageduration_temp := lstorageduration;                                  
    lrealstorageduration := lstorageduration;                                   

  end if;                                                                       
                                                                                
  if (lplayoffset is not null) then                                             
    lplayoffset_temp := lplayoffset;                                            
  end if;                                                                       
                                                                                
  if (lplayduration is not null) then                                           
    lplayduration_temp := lplayduration;                                        
  end if;                                                                       
                                                                                
  if (lstorageduration_temp < lchannelstorageduration) then                     
    lstorageduration_temp := 0;                                                 
    lrealstorageduration := lchannelstorageduration;                            

  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --convert values                                                              
  --------------------------------------                                        
  spconvertdurationtodate(sairdate,sairtime,sduration,'0',v_dsetstarttime,v_dset
endtime,result,resultdesc);                                                     
                                                                                
  if (result != 0) then                                                         
    return;                                                                     
  end if;                                                                       
                                                                                
  --------------------------------------                                        

  --rule 2 : duration judgement.                                                
  --------------------------------------                                        
  --judge the duration, if the schedule type is playlist, the max duration is in
valid.                                                                          
                                                                                
  lsetduration := (v_dsetendtime-v_dsetstarttime)*24*60*60;                     
  if (lsetduration < ctmsconstant_def.scheduleminduration or                    
      (sobjecttype_temp != '4' and schanneltype != 'A' and                      
       lsetduration > ctmsconstant_def.schedulemaxduration)) then               
    result := -172416;                                                          
    resultdesc := 'duration over range.';                                       
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('duration over range.');                               

    return;                                                                     
  end if;                                                                       
                                                                                
  --------------------------------------                                        
  --rule 3 : overlap judgement.                                                 
  --------------------------------------                                        
  --is the schedule overlap.                                                    
  v_soverlapflag := '0';                                                        
  open c_get_schedule;                                                          
  loop                                                                          
    begin                                                                       
      fetch c_get_schedule into v_lscheduleid,v_dschedulestarttime,v_dscheduleen
dtime,v_sobjecttype,v_lobjectid,v_lstorageduration;                             

                                                                                
      exit when c_get_schedule%notfound;                                        
                                                                                
        if (soverwriteflag is null or soverwriteflag != '1') then               
          v_soverlapflag := '1';                                                
          exit;                                                                 
        end if;                                                                 
                                                                                
        delete from schedule where scheduleid = v_lscheduleid;                  
    exception                                                                   
    when others then                                                            
      close c_get_schedule;                                                     
      if (iiscommit = 1) then                                                   

        rollback work;                                                          
      end if;                                                                   
      result := -170001;                                                        
      resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sql
errm,1,100);                                                                    
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||subs
tr( sqlerrm,1,100));                                                            
                                                                                
      return;                                                                   
    end;                                                                        
  end loop;                                                                     

  close c_get_schedule;                                                         
                                                                                
  if (v_soverlapflag = '1') then                                                
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -172410;                                                          
    resultdesc := 'period overlaped.';                                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('period overlaped.');                                  
    return;                                                                     
  end if;                                                                       
                                                                                

  --------------------------------------                                        
  --delay channel judgement begin                                               
  --------------------------------------                                        
  begin                                                                         
    if (schanneltype = 'A') then                                                
      sobjecttype_temp := '5';                                                  
                                                                                
      select (v_dsetstarttime-(lsourceoffsettime/86400)) into dvodstarttime_temp
 from dual;                                                                     
                                                                                
    else                                                                        
      select to_date(stvodstartdate||stvodstarttime,'yyyymmddhh24miss') into dvo
dstarttime_temp from dual;                                                      

                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    dvodstarttime_temp := null;                                                 
  end;                                                                          
                                                                                
  lobjectid_temp := lobjectid;                                                  
  begin                                                                         
    if ((schanneltype = '1' or schanneltype = '8' or schanneltype = '0' or schan
neltype = 'B') and schannelsubtype != '2') then        --tv channel/importing ch
annel                                                                           
                                                                                

      if (sobjecttype_temp = '1') then                                          
        if (lobjectid is null) then                                             
          --select programid.nextval into lobjectid_temp from dual;             
          spgetobjectid(ctmsconstant_def.objectid_programid,lobjectid_temp,resul
t,resultdesc);                                                                  
                                                                                
          if (result != 0) then                                                 
            dbms_output.put_line('spgetobjectid failed');                       
            if (iiscommit = 1) then                                             
              rollback work;                                                    
            end if;                                                             
          end if;                                                               
        else                                                                    

          lobjectid_temp := lobjectid;                                          
        end if;                                                                 
      end if;                                                                   
    elsif (schannelsubtype = 'A') then                                          
      lobjectid_temp := lsourcechannelid;                                       
    end if;                                                                     
                                                                                
    if (lscheduleid is null) then                                               
      select scheduleid.nextval into lscheduleid_temp from dual;                
    else                                                                        
      lscheduleid_temp := lscheduleid;                                          
    end if;                                                                     
                                                                                

    scode_temp := scode;                                                        
    if (scode is null) then                                                     
      spgetglobalcode(null,ctmsconstant_def.globalcode_schedule,lscheduleid_temp
,scode_temp,result);                                                            
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                

    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                
    insert into schedule(scheduleid,vspid,channelid,objecttype,objectid,        
                         code,code2,airdate,airtime,duration,hotflag,           
                         showtimeflag,storageduration,playoffset,playduration,  
                         airstarttime,airendtime,tvodstarttime,name,title_search
_name,                                                                          
                                                                                
                         createstaffid,macrovision,description,overduedate,reals
torageduration,                                                                 
                                                                                

                         source,viewpoint,viewpointkey,genre,labelids)          
    values(lscheduleid_temp,lvspid,lchannelid,sobjecttype_temp,lobjectid_temp,  
           scode_temp,scode2_temp,sairdate,sairtime,sduration,shotflag_temp,    
           sshowtimeflag_temp,lstorageduration_temp,lplayoffset_temp,lplaydurati
on_temp,                                                                        
                                                                                
           v_dsetstarttime,v_dsetendtime,dvodstarttime_temp,sname_temp,ssearchna
me_temp,                                                                        
                                                                                
           lstaffid,smacrovision,sdescription,v_dsetendtime+lrealstorageduration
/24,lrealstorageduration,                                                       
                                                                                
           ssource_temp,sviewpoint,sviewpointkey,sgenre,slabelids);             

                                                                                
    /*spaddglobalcode(ctmsconstant_def.globaltype_schedule,lscheduleid_temp,scod
e_temp,scode2_temp,'0',null,null,null,result);                                  
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;*/                                                                   
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            

    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                

  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lscheduleid_temp);                                      
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spprogramremove                                                       
(                                                                               
  lprogramid                            in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               

is                                                                              
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spprogramremove: ';                              
                                                                                
begin                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lcounter from program where programid = lprogramid;      
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
  delete from assetidmap                                                        
  where assettype = '0'                                                         
  and mamid = lprogramid;                                                       
                                                                                
  update globalcodemap                                                          
  set status = '1'                                                              
  where objecttype=ctmsconstant_def.globaltype_program                          

  and objectid=lprogramid;                                                      
                                                                                
  update program                                                                
  set status = '9',lastupdatetime=sysdate                                       
  where programid = lprogramid;                                                 
                                                                                
  delete from seriesdtl where programid = lprogramid;                           
                                                                                
  delete from favoriteobjects                                                   
  where staffid=lstaffid and objid=lprogramid;                                  
                                                                                
  delete from directorydtl                                                      
  where objtype='1' and objid=lprogramid;                                       

                                                                                
 delete from categorydtl where objid=lprogramid and objtype='8'                 
   and categoryid in (select categoryid from category where domainid is null);  
                                                                                
  delete from bundledcontentdtl where objid=lprogramid and objtype='3'          
 and bundledcontentid in (select bundledcontentid from bundledcontent where doma
inid is null);                                                                  
                                                                                
                                                                                
  delete from programcasts where programid = lprogramid;                        
                                                                                
  exception                                                                     
  when others then                                                              

    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          

                                                                                
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result :=0;                                                                   
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
