sourcemedia,pgmcategory,                                                        
                                                                                
           pgmsndclass,contentprovider,reserve1,reserve2,reserve3,reserve4,reser
ve5,genre,releaseyear,sourcetype,linkurl,labeltype,type1,lockflag,originalcountr
y,editmode,programtype,labelids,autoflag,rating,newprice,tags,viewpoint,starleve
l,awards,contractnum,                                                           
                                                                                

           cptag,cpactivetime,overdueTime,recycleflag,operater,to_char(joinrecyc
letime,'yyyymmddhh24miss'),cpdescription,cpstatus,needReleaseFlag,programcode,ne
wprice2,newprice3,Tvcolumnid,pgmcategoryid,pgmsndclassid,definitionFlag,macrovis
ion,keywords,rmediacode,cid,vid,ProductionBase,Editor,Accesser,ColumnPhoneNo,Col
umnEmail,Producer,Produce,Month,VideoDataRate,TvCloumnName,Framerate,Stockoutfla
g,KEYMAN,TAGLIST,DIRECTORINFO,SCREENWRITERINFO,VIDEOID,EXTENDFIELD1,EXTENDFIELD2
,EXTENDFIELD3,EXTENDFIELD4,EXTENDFIELD5,PGMCATEGORYDTLID,audioMsgType           
                                                                                
    into   lvspid,sname,scode,scode2,stitle_sort_name,sseriesflag,              
           stitle_search_name,fprice,sstatus,sdescription,sdescription1,smemo,sa
lias,sepititle,slanguage,sorgairdate,                                           
                                                                                
           dlicensingwindowstart,dlicensingwindowend,                           

           lepisodeindex,lepisodenum,scaptionlanguage,scopyright,ssource,scolumn
name,                                                                           
                                                                                
