           sopincharge,sduration,scrbegin,srtime,sfcl,sparachannel,srecasttime1,
                                                                                
                                                                                
           srecastchannel1,srecasttime2,srecastchannel2,srecasttime3,srecastchan
nel3,ssourcemedia,spgmcategory,                                                 
                                                                                
           spgmsndclass,scontentprovider,sreserve1,sreserve2,sreserve3,sreserve4
,sreserve5,sgenre,sreleaseyear,ssourcetype,slinkurl,llabeltype,stype1,slockflag,
sOriginalCountry,seditmode,sprogramtype,slabelids,sautoflag,srating,snewprice,st

ags,sviewpoint,sstarlevel,sawards,scontractnum,                                 
                                                                                
           scptag,scpactivetime,scpoverduetime,srecycleflag,soperater,djoinrecyc
letime,scpdescription,scpstatus,sneedReleaseFlag,sprogramcode,snewprice2,snewpri
ce3,sTvcolumnid,spgmcategoryid,spgmsndclassid,sDefinitionFlag,sMacrovision,sKeyw
ords,sRMediaCode,scid,svid,sProductionBase,sEditor,sAccesser,sColumnPhoneNo,sCol
umnEmail,sProducer,sProduce,sMonth,sVideoDataRate,sTvCloumnName,sFramerate,sStoc
koutflag,sKEYMAN,sTAGLIST,sDIRECTORINFO,sSCREENWRITERINFO,sVIDEOID,sEXTENDFIELD1
,sEXTENDFIELD2,sEXTENDFIELD3,sEXTENDFIELD4,sEXTENDFIELD5,sPGMCATEGORYDTLID,sAudi
oMsgType                                                                        
                                                                                
    from program                                                                
    where programid = lprogramid;                                               

                                                                                
  exception                                                                     
  when others then                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          

                                                                                
  result := 0;                                                                  
  resultdesc := to_char(lprogramid);                                            
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
