  sEXTENDFIELD2                          in varchar2,                           
  sEXTENDFIELD3                          in varchar2,                           
  sEXTENDFIELD4                          in varchar2,                           
  sEXTENDFIELD5                          in varchar2,                           
	sPGMCATEGORYDTLID                     in VARCHAR2,                             
	sAudioMsgType							in varchar2,                                               
  sFramerate                            in number,                              
  sStockoutflag                         in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               

is                                                                              
                                                                                
  dlicensingwindowstart_temp date;                                              
  dlicensingwindowend_temp date;                                                
  sname_temp varchar2(400);                                                     
  fprice_temp number(12,2);                                                     
  sstatus_temp varchar2(2);                                                     
  program_status varchar2(2);                                                   
  lcounter number(9);                                                           
  llabeltype_temp number(4) := 0;                                               
  llabeltype_counter number(9);                                                 
  sseriesflag_temp char(1) := '0';                                              
  functionname varchar(40) := 'spprogrammodify: ';                              

  djoinrecycletime_temp date;                                                   
                                                                                
  str_list type_split := type_split();                                          
  l_row number(9);                                                              
  directory_counter number(9);                                                  
  parent_id number(9);                                                          
  directory_id_temp number(9);                                                  
  directory_last_id number(9);                                                  
  lcontentproviderid_temp number(9);                                            
  lcopyrighterid_temp number(9);                                                
  sstockoutflag_temp varchar2(1);                                               
begin                                                                           
  result :=0;                                                                   

                                                                                
  select count(1) into lcounter from program where programid = lprogramid;      
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sname is null) then                                                       
    result := -170101;                                                          
    resultdesc := 'name is not allow empty.';                                   

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           
    return;                                                                     
  else                                                                          
    sname_temp := sname;                                                        
  end if;                                                                       
                                                                                
  begin                                                                         
    if (dlicensingwindowstart is null) then                                     
      dlicensingwindowstart_temp := null;                                       
    else                                                                        
      select to_date(dlicensingwindowstart,'yyyymmddhh24miss') into dlicensingwi
ndowstart_temp from dual;                                                       

                                                                                
    end if;                                                                     
                                                                                
    if (dlicensingwindowend is null) then                                       
      dlicensingwindowend_temp := null;                                         
    else                                                                        
      select to_date(dlicensingwindowend,'yyyymmddhh24miss') into dlicensingwind
owend_temp from dual;                                                           
                                                                                
    end if;                                                                     
    if (djoinrecycletime is null) then                                          
      djoinrecycletime_temp :=null;                                             
    else                                                                        

      select to_date(djoinrecycletime,'yyyymmddhh24miss') into djoinrecycletime_
temp from dual;                                                                 
                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170105;                                                          
    resultdesc := 'the format of licensingwindowstart/licensingwindowend is not 
correct.';                                                                      
                                                                                

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of licensingwindowstart/licensingwindowend 
is not correct.');                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  if (dlicensingwindowend_temp is not null and                                  
      dlicensingwindowstart_temp is not null and                                
      dlicensingwindowend_temp <= dlicensingwindowstart_temp) then              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     

    result := -170119;                                                          
    resultdesc := 'licensingwindowend must later than licensingwindowstart.';   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('licensingwindowend must later than licensingwindowstar
t.');                                                                           
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               
    from vsp                                                                    

    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (llabeltype is not null) then                                              
    select count(1)                                                             

    into llabeltype_counter                                                     
    from labeltype                                                              
    where labeltype = llabeltype;                                               
    if (llabeltype_counter <= 0) then                                           
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170401;                                                        
      resultdesc := 'labeltype not exist in table labeltype.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('labeltype not exist in table labeltype.');          
      return;                                                                   
    end if;                                                                     

    llabeltype_temp := llabeltype;                                              
  end if;                                                                       
                                                                                
  if(scontentprovider is not null) then                                         
      select count(1)                                                           
      into lcounter                                                             
      from contentprovider                                                      
      where name = scontentprovider;                                            
      if(lcounter >= 1) then                                                    
         select contentproviderid                                               
         into lcontentproviderid_temp                                           
         from contentprovider                                                   
         where name = scontentprovider and rownum = 1;                          

      else                                                                      
        select contentproviderid.nextval into lcontentproviderid_temp from dual;
                                                                                
                                                                                
        insert into contentprovider(contentproviderid,vspid,name,createdate,last
updatetime)                                                                     
                                                                                
        values(lcontentproviderid_temp,lvspid,scontentprovider,sysdate,sysdate);
                                                                                
                                                                                
        end if;                                                                 
    end if;                                                                     
                                                                                

     if(scopyright is not null) then                                            
      select count(1)                                                           
      into lcounter                                                             
      from copyrighter                                                          
      where name = scopyright;                                                  
      if(lcounter >= 1) then                                                    
         select copyrighterid                                                   
         into lcopyrighterid_temp                                               
         from copyrighter                                                       
         where name = scopyright;                                               
      else                                                                      
        select copyrighterid.nextval into lcopyrighterid_temp from dual;        
        insert into copyrighter(copyrighterid,name,createdate,lastupdatetime)   

        values(lcopyrighterid_temp,scopyright,sysdate,sysdate);                 
        end if;                                                                 
    end if;                                                                     
                                                                                
  if (fprice is null) then                                                      
    fprice_temp := 0;                                                           
  else                                                                          
    fprice_temp := fprice;                                                      
  end if;                                                                       
                                                                                
                                                                                
  if (sstatus is null) then                                                     
    sstatus_temp := '1';                                                        

  else                                                                          
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                
  select status into program_status from program where programid = lprogramid;  
                                                                                
   If (program_status Is Not Null) Then                                         
     If (program_status = '9') Then                                             
       sstatus_temp := program_status;                                          
     End If;                                                                    
   End If;                                                                      
                                                                                
  if (sseriesflag is not null) then                                             

    sseriesflag_temp := sseriesflag;                                            
  end if;                                                                       
                                                                                
  if(sStockoutflag is not null) then                                            
     sstockoutflag_temp :=sStockoutflag;                                        
  end if;                                                                       
                                                                                
  begin                                                                         
    update program                                                              
    set vspid = lvspid,                                                         
        name = sname_temp,                                                      
        code2 = scode2,                                                         
        title_sort_name = stitle_sort_name,                                     

        title_search_name = stitle_search_name,                                 
        price = fprice_temp,                                                    
        status = sstatus_temp,                                                  
        description = sdescription,                                             
        description1 = sdescription1,                                           
        memo = smemo,                                                           
        alias = salias,                                                         
        epititle = sepititle,                                                   
        language = slanguage,                                                   
        orgairdate = sorgairdate,                                               
        licensingwindowstart = dlicensingwindowstart_temp,                      
        licensingwindowend = dlicensingwindowend_temp,                          
        episodeindex = lepisodeindex,                                           

        episodenum = lepisodenum,                                               
        seriesflag = sseriesflag_temp,                                          
        captionlanguage = scaptionlanguage,                                     
        copyright = scopyright,                                                 
        source = ssource,                                                       
        columnname = scolumnname,                                               
        sname           = ssname          ,                                     
        kpeople         = skpeople        ,                                     
        director        = sdirector       ,                                     
        scriptwriter    = sscriptwriter   ,                                     
        compere         = scompere        ,                                     
