        PGMCATEGORYDTLID = sPGMCATEGORYDTLID,                                   
		audioMsgType = sAudioMsgType                                                  
    where programid = lprogramid;                                               
    update globalcodemap                                                        
    set status = decode(sstatus_temp,'9','1','0')                               

    where objecttype=ctmsconstant_def.globaltype_program                        
    and objectid=lprogramid;                                                    
                                                                                
    if (scolumnpath is not null) then                                           
      str_list := split(scolumnpath, '@');                                      
      l_row := str_list.first;                                                  
      while (l_row is not null)                                                 
      loop                                                                      
        dbms_output.put_line(trim(str_list(l_row)));                            
        if (parent_id is null) then                                             
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid is null and vspid=lvspid;                         
                                                                                

          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),null,l_row-1,lvspid,sysdate
);                                                                              
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid is null and vspid=lvspid;                    
                                                                                
          end if;                                                               
        else                                                                    
          select count(1) into directory_counter from directory where name=trim(

str_list(l_row)) and parentid=parent_id and vspid=lvspid;                       
                                                                                
          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),parent_id,l_row-1,lvspid,sy
sdate);                                                                         
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid=parent_id and vspid=lvspid;                  
                                                                                
          end if;                                                               

        end if;                                                                 
        parent_id := directory_id_temp;                                         
        l_row := str_list.next(l_row);                                          
      end loop;                                                                 
                                                                                
      l_row := str_list.last;                                                   
      if (l_row is not null) then                                               
        directory_last_id := directory_id_temp;                                 
        delete from directorydtl where objtype='1' and objid=lprogramid;        
        insert into directorydtl(directorydtlid,directoryid,objtype,objid,create
date) values(directorydtlid.nextval,directory_last_id,'1',lprogramid,sysdate);  
                                                                                
      end if;                                                                   

   end if;                                                                      
   if (result != 0) then                                                        
     rollback;                                                                  
     return;                                                                    
   end if;                                                                      
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler

rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result :=0;                                                                   
  resultdesc := 'successful!';                                                  

  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
