procedure spprogrammediacontentadd                                              
(                                                                               
  lprogrammediacontentid                in number,                              
  sobjecttype                           in varchar2,            --1:program,2:se
ries                                                                            
                                                                                
  lobjectid                             in number,                              
  lmediacontentid                       in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         

)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lprogrammediacontentid_temp number(9);                                        
  scontentname_temp varchar2(320);                                              
  sobjecttype_temp char(1) := '1';                                              
  sDuration_temp varchar2(20);                                                  
  sProgramDuration  program.duration%Type;                                      
  lprogramid        program.programid%Type;                                     
  functionname varchar(40) := 'spprogrammediacontentadd: ';                     
begin                                                                           
  result := 0;                                                                  

  resultdesc := 'successful!';                                                  
                                                                                
  if (sobjecttype is not null) then                                             
    sobjecttype_temp := sobjecttype;                                            
  end if;                                                                       
                                                                                
  if (sobjecttype_temp is null or sobjecttype_temp not in ('1','2')) then       
    result := -170209;                                                          
    resultdesc := 'objecttype must in (''1'',''2'').';                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('objecttype must in (''1'',''2'').');                  
    return;                                                                     
  end if;                                                                       

                                                                                
  if (sobjecttype_temp = '1') then                                              
    select count(1)                                                             
    into lcounter                                                               
    from program                                                                
    where programid = lobjectid;                                                
    if (lcounter = 0) then                                                      
      result := -170206;                                                        
      resultdesc := 'objectid not exist in table program.';                     
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objectid not exist in table program.');             
      return;                                                                   
    end if;                                                                     

  else                                                                          
    select count(1)                                                             
    into lcounter                                                               
    from series                                                                 
    where seriesid = lobjectid;                                                 
    if (lcounter = 0) then                                                      
      result := -170206;                                                        
      resultdesc := 'objectid not exist in table series.';                      
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objectid not exist in table series');               
      return;                                                                   
    end if;                                                                     
  end if;                                                                       

                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from programmediacontent                                                      
  where objtype = sobjecttype_temp                                              
  and objid = lobjectid                                                         
  and mediacontentid = lmediacontentid;                                         
  if (lcounter = 1) then                                                        
    result := 0;                                                                
    resultdesc := 'have affect row.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('have affect row.');                                   
    return;                                                                     

  end if;                                                                       
                                                                                
  begin                                                                         
    select contentname,duration into scontentname_temp,sDuration_temp           
    from mediacontent where mediacontentid = lmediacontentid;                   
  exception                                                                     
  when no_data_found then                                                       
    result := -170207;                                                          
    resultdesc := 'contentid not exist in table mediacontent.';                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('contentid not exist in table mediacontent.');         
    return;                                                                     
  end;                                                                          

                                                                                
  begin                                                                         
    if (scontentname_temp is null or length(scontentname_temp) = 0) then        
      if (sobjecttype_temp = '1') then                                          
        select name                                                             
        into scontentname_temp                                                  
        from program                                                            
        where programid = lobjectid;                                            
      else                                                                      
        select name                                                             
        into scontentname_temp                                                  
        from series                                                             
        where seriesid = lobjectid;                                             

      end if;                                                                   
                                                                                
      update mediacontent                                                       
      set contentname = scontentname_temp                                       
      where mediacontentid = lmediacontentid;                                   
    end if;                                                                     
                                                                                
    If (sobjecttype_temp = '1') Then                                            
        If ltrim(rtrim(sDuration_temp)) Is Not Null And                         
           ltrim(rtrim(sDuration_temp)) <> '0' Then                             
           Begin                                                                
             Select a.duration, a.programid                                     
               Into sProgramDuration, lprogramid                                

               From Program a                                                   
              Where a.programid = lobjectid;                                    
           Exception                                                            
             When Others Then                                                   
               Null;                                                            
           End;                                                                 
                                                                                
           If ltrim(rtrim(sprogramduration)) Is Null Or                         
              (ltrim(rtrim(sprogramduration)) Is Not Null And                   
              to_number(sDuration_temp) > to_number(sprogramduration)) Then     
              Update Program                                                    
                 Set duration = sDuration_temp                                  
               Where programid = lprogramid;                                    

           End If;                                                              
        End If;                                                                 
      End If;                                                                   
                                                                                
    if (lprogrammediacontentid is null) then                                    
      select programmediacontentid.nextval into lprogrammediacontentid_temp from
 dual;                                                                          
                                                                                
    else                                                                        
      lprogrammediacontentid_temp := lprogrammediacontentid;                    
    end if;                                                                     
                                                                                
    insert into programmediacontent(programmediacontentid,objtype,objid,mediacon

tentid)                                                                         
                                                                                
    values(lprogrammediacontentid_temp,sobjecttype_temp,lobjectid,lmediacontenti
d);                                                                             
                                                                                
    if (sobjecttype_temp = '1') then                                            
      spSynProgramBitRate(sobjecttype_temp,lobjectid,lstaffid,0,result,resultdes
c);                                                                             
                                                                                
    end if ;                                                                    
                                                                                
  exception                                                                     
  when others then                                                              

    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          

  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lprogrammediacontentid_temp);                           
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
