PROCEDURE spProgramcastsRemove                                                  
(                                                                               
  lPROGRAMCASTID                        IN number,                              
  lPROGRAMID                            IN number,                              
  lCASTACTROLEID                        IN number,                              
  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         

)                                                                               
IS                                                                              
  lCounter number(9);                                                           
  lPROGRAMCASTID_TEMP number(9);                                                
  FunctionName varchar(40) := 'spProgramcastsRemove: ';                         
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  IF (lPROGRAMCASTID is null) THEN                                              
    select count(1)                                                             
    into lCounter                                                               
    from PROGRAMCASTS                                                           
    where PROGRAMID = lPROGRAMID                                                

    and CASTACTROLEID = lCASTACTROLEID;                                         
    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    select PROGRAMCASTID                                                        
    into lPROGRAMCASTID_TEMP                                                    
    from PROGRAMCASTS                                                           
    where PROGRAMID = lPROGRAMID                                                

    and CASTACTROLEID = lCASTACTROLEID;                                         
  ELSE                                                                          
    lPROGRAMCASTID_TEMP := lPROGRAMCASTID;                                      
  END IF;                                                                       
                                                                                
  BEGIN                                                                         
    select count(1) into lCounter from PROGRAMCASTS where PROGRAMCASTID = lPROGR
AMCASTID_TEMP;                                                                  
                                                                                
    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  

      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    delete from PROGRAMCASTS where PROGRAMCASTID = lPROGRAMCASTID_TEMP;         
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      

                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      

END;                                                                            
PROCEDURE spProgramcastsAdd                                                     
(                                                                               
  lPROGRAMCASTID                        IN number,                              
  lPROGRAMID                            IN number,                              
