  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              
  lCounter number(9);                                                           

  lCounter1 number(9);                                                          
  lPROGRAMCASTID_TEMP number(9);                                                
  FunctionName varchar(40) := 'spProgramcastsAdd: ';                            
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter FROM Castactrole                                
  where CASTACTROLEID = lCASTACTROLEID;                                         
  IF (lCounter <= 0) THEN                                                       
    result := -170611;                                                          
    ResultDesc := 'CASTACTROLEID not found.';                                   
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('CASTACTROLEID not found.');                           

    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  select count(1) into lCounter FROM program                                    
  where programid = lPROGRAMID;                                                 
  IF (lCounter <= 0) THEN                                                       
    result := -170612;                                                          
    ResultDesc := 'PROGRAMID not found.';                                       
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('PROGRAMID not found.');                               
    RETURN;                                                                     
  END IF;                                                                       
                                                                                

  BEGIN                                                                         
    select count(1) into lCounter FROM programcasts                             
  where programid = lPROGRAMID and CASTACTROLEID = lCASTACTROLEID;              
  IF (lCounter = 0) THEN                                                        
   IF (lPROGRAMCASTID is null) THEN                                             
      select PROGRAMCASTID.nextval into lPROGRAMCASTID_TEMP from dual;          
    ELSE                                                                        
      lPROGRAMCASTID_TEMP := lPROGRAMCASTID;                                    
    END IF;                                                                     
                                                                                
    insert into programcasts(programcastid,programid,castactroleid)             
    values(lPROGRAMCASTID_TEMP,lPROGRAMID,lCASTACTROLEID);                      
  END IF;                                                                       

                                                                                
                                                                                
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR

( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result := 0;                                                                  
  ResultDesc := to_char(lPROGRAMCASTID_TEMP);                                   
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
procedure spprogramadd                                                          
(                                                                               

  lprogramid                            in number,                              
  lvspid                                in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
