  ssourcetype                           in varchar2,                            
  slinkurl                              in varchar2,                            
  llabeltype                            in number,                              
  scolumnpath                           in varchar2,                            
  sstorageflag                          in varchar2,                            
  stype1                                in varchar2,                            
  slockflag                             in varchar2,                            
  sOriginalCountry                      in varchar2,                            
  seditmode                             in varchar2,                            
  sRating                               in varchar2,                            

  sNewPrice                             in varchar2,                            
  stags                                 in varchar2,                            
  scontractnum                          in varchar2,                            
  scptag                                in varchar2,                            
  scpactivetime                         in varchar2,                            
  sprogramtype                          in number,                              
  sviewpoint                            in varchar2,                            
  sstarlevel                            in varchar2,                            
  sawards                               in varchar2,                            
  slabelids                             in varchar2,                            
  sautoflag                             in varchar2,                            
  srecycleflag                          in varchar2,                            
  soperater                             in varchar2,                            

  djoinrecycletime                      in varchar2,                            
  scpoverduetime                        in varchar2,                            
  scpdescription                        in varchar2,                            
  scpstatus                             in varchar2,                            
  sneedReleaseFlag                      in varchar2,                            
  sprogramcode                          in varchar2,                            
  snewprice2                            in varchar2,                            
  snewprice3                            in varchar2,                            
  sTvcolumnid                           in varchar2,                            
  spgmcategoryid                        in varchar2,                            
  spgmsndclassid                        in varchar2,                            
  sDefinitionFlag                       in varchar2,                            
  sMacrovision                          in varchar2,                            

  sKeywords                             in varchar2,                            
  sRMediaCode                           in varchar2,                            
  scid                                  in varchar2,                            
  svid                                  in varchar2,                            
  sProductionBase                       in varchar2,                            
  sEditor                               in varchar2,                            
  sAccesser                             in varchar2,                            
  sColumnPhoneNo                        in varchar2,                            
  sColumnEmail                          in varchar2,                            
  sProducer                             in varchar2,                            
  sProduce                              in varchar2,                            
  sMonth                                in number,                              
  sVideoDataRate                        in varchar2,                            

  sTvCloumnName                         in varchar2,                            
	sKEYMAN                               in varchar2,                             
	sTAGLIST                              in varchar2,                             
	sDIRECTORINFO                          in varchar2,                            
	sSCREENWRITERINFO											in varchar2,                                       
	sVIDEOID                              in varchar2,                             
	sEXTENDFIELD1                          in varchar2,                            
	sEXTENDFIELD2													in varchar2,                                         
	sEXTENDFIELD3													in varchar2,                                         
	sEXTENDFIELD4													in varchar2,                                         
	sEXTENDFIELD5													in varchar2,                                         
	sPGMCATEGORYDTLID						          in varchar2,                                  
	sAudioMsgType							in varchar2,                                               

  sFramerate                            in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
                                                                                
)                                                                               
is                                                                              
                                                                                
  lprogramid_temp number(9);                                                    
  lcounter number(9);                                                           
  dlicensingwindowstart_temp date;                                              
  dlicensingwindowend_temp date;                                                

  fprice_temp number(12,2);                                                     
  sstatus_temp varchar2(2);                                                     
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sglobalcodemapstatus char(1) := '0';                                          
  sseriesflag_temp char(1) := '0';                                              
  llabeltype_temp number(4) := 0;                                               
  llabeltype_counter number(9);                                                 
  djoinrecycletime_temp date;                                                   
                                                                                
  functionname varchar(40) := 'spprogramadd: ';                                 
                                                                                
  str_list type_split := type_split();                                          

  l_row number(9);                                                              
  directory_counter number(9);                                                  
  parent_id number(9);                                                          
  directory_id_temp number(9);                                                  
  directory_last_id number(9);                                                  
  maxstorage_temp number(9);                                                    
  filesize_sum_temp number(9);                                                  
  lcontentproviderid_temp number(9);                                            
  lcopyrighterid_temp number(9);                                                
                                                                                
begin                                                                           
  result :=0;                                                                   
                                                                                

  if (sname is null) then                                                       
    result := -170101;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    if (dlicensingwindowstart is null) then                                     
      dlicensingwindowstart_temp := null;                                       
    else                                                                        
      select to_date(dlicensingwindowstart,'yyyymmddhh24miss') into dlicensingwi

ndowstart_temp from dual;                                                       
                                                                                
    end if;                                                                     
                                                                                
    if (dlicensingwindowend is null) then                                       
      dlicensingwindowend_temp := null;                                         
    else                                                                        
      select to_date(dlicensingwindowend,'yyyymmddhh24miss') into dlicensingwind
owend_temp from dual;                                                           
                                                                                
    end if;                                                                     
                                                                                
    if (djoinrecycletime is null) then                                          

      djoinrecycletime_temp :=null;                                             
    else                                                                        
      select to_date(djoinrecycletime,'yyyymmddhh24miss') into djoinrecycletime_
temp from dual;                                                                 
                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170105;                                                          
    resultdesc := 'the format of licensingwindowstart/licensingwindowend is not 

correct.';                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of licensingwindowstart/licensingwindowend 
is not correct.');                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  if (dlicensingwindowend_temp is not null and                                  
      dlicensingwindowstart_temp is not null and                                
      dlicensingwindowend_temp <= dlicensingwindowstart_temp) then              
    if (iiscommit = 1) then                                                     

      rollback work;                                                            
    end if;                                                                     
    result := -170119;                                                          
    resultdesc := 'licensingwindowend must later than licensingwindowstart.';   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('licensingwindowend must later than licensingwindowstar
t.');                                                                           
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             

    into lcounter                                                               
    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   

    end if;                                                                     
  end if;                                                                       
                                                                                
  if (llabeltype is not null) then                                              
    select count(1)                                                             
    into llabeltype_counter                                                     
    from labeltype                                                              
    where labeltype = llabeltype;                                               
    if (llabeltype_counter <= 0) then                                           
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170401;                                                        

      resultdesc := 'labeltype not exist in table labeltype.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('labeltype not exist in table labeltype.');          
      return;                                                                   
    end if;                                                                     
    llabeltype_temp := llabeltype;                                              
  end if;                                                                       
                                                                                
  if (fprice is null) then                                                      
    fprice_temp := 0;                                                           
  else                                                                          
    fprice_temp := fprice;                                                      
  end if;                                                                       

                                                                                
  if (sstatus is null) then                                                     
    sstatus_temp := '1';                                                        
  else                                                                          
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                
  if (sstatus_temp = '9') then                                                  
    sglobalcodemapstatus := '1';                                                
  end if;                                                                       
                                                                                
  if (sseriesflag is not null) then                                             
    sseriesflag_temp := sseriesflag;                                            

  end if;                                                                       
                                                                                
  if (sstorageflag = '1') then                                                  
    select maxstorage into maxstorage_temp from vsp where vspid=lvspid;         
    if (maxstorage_temp > 0 ) then                                              
      select (nvl(sum(filesize),0))/1024/1024 into filesize_sum_temp from mediac
ontent where status='4' and vspid=lvspid;                                       
                                                                                
      if (filesize_sum_temp > maxstorage_temp) then                             
        result := -170701;                                                      
        resultdesc := 'exceeds the capacity.';                                  
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('exceeds the capacity.');                          

        return;                                                                 
      end if;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
                                                                                
  begin                                                                         
    if (lprogramid is null) then                                                
      spgetobjectid(ctmsconstant_def.objectid_programid,lprogramid_temp,result,r
esultdesc);                                                                     
                                                                                
      if (result != 0) then                                                     
        dbms_output.put_line(functionname||'result = '||result);                

        dbms_output.put_line('get objectid failed.');                           
        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        return;                                                                 
      end if;                                                                   
    else                                                                        
      lprogramid_temp := lprogramid;                                            
    end if;                                                                     
                                                                                
    scode_temp := scode;                                                        
    if (scode is null) then                                                     
      spgetglobalcode(lvspid,ctmsconstant_def.globalcode_program,lprogramid_temp

,scode_temp,result);                                                            
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                
    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     

                                                                                
   if(scontentprovider is not null) then                                        
      select count(1)                                                           
      into lcounter                                                             
      from contentprovider                                                      
      where name = scontentprovider;                                            
      if(lcounter >= 1) then                                                    
         select contentproviderid                                               
         into lcontentproviderid_temp                                           
         from contentprovider                                                   
         where name = scontentprovider and rownum =1;                           
      else                                                                      
        select contentproviderid.nextval into lcontentproviderid_temp from dual;

                                                                                
                                                                                
        insert into contentprovider(contentproviderid,vspid,name,createdate,last
updatetime)                                                                     
                                                                                
        values(lcontentproviderid_temp,lvspid,scontentprovider,sysdate,sysdate);
                                                                                
                                                                                
        end if;                                                                 
    end if;                                                                     
                                                                                
    if(scopyright is not null) then                                             
      select count(1)                                                           

      into lcounter                                                             
      from copyrighter                                                          
      where name = scopyright;                                                  
      if(lcounter >= 1) then                                                    
         select copyrighterid                                                   
         into lcopyrighterid_temp                                               
         from copyrighter                                                       
         where name = scopyright;                                               
      else                                                                      
        select copyrighterid.nextval into lcopyrighterid_temp from dual;        
        insert into copyrighter(copyrighterid,name,createdate,lastupdatetime)   
        values(lcopyrighterid_temp,scopyright,sysdate,sysdate);                 
        end if;                                                                 

    end if;                                                                     
                                                                                
    insert into program(programid,vspid,name,code,code2,title_sort_name,createst
affid,seriesflag,                                                               
                                                                                
                        title_search_name,price,status,description,description1,
memo,alias,epititle,                                                            
                                                                                
                        language,orgairdate,licensingwindowstart,licensingwindow
end,                                                                            
                                                                                
                        episodeindex,episodenum,captionlanguage,copyright,source
,columnname,                                                                    

                                                                                
                        sname,kpeople,director,scriptwriter,compere,guest,report
er,                                                                             
                                                                                
                        opincharge,duration,crbegin,rtime,fcl,parachannel,recast
time1,                                                                          
                                                                                
                        recastchannel1,recasttime2,recastchannel2,recasttime3,re
castchannel3,sourcemedia,pgmcategory,                                           
                                                                                
                        pgmsndclass,contentprovider,reserve1,reserve2,reserve3,r
eserve4,reserve5,genre,releaseyear,sourcetype,linkurl,labeltype,columnpath,type1
,lockflag,Originalcountry,contentproviderid,copyrighterid,editmode,programtype,l

abelids,autoflag,                                                               
                                                                                
                        Rating,NewPrice,tags,viewpoint,starlevel,awards,contract
num,recycleflag,cptag,cpactivetime,overdueTime,operater,joinrecycletime,cpdescri
ption,cpstatus,needReleaseFlag,programcode,newprice2,newprice3,Tvcolumnid,pgmcat
egoryid,pgmsndclassid,DefinitionFlag,Macrovision,Keywords,RMediaCode,cid,vid,Pro
ductionBase,Editor,Accesser,ColumnPhoneNo,ColumnEmail,Producer,Produce,Month,Vid
eoDataRate,TvCloumnName,Framerate,KEYMAN,TAGLIST,DIRECTORINFO,SCREENWRITERINFO,V
IDEOID,EXTENDFIELD1,EXTENDFIELD2,EXTENDFIELD3,EXTENDFIELD4,EXTENDFIELD5,PGMCATEG
ORYDTLID,audioMsgType)                                                          
                                                                                
    values(lprogramid_temp,lvspid,sname,scode_temp,scode2_temp,stitle_sort_name,
lstaffid,sseriesflag_temp,                                                      

                                                                                
           stitle_search_name,fprice_temp,sstatus_temp,sdescription,sdescription
1,smemo,salias,sepititle,                                                       
                                                                                
           slanguage,sorgairdate,dlicensingwindowstart_temp,dlicensingwindowend_
temp,                                                                           
                                                                                
           lepisodeindex,lepisodenum,scaptionlanguage,scopyright,ssource,scolumn
name,                                                                           
                                                                                
           ssname,skpeople,sdirector,sscriptwriter,scompere,sguest,sreporter,   
           sopincharge,sduration,scrbegin,srtime,sfcl,sparachannel,srecasttime1,
                                                                                

                                                                                
           srecastchannel1,srecasttime2,srecastchannel2,srecasttime3,srecastchan
nel3,ssourcemedia,spgmcategory,                                                 
                                                                                
           spgmsndclass,scontentprovider,sreserve1,sreserve2,sreserve3,sreserve4
,sreserve5,sgenre,sreleaseyear,ssourcetype,slinkurl,llabeltype_temp,scolumnpath,
stype1,slockflag,soriginalCountry,lcontentproviderid_temp,lcopyrighterid_temp,se
ditmode,sprogramtype,slabelids,sautoflag,                                       
                                                                                
           sRating,sNewPrice,stags,sviewpoint,sstarlevel,sawards,scontractnum,sr
ecycleflag,scptag,scpactivetime,scpoverduetime,soperater,djoinrecycletime_temp,s
cpdescription,scpstatus,sneedReleaseFlag,sprogramcode,snewprice2,snewprice3,sTvc
olumnid,spgmcategoryid,spgmsndclassid,sDefinitionFlag,sMacrovision,sKeywords,sRM

ediaCode,scid,svid,sProductionBase,sEditor,sAccesser,sColumnPhoneNo,sColumnEmail
,sProducer,sProduce,sMonth,sVideoDataRate,sTvCloumnName,sFramerate,sKEYMAN,sTAGL
IST,sDIRECTORINFO,sSCREENWRITERINFO,sVIDEOID,sEXTENDFIELD1,sEXTENDFIELD2,sEXTEND
FIELD3,sEXTENDFIELD4,sEXTENDFIELD5,sPGMCATEGORYDTLID,sAudioMsgType);            
                                                                                
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_program,lprogramid_temp,scode_te
mp,scode2_temp,sglobalcodemapstatus,null,null,null,result);                     
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     

                                                                                
                                                                                
    if (scolumnpath is not null) then                                           
      str_list := split(scolumnpath, '@');                                      
      l_row := str_list.first;                                                  
      while (l_row is not null)                                                 
      loop                                                                      
        dbms_output.put_line(trim(str_list(l_row)));                            
        if (parent_id is null) then                                             
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid is null and vspid=lvspid;                         
                                                                                
          if (directory_counter <= 0) then                                      

            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),null,l_row-1,lvspid,sysdate
);                                                                              
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid is null and vspid=lvspid;                    
                                                                                
          end if;                                                               
        else                                                                    
          select count(1) into directory_counter from directory where name=trim(
str_list(l_row)) and parentid=parent_id and vspid=lvspid;                       

                                                                                
          if (directory_counter <= 0) then                                      
            select directoryid.nextval into directory_id_temp from dual;        
            insert into directory(directoryid,name,parentid,"LEVEL",vspid,create
date) values(directory_id_temp,trim(str_list(l_row)),parent_id,l_row-1,lvspid,sy
sdate);                                                                         
                                                                                
          else                                                                  
            select directoryid into directory_id_temp from directory where name=
trim(str_list(l_row)) and parentid=parent_id and vspid=lvspid;                  
                                                                                
          end if;                                                               
        end if;                                                                 

        parent_id := directory_id_temp;                                         
        l_row := str_list.next(l_row);                                          
      end loop;                                                                 
                                                                                
      l_row := str_list.last;                                                   
      if (l_row is not null) then                                               
        directory_last_id := directory_id_temp;                                 
        insert into directorydtl(directorydtlid,directoryid,objtype,objid,create
date) values(directorydtlid.nextval,directory_last_id,'1',lprogramid_temp,sysdat
e);                                                                             
                                                                                
      end if;                                                                   
    end if;                                                                     

    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler

rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lprogramid_temp);                                       

  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure sppicturemapremove                                                    
(                                                                               
  lpicturemapid                         in number,                              
  lobjtype                              in number,                              
  lobjid                                in number,                              
  ltype                                 in number,                              
  lmetapictureid                        in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         

)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lobjtype_temp number(9);                                                      
  functionname varchar(40) := 'sppicturemapremove: ';                           
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  begin                                                                         
    if (lpicturemapid is null) then                                             
      if (ltype is null) then                                                   

        delete from picturemap                                                  
        where objtype = lobjtype                                                
        and objid = lobjid                                                      
        and metapictureid = lmetapictureid;                                     
      else                                                                      
        delete from picturemap                                                  
        where objtype = lobjtype                                                
        and objid = lobjid                                                      
        and picturetypeid in                                                    
        (                                                                       
          select picturetypeid                                                  
          from picturetype                                                      
          where picturetype = ltype                                             

          and objtype = lobjtype                                                
        )                                                                       
        and metapictureid = lmetapictureid;                                     
      end if;                                                                   
    else                                                                        
      delete from picturemap where picturemapid = lpicturemapid;                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    rollback work;                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
