procedure sppicturemapmodify                                                    
(                                                                               
  lpicturemapid                         in number,                              
  lobjtype                              in number,      --1: bundledcontent pict
ure                                                                             

                                                                                
                                                        --2: channel picture    
                                                        --3: category picture   
                                                        --4: program picture    
                                                        --5: series picture     
  lobjid                                in number,                              
  ltype                                 in number,                              
  lmetapictureid                        in number,                              
  lsequence                             in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         

)                                                                               
is                                                                              
                                                                                
  lpicturemapid_temp number(9);                                                 
  lsequence_temp number(9);                                                     
  lcounter number(9);                                                           
  lpicturetypeid_temp number(9);                                                
  functionname varchar(40) := 'sppicturemapmodify: ';                           
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  if (lpicturemapid is null) then                                               

  	select picturemapid into lpicturemapid_temp from picturemap                  
  	where objtype = lobjtype and objid = lobjid and metapictureid = lmetapicturei
d;                                                                              
                                                                                
  else                                                                          
  	lpicturemapid_temp := lpicturemapid;                                         
  end if;                                                                       
                                                                                
  lsequence_temp := lsequence;                                                  
  if (lsequence is null) then                                                   
    lsequence_temp := 9999;                                                     
  end if;                                                                       
                                                                                

  select count(1)                                                               
  into lcounter                                                                 
  from picturetype                                                              
  where objtype = lobjtype                                                      
  and picturetype = ltype;                                                      
  if (lcounter != 1) then                                                       
    result := -174512;                                                          
    resultdesc := 'picture type not found.';                                    
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('picture type not found.');                            
    return;                                                                     
  end if;                                                                       
                                                                                

  select picturetypeid                                                          
  into lpicturetypeid_temp                                                      
  from picturetype                                                              
  where objtype = lobjtype                                                      
  and picturetype = ltype;                                                      
                                                                                
  begin                                                                         
    update picturemap                                                           
    set sequence = lsequence_temp,                                              
    picturetypeid = lpicturetypeid_temp                                         
    where picturemapid=lpicturemapid_temp;                                      
  exception                                                                     
  when others then                                                              

    rollback work;                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                

  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lpicturemapid);                                         
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure sppicturemapadd                                                       
(                                                                               
  lpicturemapid                         in number,                              
  lobjtype                              in number,      --1: bundledcontent pict
ure                                                                             
                                                                                
                                                        --2: channel picture    
                                                        --3: category picture   

                                                        --4: program picture    
                                                        --5: series picture     
  lobjid                                in number,                              
  ltype                                 in number,                              
  lmetapictureid                        in number,                              
  lsequence                             in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                

  lcounter number(9);                                                           
  lpicturemapid_temp number(9);                                                 
  lpicturemapid_update_temp number(9);                                          
  lpicturetypeid_temp number(9);                                                
  lsequence_temp number(9);                                                     
  functionname varchar(40) := 'sppicturemapadd: ';                              
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  if (lobjtype is null or lobjtype not in ('1','2','3','4','5','7','13')) then  
    result := -174501;                                                          
    resultdesc := 'objtype is wrong.'||lobjtype;                                

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('objtype is wrong.');                                  
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lobjtype = 1) then                                                        
    select count(1) into lcounter from bundledcontent where bundledcontentid = l
objid;                                                                          
                                                                                
    if (lcounter <= 0) then                                                     
      result := -174502;                                                        
      resultdesc := 'objid not exist in table bundledcontent.';                 
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('objid not exist in table bundledcontent.');         
      return;                                                                   
    end if;                                                                     
  elsif (lobjtype = 2) then                                                     
    select count(1) into lcounter from channel where channelid = lobjid;        
    if (lcounter <= 0) then                                                     
      result := -174503;                                                        
      resultdesc := 'objid not exist in table channel.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table channel.');                
      return;                                                                   
    end if;                                                                     
  elsif (lobjtype = 3) then                                                     

    select count(1) into lcounter from category where categoryid = lobjid;      
    if (lcounter <= 0) then                                                     
      result := -174504;                                                        
      resultdesc := 'objid not exist in table category.';                       
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table category.');               
      return;                                                                   
    end if;                                                                     
  elsif (lobjtype = 4) then                                                     
    select count(1) into lcounter from program where programid = lobjid;        
    if (lcounter <= 0) then                                                     
      result := -174505;                                                        
      resultdesc := 'objid not exist in table program.';                        

      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table program.');                
      return;                                                                   
    end if;                                                                     
  elsif (lobjtype = 5) then                                                     
    select count(1) into lcounter from series where seriesid = lobjid;          
    if (lcounter <= 0) then                                                     
      result := -174506;                                                        
      resultdesc := 'objid not exist in table series.';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   
    end if;                                                                     

   elsif (lobjtype = 7) then                                                    
    select count(1) into lcounter from cast where castid = lobjid;              
    if (lcounter <= 0) then                                                     
      result := -174507;                                                        
      resultdesc := 'objid not exist in table cast.';                           
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table cast.');                   
      return;                                                                   
    end if;                                                                     
   elsif (lobjtype = 13 ) then                                                  
    select count(1) into lcounter from schedule where scheduleid = lobjid;      
    if (lcounter <= 0) then                                                     
      resultdesc := 'objid not exist in table cast.';                           

      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table cast.');                   
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from picturetype                                                              
  where objtype = lobjtype                                                      
  and picturetype = ltype;                                                      
  if (lcounter != 1) then                                                       
    result := -174512;                                                          

    resultdesc := 'picture type not found.';                                    
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('picture type not found.');                            
    return;                                                                     
  end if;                                                                       
                                                                                
  select picturetypeid                                                          
  into lpicturetypeid_temp                                                      
  from picturetype                                                              
  where objtype = lobjtype                                                      
  and picturetype = ltype;                                                      
                                                                                
  select count(1)                                                               

  into lcounter                                                                 
  from metapicture                                                              
  where metapictureid = lmetapictureid;                                         
  if (lcounter <= 0) then                                                       
    result := -174513;                                                          
    resultdesc := 'metapictureid not exist in table metapicture.';              
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('metapictureid not exist in table metapicture.');      
    return;                                                                     
  end if;                                                                       
                                                                                
  lsequence_temp := lsequence;                                                  
  if (lsequence is null) then                                                   

    lsequence_temp := 9999;                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    select count(1) into lcounter from picturemap where objtype = lobjtype and o
bjid = lobjid                                                                   
                                                                                
    and metapictureid = lmetapictureid;                                         
    if (lcounter = 1) then                                                      
      update picturemap                                                         
      set sequence = lsequence_temp,                                            
      picturetypeid = lpicturetypeid_temp                                       
      where objtype = lobjtype                                                  

      and objid = lobjid                                                        
      and metapictureid = lmetapictureid;                                       
      select picturemapid into lpicturemapid_update_temp from picturemap where o
bjtype = lobjtype and objid = lobjid and metapictureid = lmetapictureid;        
                                                                                
      lpicturemapid_temp := lpicturemapid_update_temp;                          
    else                                                                        
      if (lpicturemapid is null) then                                           
        select picturemapid.nextval into lpicturemapid_temp from dual;          
      else                                                                      
        lpicturemapid_temp := lpicturemapid;                                    
      end if;                                                                   
                                                                                

      insert into picturemap(picturemapid,objtype,objid,picturetypeid,metapictur
eid,sequence)                                                                   
                                                                                
      values(lpicturemapid_temp,lobjtype,lobjid,lpicturetypeid_temp,lmetapicture
id,lsequence_temp);                                                             
                                                                                
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    rollback work;                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lpicturemapid_temp);                                    
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
procedure spphysicalchannelremove                                               
(                                                                               
  lphysicalchannelid                    in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lchannelid_temp number(9);                                                    
  lcounter number(9);                                                           

  functionname varchar(40) := 'spphysicalchannelremove: ';                      
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  select count(1) into lcounter from physicalchannel where physicalchannelid = l
physicalchannelid;                                                              
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no affected row.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no affected row.');                                   

    return;                                                                     
  end if;                                                                       
                                                                                
  select channelid into lchannelid_temp from physicalchannel                    
  where physicalchannelid = lphysicalchannelid;                                 
                                                                                
  select count(1) into lcounter from channel where sourcechannelid = lchannelid_
temp and status != '9';                                                         
                                                                                
  if (lcounter > 0) then                                                        
    result := -177722;                                                          
    resultdesc := 'can not remove physicalchannel because of existing delay chan
nel.';                                                                          

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('can not remove physicalchannel because of existing del
ay channel.');                                                                  
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    delete from assetidmap                                                      
    where assettype = 'M'                                                       
    and mamid = lphysicalchannelid;                                             

                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_physicalchannel                
    and objectid=lphysicalchannelid;                                            
                                                                                
    delete from physicalchannel where physicalchannelid = lphysicalchannelid;   
                                                                                
  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     

    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       

  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
