    into lchannelid,scode,scodec,sbitratetype,sip,lport,ssourceip,lsourceport,se
ncoderip,                                                                       
                                                                                
         lfrequency,sformat,sdrmrecvip,ldrmrecvport,lpmtpid,lencoderport,schanne
lurl,                                                                           

                                                                                
         scode2,lcontentdefid,stimeshifturl,scdndomaincode,ssrccasttype         
