procedure spphysicalchannelmodify                                               
(                                                                               
  lphysicalchannelid                    in number,                              

  lchannelid                            in number,                              
  scode                                 in varchar2,                            
  sbitratetype                          in varchar2,                            
  lcontentdefid                         in number,                              
  sip                                   in varchar2,                            
  lport                                 in number,                              
  ssourceip                             in varchar2,                            
  lsourceport                           in number,                              
  sencoderip                            in varchar2,                            
  sfrequency                            in varchar2,                            
  sformat                               in varchar2,                            
  sdrmrecvip                            in varchar2,                            
  ldrmrecvport                          in number,                              

  lpmtpid                               in number,                              
  scode2                                in varchar2,                            
  lencoderport                          in number,                              
  schannelurl                           in varchar2,                            
  stimeshifturl                         in varchar2,                            
  scodec                                in varchar2,                            
  scdndomaincode			in varchar2,                                                 
  ssrccasttype                          in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               

is                                                                              
                                                                                
  lphysicalchannelid_temp number(9);                                            
  scodec_temp varchar2(2) := '1';                                               
  scdndomaincode_temp varchar2(16) := '0';                                      
  sbitratetype_temp varchar(32);                                                
  sodcflag char(1);                                                             
  sstatus char(1);                                                              
  lfrequency number(9);                                                         
  lcounter number(9);                                                           
  lpmtpid_temp number(9) := null;                                               
  functionname varchar(40) := 'spphysicalchannelmodify: ';                      
begin                                                                           

  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  if (scodec is not null ) then                                                 
     scodec_temp := scodec;                                                     
  end if;                                                                       
                                                                                
  if (scdndomaincode is not null ) then                                         
     scdndomaincode_temp := scdndomaincode;                                     
  end if;                                                                       
                                                                                
  if (lcontentdefid is not null) then                                           
    select count(1)                                                             

    into lcounter                                                               
    from contentdef                                                             
    where contentdefid = lcontentdefid;                                         
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -177730;                                                        
      resultdesc := 'contentdefid not exist in table contentdef.';              
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('contentdefid not exist in table contentdef.');      
      return;                                                                   

    end if;                                                                     
  end if;                                                                       
                                                                                
  lphysicalchannelid_temp := lphysicalchannelid;                                
                                                                                
  select count(1) into lcounter from physicalchannel where physicalchannelid = l
physicalchannelid_temp;                                                         
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no affected row.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no affected row.');                                   

    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from channel                                                                  
  where channelid = lchannelid;                                                 
  if (lcounter <= 0) then                                                       
    result := -177702;                                                          
    resultdesc := 'channelid not exist in table channel.';                      
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('channelid not exist in table channel.');              
    return;                                                                     

  end if;                                                                       
                                                                                
  select odcflag,status into sodcflag,sstatus                                   
  from channel where channelid = lchannelid;                                    
                                                                                
  if (sbitratetype is null) then                                                
    sbitratetype_temp := '2';                                                   
  else                                                                          
    sbitratetype_temp := sbitratetype;                                          
  end if;                                                                       
                                                                                
  --port judgement                                                              
  if (lport is not null and (lport < 0 or lport > 65535)) then                  

    result := -177707;                                                          
    resultdesc := 'port invalid.';                                              
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('port invalid.');                                      
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sstatus = '4' and sip is not null) then                                   
    --ip judgement.                                                             
    --spcheckip(sip, result, resultdesc);                                       
    --if (result != 0) then                                                     
     -- return;                                                                 
    --end if;                                                                   

                                                                                
    --spcheckmulticastip(sip, result, resultdesc);                              
    --if (result != 0) then                                                     
      --return;                                                                 
    --end if;                                                                   
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from physicalchannel a, channel b                                           
    where a.channelid = b.channelid                                             
    and a.ip = sip and port=lport                                               
    and a.physicalchannelid != lphysicalchannelid_temp                          
    and b.status = '4';                                                         

    if (lcounter > 0) then                                                      
      result := -177705;                                                        
      resultdesc := 'ip repeated.';                                             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ip repeated.');                                     
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sodcflag = '5' and ssourceip is null) then                                
    result := -177714;                                                          
    resultdesc := 'the sourceip of backup channel should not be empty.';        
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('the sourceip of backup channel should not be empty.');
                                                                                
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if (ssourceip is not null) then                                               
    spcheckip(ssourceip, result, resultdesc);                                   
    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                

  if (lsourceport is not null and (lsourceport < 0 or lsourceport > 65535)) then
                                                                                
                                                                                
    result := -177710;                                                          
    resultdesc := 'sourceport invalid.';                                        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('sourceport invalid.');                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sodcflag = '5' and sencoderip is not null) then                           
    result := -177713;                                                          
    resultdesc := 'the encoderip of backup channel should be empty.';           

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the encoderip of backup channel should be empty.');   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sencoderip is not null) then                                              
    spcheckip(sencoderip, result, resultdesc);                                  
    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sdrmrecvip is not null) then                                              

    spcheckip(sdrmrecvip, result, resultdesc);                                  
    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (ssourceip is not null and sdrmrecvip is not null and ssourceip = sdrmrecvi
p) then                                                                         
                                                                                
    result := -177716;                                                          
    resultdesc := 'sourceip and drmsourceip repeated.';                         
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('sourceip and drmsourceip repeated.');                 

    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from physicalchannel                                                          
  where channelid = lchannelid                                                  
  and bitratetype = sbitratetype_temp and codec=scodec_temp                     
  and physicalchannelid != lphysicalchannelid_temp;                             
  if (lcounter > 0) then                                                        
    result := -177723;                                                          
    resultdesc := 'the codec and birratetype is already existed.';              
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('the codec and birratetype is already existed.');      
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    select to_number(sfrequency) into lfrequency from dual;                     
  exception                                                                     
  when others then                                                              
    result := -177712;                                                          
    resultdesc := 'frequency invalid.';                                         
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('frequency invalid.');                                 
    return;                                                                     

  end;                                                                          
                                                                                
  if (sodcflag = '6') then                                                      
    select count(1)                                                             
    into lcounter                                                               
    from physicalchannel                                                        
    where channelid = lchannelid                                                
    and physicalchannelid != lphysicalchannelid_temp;                           
    if (lcounter > 0) then                                                      
      result := -177715;                                                        
      resultdesc := 'ppv channel should only set one bitrate for it.';          
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ppv channel should only set one bitrate for it.');  

      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  lpmtpid_temp := lpmtpid;                                                      
  if (sodcflag = 'A') then                                                      
    if (lpmtpid_temp is null or lfrequency is null) then                        
      result := -177720;                                                        
      resultdesc := 'when it is dvb channel, frequency and pmtpid can not be nul
l.';                                                                            
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when it is dvb channel, frequency and pmtpid can not

 be null.');                                                                    
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1) into lcounter from channel a,physicalchannel b where a.chann
elid=b.channelid and a.status!='9' and a.odcflag='A' and b.frequency=lfrequency 
and pmtpid=lpmtpid_temp and physicalchannelid!=lphysicalchannelid_temp;         
                                                                                
    if (lcounter > 0) then                                                      
      result := -177721;                                                        
      resultdesc := 'for dvb channel, frequency+pmtpid can not be repeated.';   
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('for dvb channel, frequency+pmtpid can not be repeate
d.');                                                                           
                                                                                
      return;                                                                   
    end if;                                                                     
  else                                                                          
    lpmtpid_temp := null;                                                       
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    update physicalchannel                                                      
    set channelid = lchannelid,                                                 

        bitratetype = sbitratetype_temp,                                        
        ip = sip,                                                               
        port = lport,                                                           
        sourceip = ssourceip,                                                   
        sourceport = lsourceport,                                               
        encoderip = sencoderip,                                                 
        frequency = lfrequency,                                                 
        format = sformat,                                                       
        drmrecvip = sdrmrecvip,                                                 
        drmrecvport = ldrmrecvport,                                             
        encoderport = lencoderport,                                             
        pmtpid = lpmtpid_temp,                                                  
        channelurl = schannelurl,                                               

        timeshifturl = stimeshifturl,                                           
        codec = scodec_temp,                                                    
        code2 = scode2,                                                         
	cdndomaincode = scdndomaincode_temp,                                           
        lastupdatetime = sysdate,                                               
        contentdefid = lcontentdefid,                                           
	srccasttype = ssrccasttype                                                     
    where physicalchannelid = lphysicalchannelid_temp;                          
                                                                                
    update globalcodemap                                                        
    set status = decode(sstatus,'9','1','0')                                    
    where objecttype=ctmsconstant_def.globaltype_physicalchannel                
    and objectid=lphysicalchannelid_temp;                                       

                                                                                
  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              

                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spphysicalchanneladd                                                  
(                                                                               
  lphysicalchannelid                    in number,                              

  lchannelid                            in number,                              
  scode                                 in varchar2,                            
  sbitratetype                          in varchar2,                            
  lcontentdefid                         in number,                              
  sip                                   in varchar2,                            
  lport                                 in number,                              
  ssourceip                             in varchar2,                            
  lsourceport                           in number,                              
  sencoderip                            in varchar2,                            
  sfrequency                            in varchar2,                            
  sformat                               in varchar2,                            
  sdrmrecvip                            in varchar2,                            
  ldrmrecvport                          in number,                              

  lpmtpid                               in number,                              
  scode2                                in varchar2,                            
  lencoderport                          in number,                              
  schannelurl                           in varchar2,                            
  stimeshifturl                         in varchar2,                            
  scodec                                in varchar2,                            
  scdndomaincode			                  in varchar2,                               
  ssrccasttype                          in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               

is                                                                              
                                                                                
  lphysicalchannelid_temp number(9);                                            
  sbitratetype_temp varchar2(32);                                               
  sodcflag char(1);                                                             
  sstatus char(1);                                                              
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  scodec_temp varchar2(2) := '1';                                               
  scdndomaincode_temp varchar2(16) := '0';                                      
  sglobalcodemapstatus char(1) := '0';                                          
  lcounter number(9);                                                           
  lfrequency number(9);                                                         

  lpmtpid_temp number(9) := null;                                               
  functionname varchar(40) := 'spphysicalchanneladd: ';                         
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  if (scodec is not null ) then                                                 
     scodec_temp := scodec;                                                     
  end if;                                                                       
                                                                                
  if (scdndomaincode is not null ) then                                         
     scdndomaincode_temp := scdndomaincode;                                     
  end if;                                                                       

                                                                                
  if (lcontentdefid is not null) then                                           
    select count(1)                                                             
    into lcounter                                                               
    from contentdef                                                             
    where contentdefid = lcontentdefid;                                         
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -177730;                                                        
      resultdesc := 'contentdefid not exist in table contentdef.';              

      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('contentdefid not exist in table contentdef.');      
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (lphysicalchannelid is null) then                                          
    spgetobjectid(ctmsconstant_def.objectid_physicalchannelid,lphysicalchannelid
_temp,result,resultdesc);                                                       
                                                                                
    if (result != 0) then                                                       
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('get objectid failed.');                             

      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      return;                                                                   
    end if;                                                                     
  else                                                                          
    lphysicalchannelid_temp := lphysicalchannelid;                              
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from channel                                                                  
  where channelid = lchannelid;                                                 

  if (lcounter <= 0) then                                                       
    result := -177702;                                                          
    resultdesc := 'channelid not exist in table channel.';                      
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('channelid not exist in table channel.');              
    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1) into lcounter from channel where sourcechannelid = lchannelid 
and status != '9';                                                              
                                                                                
  if (lcounter > 0) then                                                        
    result := -177722;                                                          

    resultdesc := 'can not add physicalchannel because of existing delay channel
.';                                                                             
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('can not add physicalchannel because of existing delay 
channel.');                                                                     
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  select odcflag,status                                                         
  into sodcflag,sstatus                                                         
  from channel                                                                  

  where channelid = lchannelid;                                                 
                                                                                
  if (sstatus = '2') then                                                       
    sglobalcodemapstatus := '1';                                                
  end if;                                                                       
                                                                                
  scode_temp := scode;                                                          
  if (scode is null) then                                                       
    spgetglobalcode(null,ctmsconstant_def.globalcode_physicalchannel,lphysicalch
annelid_temp,scode_temp,result);                                                
                                                                                
    if (result != 0) then                                                       
      if (iiscommit = 1) then rollback work; end if;                            

      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (scode2 is null) then                                                      
    scode2_temp := scode_temp;                                                  
  else                                                                          
    scode2_temp := scode2;                                                      
  end if;                                                                       
                                                                                
  if (sbitratetype is null) then                                                
    sbitratetype_temp := '2';                                                   
  else                                                                          

    sbitratetype_temp := sbitratetype;                                          
  end if;                                                                       
                                                                                
  if (lport is not null) then                                                   
    if (lport < 0 or lport > 65535) then                                        
      result := -177707;                                                        
      resultdesc := 'port invalid.';                                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('port invalid.');                                    
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                

  if (sstatus = '4' and sip is not null) then                                   
                                                                                
     -- spcheckip(sip, result, resultdesc);                                     
      --if (result != 0) then                                                   
       -- return;                                                               
     -- end if;                                                                 
                                                                                
     -- spcheckmulticastip(sip, result, resultdesc);                            
      --if (result != 0) then                                                   
       -- return;                                                               
     -- end if;                                                                 
                                                                                
                                                                                

    select count(1)                                                             
    into lcounter                                                               
    from physicalchannel a, channel b                                           
    where a.channelid = b.channelid                                             
    and a.ip = sip and port=lport                                               
    and b.status = '4';                                                         
    if (lcounter > 0) then                                                      
      result := -177705;                                                        
      resultdesc := 'ip repeated.';                                             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ip repeated.');                                     
      return;                                                                   
    end if;                                                                     

  end if;                                                                       
                                                                                
  if (sodcflag = '5' and ssourceip is null) then                                
    result := -177714;                                                          
    resultdesc := 'the sourceip of backup channel should not be empty.';        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the sourceip of backup channel should not be empty.');
                                                                                
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if (ssourceip is not null) then                                               

    spcheckip(ssourceip, result, resultdesc);                                   
    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (lsourceport is not null and (lsourceport < 0 or lsourceport > 65535)) then
                                                                                
                                                                                
    result := -177710;                                                          
    resultdesc := 'sourceport invalid.';                                        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('sourceport invalid.');                                

    return;                                                                     
  end if;                                                                       
                                                                                
  if (sodcflag = '5' and sencoderip is not null) then                           
    result := -177713;                                                          
    resultdesc := 'the encoderip of backup channel should be empty.';           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the encoderip of backup channel should be empty.');   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sencoderip is not null) then                                              
    spcheckip(sencoderip, result, resultdesc);                                  

    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sdrmrecvip is not null) then                                              
    spcheckip(sdrmrecvip, result, resultdesc);                                  
    if (result != 0) then                                                       
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (ssourceip is not null and sdrmrecvip is not null and ssourceip = sdrmrecvi

p) then                                                                         
                                                                                
    result := -177716;                                                          
    resultdesc := 'sourceip and drmsourceip repeated.';                         
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('sourceip and drmsourceip repeated.');                 
    return;                                                                     
  end if;                                                                       
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from physicalchannel                                                          
  where channelid = lchannelid                                                  

  and bitratetype = sbitratetype_temp and codec=scodec_temp;                    
  if (lcounter > 0) then                                                        
    result := -177723;                                                          
    resultdesc := 'the codec and birratetype is already existed.';              
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the codec and birratetype is already existed.');      
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    select to_number(sfrequency) into lfrequency from dual;                     
  exception                                                                     
  when others then                                                              

    result := -177712;                                                          
    resultdesc := 'frequency invalid.';                                         
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('frequency invalid.');                                 
    return;                                                                     
  end;                                                                          
                                                                                
  if (sodcflag = '6') then                                                      
    select count(1)                                                             
    into lcounter                                                               
    from physicalchannel                                                        
    where channelid = lchannelid;                                               
    if (lcounter > 0) then                                                      

      result := -177715;                                                        
      resultdesc := 'ppv channel should only set one bitrate for it.';          
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ppv channel should only set one bitrate for it.');  
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  lpmtpid_temp := lpmtpid;                                                      
  if (sodcflag = 'A') then                                                      
    if (lpmtpid_temp is null or lfrequency is null) then                        
      result := -177720;                                                        
      resultdesc := 'when it is dvb channel, frequency and pmtpid can not be nul

l.';                                                                            
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when it is dvb channel, frequency and pmtpid can not
 be null.');                                                                    
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1) into lcounter from channel a,physicalchannel b where a.chann
elid=b.channelid and a.status!='9' and a.odcflag='A' and b.frequency=lfrequency 
and pmtpid=lpmtpid_temp;                                                        
                                                                                

    if (lcounter > 0) then                                                      
      result := -177721;                                                        
      resultdesc := 'for dvb channel, frequency+pmtpid can not be repeated.';   
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('for dvb channel, frequency+pmtpid can not be repeate
d.');                                                                           
                                                                                
      return;                                                                   
    end if;                                                                     
  else                                                                          
    lpmtpid_temp := null;                                                       
  end if;                                                                       
                                                                                

  begin                                                                         
                                                                                
    insert into physicalchannel(physicalchannelid,channelid,code,codec,bitratety
pe,ip,port,                                                                     
                                                                                
                                sourceip,sourceport,encoderip,frequency,format, 
                                drmrecvip,drmrecvport,pmtpid,encoderport,channel
url,                                                                            
                                                                                
                                code2,contentdefid,timeshifturl,cdndomaincode,cr
eatestaffid,srccasttype)                                                        
                                                                                
    values(lphysicalchannelid_temp,lchannelid,scode_temp,scodec_temp,sbitratetyp

e_temp,sip,lport,                                                               
                                                                                
           ssourceip,lsourceport,sencoderip,lfrequency,sformat,                 
           sdrmrecvip,ldrmrecvport,lpmtpid_temp,lencoderport,schannelurl,       
           scode2_temp,lcontentdefid,stimeshifturl,scdndomaincode_temp,lstaffid,
ssrccasttype);                                                                  
                                                                                
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_physicalchannel,lphysicalchannel
id_temp,scode_temp,scode2_temp,sglobalcodemapstatus,null,null,null,result);     
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 

      return;                                                                   
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lphysicalchannelid_temp);                               
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure sppgmsndclass_series is                                               

  allname  VARCHAR2(256) := '';                                                 
  singlename VARCHAR2(256) := '';                                               
  sprogramattributeid number :=0;                                               
  allid       VARCHAR2(256) := '';                                              
  lcount number := 0;                                                           
  CURSOR columnhis is                                                           
       select pgmsndclass,seriesid                                              
       from series                                                              
       where pgmsndclass is not null and pgmsndclassid is  null ;               
  ccolumns columnhis%ROWTYPE;                                                   
                                                                                
                                                                                
begin                                                                           

 open columnhis;                                                                
    loop                                                                        
        fetch columnhis                                                         
        into ccolumns;                                                          
      EXIT WHEN columnhis%NOTFOUND;                                             
      begin                                                                     
         allname := regexp_replace(ccolumns.pgmsndclass,'[;||,||，|| ||/|||]',',
');                                                                             
                                                                                
             while allname is not null loop                                     
             if instr(allname,',') > 0 then                                     
                singlename := substr(allname,0,instr(allname,',')-1);           
                allname := substr(allname,instr(allname,',')+1);                

             else                                                               
                singlename:=allname;                                            
                allname:='';                                                    
            end if;                                                             
             select count(1) into lcount  from programattribute where name = sin
glename and type = '1';                                                         
                                                                                
                                                                                
            if lcount = 0 then                                                  
               select programattributeid.nextval into sprogramattributeid from d
ual;                                                                            
                                                                                
							 if(singlename is not null) then                                         

                insert into programattribute (programattributeid,name,status,cre
atetime,type) values (sprogramattributeid,singlename,'1',sysdate,'1');          
                                                                                
               end if;                                                          
						else                                                                      
