               select programattributeid.nextval into sprogramattributeid from d
ual;                                                                            

                                                                                
							 if(singlename is not null) then                                         
                insert into programattribute (programattributeid,name,status,cre
atetime,type) values (sprogramattributeid,singlename,'1',sysdate,'1');          
                                                                                
               end if;                                                          
						else                                                                      
               select programattributeid into sprogramattributeid  from programa
ttribute where name = singlename and type = '1';                                
                                                                                
                                                                                
          end if;                                                               
            if allid is null then                                               

                                                                                
              allid := sprogramattributeid;                                     
            else                                                                
              allid := allid ||','||sprogramattributeid;                        
            end if;                                                             
          end loop;                                                             
                                                                                
           update program set pgmsndclassid = allid where programid = ccolumns.p
rogramid;                                                                       
                                                                                
           allid := '';                                                         
      end;                                                                      
      commit work;                                                              

     end loop;                                                                  
 close columnhis;                                                               
end;                                                                            
