procedure spnodeobjectsrelease                                                  
(                                                                               
  ldomainid                             in number,                              
  lnodeid                               in number,                              
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              

  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  supdateflag char(1);                                                          
  lnodeobjectsid_temp number(9);                                                
  functionname varchar(40) := 'spnodeobjectsrelease: ';                         
begin                                                                           
  result := 0;                                                                  

                                                                                
  begin                                                                         
                                                                                
  supdateflag := '0';                                                           
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from nodeobjects                                                              
  where domainid = ldomainid and nodeid = lnodeid                               
  and objtype=sobjtype and objid=lobjid;                                        
  if (lcounter = 1) then                                                        
    select nodeobjectsid                                                        
    into lnodeobjectsid_temp                                                    

    from nodeobjects                                                            
    where domainid = ldomainid and nodeid = lnodeid                             
    and objtype=sobjtype and objid=lobjid;                                      
    supdateflag := '1';                                                         
  end if;                                                                       
                                                                                
  if (supdateflag = '1') then                                                   
    update nodeobjects                                                          
    set dispatchstatus = '0',lastupdatetime=sysdate where nodeobjectsid = lnodeo
bjectsid_temp;                                                                  
                                                                                
  else                                                                          
    select nodeobjectsid.nextval into lnodeobjectsid_temp from dual;            

                                                                                
    insert into nodeobjects(nodeobjectsid,domainid,nodeid,objid,objtype,dispatch
status,createstaffid)                                                           
                                                                                
    values(lnodeobjectsid_temp,ldomainid,lnodeid,lobjid,sobjtype,'0',lstaffid); 
  end if;                                                                       
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          

    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  

  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
