procedure spmetapictureremove                                                   
(                                                                               
  lmetapictureid                        in number,                              
  sautodeleteflag                       in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                

  lcounter number(9);                                                           
  functionname varchar(40) := 'spmetapictureremove: ';                          
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  select count(1) into lcounter from metapicture where metapictureid = lmetapict
ureid;                                                                          
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no affected row.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('no affected row.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
  if (sautodeleteflag = '1') then                                               
	delete from picturemap where metapictureid = lmetapictureid;                   
  else                                                                          
	select count(1) into lcounter from picturemap where metapictureid = lmetapictur
eid;                                                                            
                                                                                
	if (lcounter > 0) then                                                         

		result := -170307;                                                            
		resultdesc := 'related record exist in picturemap.';                          
		dbms_output.put_line(functionname||'result = '||result);                      
		dbms_output.put_line('related record exist in picturemap.');                  
		return;                                                                       
	end if;                                                                        
  end if;                                                                       
                                                                                
  delete from assetidmap                                                        
  where assettype = '1'                                                         
  and mamid = lmetapictureid;                                                   
                                                                                
  update globalcodemap                                                          

  set status = '1'                                                              
  where objecttype=ctmsconstant_def.globaltype_picture                          
  and objectid=lmetapictureid;                                                  
                                                                                
  delete from metapicture where metapictureid = lmetapictureid;                 
                                                                                
                                                                                
  exception                                                                     
  when others then                                                              
    rollback work;                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
