  lcounter number(9);                                                           
  functionname varchar(40) := 'spmetapicturequery: ';                           
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                

  begin                                                                         
    select count(1)                                                             
    into lcounter                                                               
    from metapicture                                                            
    where metapictureid = lmetapictureid;                                       
    if (lcounter != 1) then                                                     
      result := -170003;                                                        
      resultdesc := 'query record not found.';                                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('query record not found.');                          
