procedure spmetapicturemodify                                                   

(                                                                               
  lmetapictureid                        in number,                              
  lmetadefid                            in number,                              
  spicture                              in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
