  if (spicture is null) then                                                    
    result := -170305;                                                          
    resultdesc := 'picture is not allow empty.';                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('picture is not allow empty.');                        
    return;                                                                     
  end if;                                                                       
                                                                                
