procedure spmetapictureadd                                                      
(                                                                               
  lmetapictureid                        in number,                              
  lmetadefid                            in number,                              

  spicture                              in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  lwidth                                in number,                              
  lheight                               in number,                              
  sformat                               in varchar2,                            
  lfilesize                             in number,                              
  sdescription                          in varchar2,                            
  sverifycode                           in varchar2,                            
  sstatus                               in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          

  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  lmetapictureid_temp number(9);                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spmetapictureadd: ';                             
  lpiccounter number(9);                                                        
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  

                                                                                
  if (spicture is null) then                                                    
    result := -170305;                                                          
    resultdesc := 'picture is not allow empty.';                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('picture is not allow empty.');                        
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lmetadefid is not null) then                                              
    select count(1)                                                             
    into lcounter                                                               
    from metadef                                                                

    where metadefid = lmetadefid;                                               
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170306;                                                        
      resultdesc := 'metadefid not exist in table metadef.';                    
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('metadefid not exist in table metadef.');            
      return;                                                                   
    end if;                                                                     
  end if;                                                                       

                                                                                
  begin                                                                         
    if (lmetapictureid is null) then                                            
      select metapictureid.nextval into lmetapictureid_temp from dual;          
    else                                                                        
      lmetapictureid_temp := lmetapictureid;                                    
    end if;                                                                     
                                                                                
    select count(1) into lpiccounter from metapicture m where m.metapictureid = 
lmetapictureid_temp;                                                            
                                                                                
    if (lpiccounter <= 0) then                                                  
	    scode_temp := scode;                                                       

	    if (scode is null) then                                                    
	      spgetglobalcode(null,ctmsconstant_def.globalcode_picture,lmetapictureid_t
emp,scode_temp,result);                                                         
                                                                                
	      if (result != 0) then                                                    
		if (iiscommit = 1) then rollback work; end if;                                
		return;                                                                       
	      end if;                                                                  
	    end if;                                                                    
                                                                                
	    if (scode2 is null) then                                                   
	      scode2_temp := scode_temp;                                               
	    else                                                                       

