  functionname varchar(40) := 'spmediacontentmodify: ';                         
begin                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lcounter from mediacontent where mediacontentid = lmediac

ontentid;                                                                       
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no affect row.';                                             
