  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               

    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
