      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   
    end if;                                                                     

  end if;                                                                       
                                                                                
  if (lcontentdefid is not null) then                                           
    select count(1)                                                             
    into lcounter                                                               
    from contentdef                                                             
    where contentdefid = lcontentdefid;                                         
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
