');                                                                             
                                                                                
      return;                                                                   
    end if;                                                                     
  end if;                                                                       

                                                                                
  if (sstatus is null) then                                                     
    sstatus_temp := '4';                                                        
  else                                                                          
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                
  if (sbizdomain is  null) or (trim(sbizdomain) is null) then                   
   Select sbizdomain into sbizdomain_temp from mediacontent where mediacontentid
 = lmediacontentid;                                                             
                                                                                
      else                                                                      
        sbizdomain_temp := sbizdomain;                                          

      end if;                                                                   
                                                                                
                                                                                
  Select status into smediacontent_status from mediacontent where mediacontentid
 = lmediacontentid;                                                             
                                                                                
                                                                                
   If (smediacontent_status Is Not Null) Then                                   
     If (smediacontent_status = '2') Then                                       
       sstatus_temp := smediacontent_status;                                    
     End If;                                                                    
   End If;                                                                      
                                                                                

  if(smovieheadduration is null) then                                           
     smovieheadduration_temp := 0 ;                                             
     else                                                                       
     smovieheadduration_temp := smovieheadduration;                             
  end if;                                                                       
                                                                                
  if(smovietailduration is null) then                                           
