  end if;                                                                       
                                                                                
  If ltrim(rtrim(sDuration)) Is Not Null And                                    

     ltrim(rtrim(sDuration)) <> '0' Then                                        
     Begin                                                                      
       Select a.duration, a.programid                                           
         Into sProgramDuration, lprogramid                                      
         From Program a, ProgramMediaContent b                                  
        Where b.objtype = '1'                                                   
          And a.programid = b.objid                                             
          And b.mediacontentid = lmediacontentid;                               
     Exception                                                                  
       When Others Then                                                         
         Null;                                                                  
     End;                                                                       
                                                                                

     If ltrim(rtrim(sprogramduration)) Is Null Or                               
        (ltrim(rtrim(sprogramduration)) Is Not Null And                         
        to_number(sduration) > to_number(sprogramduration)) Then                
        Update Program                                                          
           Set duration = sDuration                                             
         Where programid = lprogramid;                                          
     End If;                                                                    
  End If;                                                                       
                                                                                
  begin                                                                         
    update globalcodemap                                                        
    set status = decode(sstatus,'2','1','8','1','9','1','0')                    
