        transcodeflag =stranscodeflag,                                          
        tcsoriginalcontentdefid = ltcsoriginalcontentdefid,                     
        tcstargetcontentdefid = ltcstargetcontentdefid,                         
        tcsoriginalfileurl =stcsoriginalfileurl,                                
        auditflag = sauditflag,                                                 
