        auditerrorinfo = sauditerrorinfo,                                       

        parsererrorcode = sparsererrorcode,                                     
        parsererrorinfo = sparsererrorinfo,                                     
        auditresult = sauditresult,                                             
        duration = sduration,                                                   
        verifycode  = sverifycode,                                              
        sourcedrmtype=ssourcedrmtype,                                           
        destdrmtype=sdestdrmtype,                                               
        moviefiletype=smoviefiletype,                                           
        filesize = lfilesize,                                                   
        movieheadduration=smovieheadduration_temp,                              
        movietailduration=smovietailduration_temp,                              
        videoprofile = svideoprofile,                                           
        systemlayer = ssystemlayer,                                             

        bizdomain = sbizdomain_temp,                                            
        nasserverid = lnasserverid                                              
    where mediacontentid = lmediacontentid;                                     
                                                                                
      begin                                                                     
                                                                                
      Select b.objtype,a.programid                                              
          Into sobjecttype_temp,lobjectid                                       
          From Program a, ProgramMediaContent b                                 
          Where b.objtype = '1'                                                 
            And a.programid = b.objid                                           
            And b.mediacontentid = lmediacontentid;                             
                                                                                

    if (sobjecttype_temp = '1') then                                            
      spSynProgramBitRate(sobjecttype_temp,lobjectid,lstaffid,0,result,resultdes
c);                                                                             
                                                                                
    end if ;                                                                    
         Exception                                                              
