procedure spiptvproductquery                                                    
(                                                                               
  liptvproductid                        in out number,                          
  ldomainid                             in out number,                          
  sname                                 in out varchar2,                        
  scode                                 in out varchar2,                        
  scode2                                in out varchar2,                        
  sordercode                            in out varchar2,                        
  sstatus                               in out varchar2,                        
  sbillingmethod                        in out varchar2,                        
  fmonthrent                            in out number,                          
  susageunit                            in out varchar2,                        
  spricefrom                            in out varchar2,                        

  funitrate                             in out number,                          
  lrentperiod                           in out number,                          
  dvalidthrough                         in out varchar2,                        
  dvaliduntil                           in out varchar2,                        
  sdescription                          in out varchar2,                        
  spublicflag                           in out varchar2,                        
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
  lcounter number(9);                                                           
  functionname varchar(40) := 'spiptvproductquery: ';                           
begin                                                                           

  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  begin                                                                         
    select count(1)                                                             
    into lcounter                                                               
    from iptvproduct                                                            
    where iptvproductid = liptvproductid;                                       
    if (lcounter != 1) then                                                     
      result := -170003;                                                        
      resultdesc := 'query record not found.';                                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('query record not found.');                          

      return;                                                                   
    end if;                                                                     
                                                                                
    select domainid,name,code,code2,ordercode,status,                           
           billingmethod,monthrent,usageunit,pricefrom,unitrate,rentperiod,     
           to_char(validthrough,'yyyymmddhh24miss'),                            
           to_char(validuntil,'yyyymmddhh24miss'),description,publicflag        
    into ldomainid,sname,scode,scode2,sordercode,sstatus,                       
           sbillingmethod,fmonthrent,susageunit,spricefrom,funitrate,lrentperiod
,                                                                               
                                                                                
           dvalidthrough,dvaliduntil,sdescription,spublicflag                   
    from iptvproduct                                                            

    where iptvproductid = liptvproductid;                                       
  exception                                                                     
  when others then                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          

  result := 0;                                                                  
  resultdesc := to_char(liptvproductid);                                        
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
