procedure spiptvproductmodify                                                   
(                                                                               
  liptvproductid                        in number,                              
  ldomainid                             in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sordercode                            in varchar2,                            
  sstatus                               in varchar2,                            
  sbillingmethod                        in varchar2,                            
  fmonthrent                            in number,                              

  susageunit                            in varchar2,                            
  spricefrom                            in varchar2,                            
  funitrate                             in number,                              
  lrentperiod                           in number,                              
  dvalidthrough                         in varchar2,                            
  dvaliduntil                           in varchar2,                            
  sdescription                          in varchar2,                            
  spublicflag                           in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               

is                                                                              
  lcounter number(9);                                                           
  functionname varchar(40) := 'spiptvproductmodify: ';                          
  ltransactionid  number;                                                       
                                                                                
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  select count(1) into lcounter from iptvproduct where iptvproductid = liptvprod
uctid;                                                                          
                                                                                
  if (lcounter != 1) then                                                       

    result := -170003;                                                          
    resultdesc := 'query record not found.';                                    
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no affected row.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sname is null) then                                                       
  	result := -179603;                                                           
    resultdesc := 'name cannot be null';                                        
    return;                                                                     
  end if;                                                                       
                                                                                

  select count(1) into lcounter from iptvproduct                                
  where domainid = ldomainid and ordercode = sordercode and iptvproductid != lip
tvproductid;                                                                    
                                                                                
  if (lcounter > 0) then                                                        
    result := -179604;                                                          
    resultdesc := 'OrderCode Is Duplicate.';                                    
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('OrderCode Is Duplicate.');                            
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         

    update iptvproduct                                                          
    set domainid = ldomainid,                                                   
        name = sname,                                                           
        code2 = scode2,                                                         
        ordercode = sordercode,                                                 
        status = sstatus,                                                       
        billingmethod = sbillingmethod,                                         
        monthrent = fmonthrent,                                                 
        usageunit = susageunit,                                                 
        pricefrom = spricefrom,                                                 
        unitrate = funitrate,                                                   
        rentperiod = lrentperiod,                                               
        validthrough = to_date(dvalidthrough,'yyyymmddhh24miss'),               

        validuntil = to_date(dvaliduntil,'yyyymmddhh24miss'),                   
        description = sdescription,                                             
        publicflag = spublicflag,                                               
        lastupdatetime = sysdate                                                
    where iptvproductid = liptvproductid;                                       
                                                                                
  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler

rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  

  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
