    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr

( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := to_char(lhtmlcontentid);                                        
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure sphtmlcontentmodify                                                   
(                                                                               
  lhtmlcontentid                        in number,                              
  lvspid                                in number,                              

  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sfileurl                              in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  sstatus_temp varchar2(1);                                                     

  functionname varchar(40) := 'sphtmlcontentmodify: ';                          
begin                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lcounter from htmlcontent where htmlcontentid = lhtmlcont
entid;                                                                          
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no affect row.';                                             
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no affect row.');                                     
    return;                                                                     

  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               
    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170108;                                                        

      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    update htmlcontent                                                          
    set vspid = lvspid,                                                         
        name = sname,                                                           
        code2 = scode2,                                                         
        fileurl = sfileurl,                                                     

        lastupdatetime = sysdate                                                
    where htmlcontentid = lhtmlcontentid;                                       
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if (iiscommit = 1) then                                                       
    commit work;                                                                
  end if;                                                                       
  result :=0;                                                                   
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure sphtmlcontentadd                                                      

(                                                                               
  lhtmlcontentid                        in number,                              
  lvspid                                in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sfileurl                              in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              

                                                                                
  lcounter number(9);                                                           
  lhtmlcontentid_temp number(9);                                                
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sglobalcodemapstatus char(1) := '0';                                          
  functionname varchar(40) := 'sphtmlcontentadd: ';                             
begin                                                                           
  result :=0;                                                                   
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               

    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   
    end if;                                                                     

  end if;                                                                       
                                                                                
  begin                                                                         
    if (lhtmlcontentid is null) then                                            
      select htmlcontentid.nextval into lhtmlcontentid_temp from dual;          
    else                                                                        
      lhtmlcontentid_temp := lhtmlcontentid;                                    
    end if;                                                                     
                                                                                
    scode_temp := scode;                                                        
    if (scode is null) then                                                     
      spgetglobalcode(lvspid,ctmsconstant_def.globalcode_htmlcontent,lhtmlconten
tid_temp,scode_temp,result);                                                    

                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                
    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                

    spaddglobalcode(ctmsconstant_def.globaltype_htmlcontent,lhtmlcontentid_temp,
scode_temp,scode2_temp,sglobalcodemapstatus,null,null,null,result);             
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
    insert into htmlcontent(htmlcontentid,name,code,code2,vspid,fileurl,createst
affid)                                                                          
                                                                                
    values(lhtmlcontentid_temp,sname,scode_temp,scode2_temp,lvspid,sfileurl,lsta
ffid);                                                                          

                                                                                
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr

( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if (iiscommit = 1) then                                                       
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lhtmlcontentid_temp);                                   
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spgetprogramcopyright                                                 
(                                                                               

        sobjtype                                in varchar2,                    
	lobjid                                  in number,                             
	dcopyrightexpirationtime                in out date,                           
	result                                  in out number,                         
	resultdesc                              in out varchar                         
)                                                                               
is                                                                              
       lcopyrightid number(9);                                                  
       --denddate date;                                                         
       maxdate date;                                                            
       mindate date;                                                            
       flag Number(9);                                                          
       dcopyrightexpirationtime_temp date;                                      

       functionname varchar(40) := 'spscheduleadd: ';                           
       cursor c_get_copyright is                                                
       select copyrightid from copyrightmap                                     
       where objtype = sobjtype and objid = lobjid;                             
begin                                                                           
       result := 0;                                                             
                                                                                
        begin                                                                   
       if(sobjtype = '1') then                                                  
         select copyrightexpirationtime into dcopyrightexpirationtime_temp from 
program where programid = lobjid;                                               
                                                                                
       end if;                                                                  

                                                                                
       if(sobjtype = '2') then                                                  
	        select copyrightexpirationtime into dcopyrightexpirationtime_temp From 
series where seriesid = lobjid;                                                 
                                                                                
       end if;                                                                  
                                                                                
       if(dcopyrightexpirationtime_temp is null) then                           
           result := 0;                                                         
	         resultdesc := 'the row no copyright.';                                
	         dbms_output.put_line(functionname||'result = '||result);              
	         dbms_output.put_line('the row no copyright.');                        
	         return;                                                               

       end if;                                                                  
                                                                                
       maxdate := dcopyrightexpirationtime_temp;                                
      flag := 1;                                                                
       open c_get_copyright;                                                    
       loop                                                                     
          begin                                                                 
             fetch c_get_copyright into lcopyrightid;                           
	     exit when c_get_copyright%notfound;                                       
                                                                                
             if(lcopyrightid is null) then                                      
                result := 0;                                                    
	        resultdesc := 'the row no copyright.';                                 

	        dbms_output.put_line(functionname||'result = '||result);               
	        dbms_output.put_line('the row no copyright.');                         
	        return;                                                                
             end if;                                                            
            If(flag = 1) Then                                                   
             select enddate into maxdate from copyright where copyrightid = lcop
yrightid;                                                                       
                                                                                
            Else                                                                
             select enddate into mindate from copyright where copyrightid = lcop
yrightid;                                                                       
                                                                                
           End If;                                                              

           flag := flag + 1;                                                    
                                                                                
	     if(maxdate < mindate) then                                                
	        maxdate := mindate;                                                    
	     end if;                                                                   
                                                                                
             dcopyrightexpirationtime := maxdate;                               
                                                                                
          exception                                                             
          when others then                                                      
             close c_get_copyright;                                             
             result := -500003;                                                 
             resultdesc := 'oracle error code:'||sqlcode||'error message:'||subs

tr( sqlerrm,1,100);                                                             
                                                                                
             dbms_output.put_line(functionname||'result = '||result);           
             dbms_output.put_line('oracle error code:'||sqlcode||'error message:
'||substr( sqlerrm,1,100));                                                     
                                                                                
             return;                                                            
         end;                                                                   
         end loop;                                                              
         close c_get_copyright;                                                 
     exception                                                                  
     when others then                                                           
	 result := -500003;                                                            

	 resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqlerrm
,1,100);                                                                        
                                                                                
	 dbms_output.put_line(functionname||'result = '||result);                      
	 dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr( 
sqlerrm,1,100));                                                                
                                                                                
	 return;                                                                       
     end;                                                                       
                                                                                
     result := 0;                                                               
     resultdesc := to_char(dcopyrightexpirationtime);                           
     dbms_output.put_line(functionname||'result = '||result);                   

end;                                                                            
procedure spgetoneobjectid                                                      
(                                                                               
  ctype                                 in char,                                
  lobjectid                             in out number,   -- if result=0, then it
 means the id                                                                   
                                                                                
  result                                in out number,   -- 0: success, else: fa
lse                                                                             
                                                                                
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              

                                                                                
  ltempobjectid   number(9) := 0;                                               
  functionname varchar(40) := 'spgetoneobjectid: ';                             
begin                                                                           
  result :=0;                                                                   
                                                                                
  begin                                                                         
    if ctype ='0'  then                                                         
        select programid.nextval into ltempobjectid from dual;                  
    elsif ctype ='1' then                                                       
        select channelid.nextval into ltempobjectid from dual;                  
    elsif ctype ='2' then                                                       
        select bundledcontentid.nextval into ltempobjectid from dual;           

    elsif ctype ='3' then                                                       
        select mediacontentid.nextval into ltempobjectid from dual;             
    elsif ctype ='4' then                                                       
        select seriesid.nextval into ltempobjectid from dual;                   
    elsif ctype ='9' then                                                       
        select physicalchannelid.nextval into ltempobjectid from dual;          
    else                                                                        
        result := -170006;                                                      
        resultdesc := 'get objectid fail. type:' || ctype;                      
        dbms_output.put_line(functionname||'result = '||result);                
        return;                                                                 
    end if;                                                                     
  exception                                                                     

  when others then                                                              
    result := -170004;                                                          
    resultdesc := 'get objectid fail. type:' || ctype;                          
    dbms_output.put_line(functionname||'result = '||result);                    
    return;                                                                     
  end;                                                                          
                                                                                
end;                                                                            
procedure spgetobjectid                                                         
(                                                                               
  ctype                                 in char,                                
  lobjectid                             in out number,   -- if result=0, then it
 means the id                                                                   

                                                                                
  result                                in out number,   -- 0: success, else: fa
lse                                                                             
                                                                                
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  functionname varchar(40) := 'spgetobjectid: ';                                
  icount       number;                                                          
  iloopcount   number(9);                                                       
begin                                                                           
  result :=0;                                                                   

                                                                                
  icount := 1;                                                                  
  iloopcount := 0;                                                              
  begin                                                                         
    loop                                                                        
    exit when icount=0 or iloopcount>1000000;                                   
                                                                                
      --get one id                                                              
      spgetoneobjectid(ctype,lobjectid,result,resultdesc);                      
      if result != 0 then                                                       
         return;                                                                
      end if;                                                                   
                                                                                

      --check id,id id has been used,get the next id                            
      if (ctype in ('0')) then                                                  
        select count(1) into icount from program where programid=lobjectid;     
      elsif (ctype in ('1')) then                                               
        select count(1) into icount from channel where channelid=lobjectid;     
      elsif (ctype in ('2')) then                                               
        select count(1) into icount from bundledcontent where bundledcontentid=l
objectid;                                                                       
                                                                                
      elsif (ctype in ('3')) then                                               
        select count(1) into icount from mediacontent where mediacontentid=lobje
ctid;                                                                           
                                                                                

      elsif (ctype in ('4')) then                                               
        select count(1) into icount from series where seriesid=lobjectid;       
      elsif (ctype in ('9')) then                                               
        select count(1) into icount from physicalchannel where physicalchannelid
=lobjectid;                                                                     
                                                                                
      else                                                                      
        icount := 0;                                                            
      end if;                                                                   
                                                                                
      iloopcount := iloopcount + 1;                                             
    end loop;                                                                   
  end;                                                                          

                                                                                
  dbms_output.put_line('id:' || lobjectid);                                     
end;                                                                            
procedure spgetglobalcode                                                       
(                                                                               
  lvspid                                in number,                              
  sobjecttype                           in varchar2,--1: vod                    
                                                    --2: movie                  
                                                    --3: channel                
                                                    --4: schedule               
                                                    --5: bundledcontent         
                                                    --7: physicalchannel        
                                                    --8: category               

                                                    --11: series                
                                                    --13: picture               
  lobjectid                             in number,                              
  sglobalcode                           in out varchar2,                        
  result                                in out number                           
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lcodelength number(6);                                                        
  sbody varchar2(40);                                                           
  sprefix varchar2(150);                                                        
  sbodytype char(1);                                                            

  sbodyformat char(1);                                                          
  lbodylength number(3);                                                        
  ssuffix varchar2(150);                                                        
  functionname varchar(40) := 'spgetglobalcode: ';                              
begin                                                                           
  sbody := '';                                                                  
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from globalcodedef                                                            
  where ownertype = '0'                                                         
  and objecttype = sobjecttype;                                                 
                                                                                

  if (lcounter = 1) then                                                        
    begin                                                                       
      select prefix,bodytype,bodyformat,bodylength,suffix                       
      into sprefix,sbodytype,sbodyformat,lbodylength,ssuffix                    
      from globalcodedef                                                        
      where ownertype = '0'                                                     
      and objecttype = sobjecttype;                                             
                                                                                
      sbody := to_char(lobjectid);                                              
      if (sbodyformat = '2') then                                               
        sbody := lpad(sbody,lbodylength,'0');                                   
      end if;                                                                   
      lcodelength := length(sprefix||sbody||ssuffix);                           

      if (lcodelength > 128) then                                               
        result := -170011;                                                      
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('value larger than specified precision allows for t
he global code.');                                                              
                                                                                
        return;                                                                 
      end if;                                                                   
                                                                                
    exception                                                                   
    when others then                                                            
      result := -170012;                                                        
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('global code rule not found.');                      
      return;                                                                   
    end;                                                                        
                                                                                
    sglobalcode := sprefix||sbody||ssuffix;                                     
    result := 0;                                                                
    return;                                                                     
  else                                                                          
    result := -170013;                                                          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('global code rule not found or found many records.');  
    return;                                                                     
  end if;                                                                       

                                                                                
end;                                                                            
procedure spdomainobjectsupdatestatus                                           
(                                                                               
  ldomainobjectsid                      in number,                              
  ldomainid                             in number,                              
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              
  sstatus                               in varchar2,                            
  spromotionlevel                       in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          

  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  ldomainobjectsid_temp number(9);                                              
  spromotionlevel_temp varchar(1);                                              
  functionname varchar(40) := 'spdomainobjectsupdatestatus: ';                  
                                                                                
begin                                                                           
  result := 0;                                                                  
                                                                                
  begin                                                                         

    if (sstatus is null or sstatus not in ('0','1')) then                       
      result := -174005;                                                        
      resultdesc := 'status is empty or not in (''0'',''1'').';                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('status is empty or not in (''0'',''1'').');         
      return;                                                                   
    end if;                                                                     
                                                                                
    if (ldomainobjectsid is null) then                                          
      select domainobjectsid into ldomainobjectsid_temp from domainobjects      
      where domainid=ldomainid and objtype=sobjtype and objid=lobjid;           
    else                                                                        
      ldomainobjectsid_temp := ldomainobjectsid;                                

    end if;                                                                     
                                                                                
    if (spromotionlevel is null) then                                           
      select promotionlevel into spromotionlevel_temp from domainobjects        
      where domainobjectsid=ldomainobjectsid_temp;                              
    else                                                                        
      spromotionlevel_temp := spromotionlevel;                                  
    end if;                                                                     
                                                                                
                                                                                
    update domainobjects                                                        
    set status = sstatus,lastupdatetime=sysdate,promotionlevel=spromotionlevel_t
emp                                                                             

                                                                                
    where domainobjectsid = ldomainobjectsid_temp;                              
    if (sobjtype = '1') then                                                    
       begin                                                                    
       insert into publishlog (publishlogid,domainid,domainname,categoryid,categ
oryname,objtype,objid,objname,status,duration)                                  
                                                                                
                select  publishlogid.nextval,d.domainid,d.name,c.categoryid,c.na
me,obj.objtype,obj.objid,p.name,sstatus,to_number(nvl(p.duration,0))            
                                                                                
         from   domainobjects obj,program p ,categorydtl cdtl ,category c,domain
 d                                                                              
                                                                                

         where  p.programid = obj.objid                                         
               and obj.objid =  lobjid                                          
               and obj.objtype = 1                                              
               and obj.domainid  = ldomainid                                    
               and d.domainid = obj.domainid                                    
               and c.domainid = obj.domainid                                    
               and c.categoryid = cdtl.categoryid                               
               and cdtl.objtype = '8'                                           
               and cdtl.objid = obj.objid   ;                                   
       end;                                                                     
    end if;                                                                     
   if (sobjtype = '35') then                                                    
       begin                                                                    

       insert into publishlog (publishlogid,domainid,domainname,categoryid,categ
oryname,objtype,objid,objname,status,duration)                                  
                                                                                
               select  publishlogid.nextval,d.domainid,d.name,c.categoryid,c.nam
e,obj.objtype,obj.objid,s.name,sstatus,to_number(nvl(temp.totaltime,0))         
                                                                                
         from   domainobjects obj,series s,categorydtl cdtl ,category c,domain d
,( select t.seriesid seriesid,sum(p.duration) totaltime from program p,(select p
rogramid,seriesid from seriesdtl where seriesid=(                               
                                                                                
               select s.seriesid from series s,domainobjects obj where          
               obj.objid =  lobjid                                              
               and obj.objtype = 35                                             

               and obj.domainid  = ldomainid                                    
               and obj.objid= s.seriesid )) t where p.programid in (t.programid)
 group by t.seriesid) temp                                                      
                                                                                
where                                                                           
     obj.objid =  lobjid                                                        
     and obj.objtype = 35                                                       
     and obj.domainid  = ldomainid                                              
     and cdtl.objtype = '1'                                                     
     and temp.seriesid=s.seriesid                                               
     and obj.objid= s.seriesid                                                  
     and obj.domainid=d.domainid                                                
     and obj.objid=cdtl.objid                                                   

     and s.seriesid=cdtl.objid                                                  
     and cdtl.categoryid=c.categoryid                                           
     and c.domainid=d.domainid;                                                 
       end;                                                                     
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      

end;                                                                            
PROCEDURE "SPDOMAINOBJECTSRELEASE"                                              
(                                                                               
  ldomainobjectsid                      IN number,                              
  ldomainid                             IN number,                              
  lnodeid                               IN number,                              
  sobjtype                              IN varchar2,                            
  sstatus                               IN varchar2,                            
  lobjid                                IN number,                              
  lstaffid                              IN number,                              
  iiscommit                             IN number,                              
  result                                IN OUT number,                          
  resultdesc                            IN OUT varchar2                         

)                                                                               
IS                                                                              
                                                                                
  lcounter number(9);                                                           
  supdateflag CHAR(1);                                                          
  sstatus_temp CHAR(1);                                                         
  ldomainobjectsid_temp number(9);                                              
  ldomainid_temp number(9);                                                     
  lnodeid_temp number(9);                                                       
  functionname VARCHAR(40) := 'spdomainobjectsrelease: ';                       
  dcount number(9);                                                             
                                                                                
  CURSOR c_childnode IS                                                         

  SELECT DISTINCT domainid,underctmsnodeid FROM                                 
  (SELECT domainid,underctmsnodeid FROM underctmsnode WHERE domainid = ldomainid
 AND STATUS <> '0'                                                              
                                                                                
  UNION ALL SELECT domainid,underctmsnodeid FROM underctmsnode WHERE domainid IN
                                                                                
                                                                                
  (SELECT domainid FROM domain WHERE parentid=ldomainid) AND STATUS <> '0');    
BEGIN                                                                           
  result := 0;                                                                  
                                                                                
  BEGIN                                                                         
                                                                                

  SELECT COUNT(1)                                                               
  INTO lcounter                                                                 
  FROM domain                                                                   
  WHERE domainid = ldomainid;                                                   
  IF (lcounter <= 0) THEN                                                       
    result := -174020;                                                          
    resultdesc := 'domainid not exist.';                                        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('domainid not exist.');                                
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  IF (lobjid IS NULL) THEN                                                      

    result := -174102;                                                          
    resultdesc := 'objid is not allow empty.';                                  
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('objid is not allow empty.');                          
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  IF (sobjtype IS NULL) THEN                                                    
    result := -174103;                                                          
    resultdesc := 'type is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('type is not allow empty.');                           
    RETURN;                                                                     

  END IF;                                                                       
                                                                                
  IF  (sobjtype = '35') THEN                                                    
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM series                                                                 
    WHERE seriesid = lobjid AND STATUS<>'9';                                    
    IF (lcounter <= 0) THEN                                                     
      result := -174110;                                                        
      resultdesc := 'objid not exist in table series.';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      RETURN;                                                                   

    END IF;                                                                     
                                                                                
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM series                                                                 
    WHERE seriesid = lobjid AND STATUS<>'4';                                    
    IF (lcounter > 0) THEN                                                      
      result := 0;                                                              
      resultdesc := 'stuts not is audit succ.';                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
  elsif (sobjtype = '1') THEN                                                   

    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM program                                                                
    WHERE programid = lobjid AND STATUS<>'9';                                   
    IF (lcounter <= 0) THEN                                                     
      result := -174108;                                                        
      resultdesc := 'objid not exist in table program.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('lobjid not exist in table program.');               
      RETURN;                                                                   
    END IF;                                                                     
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               

    FROM program                                                                
    WHERE programid = lobjid AND STATUS<>'4';                                   
    IF (lcounter > 0) THEN                                                      
      result := 0;                                                              
      resultdesc := 'stuts not is audit succ.';                                 
      RETURN;                                                                   
    END IF;                                                                     
  elsif (sobjtype = '12') THEN                                                  
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM channel                                                                
    WHERE channelid = lobjid AND STATUS<>'9';                                   
    IF (lcounter <= 0) THEN                                                     

      result := -174112;                                                        
      resultdesc := 'objid not exist in table channel.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table channel.');                
      RETURN;                                                                   
    END IF;                                                                     
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM channel                                                                
    WHERE channelid = lobjid AND STATUS<>'4';                                   
    IF (lcounter > 0) THEN                                                      
      result := 0;                                                              
      resultdesc := 'stuts not is audit succ.';                                 

      RETURN;                                                                   
    END IF;                                                                     
  elsif (sobjtype = '25') THEN                                                  
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM metapicture                                                            
    WHERE metapictureid = lobjid AND (STATUS IS NULL OR STATUS ='1') ;          
    IF(lcounter <= 0) THEN                                                      
      result := -174113;                                                        
      resultdesc := 'objid not exist in table metapicture.';                    
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('objid not exist in table metapicture.');          
        RETURN;                                                                 

    END IF;                                                                     
  elsif (sobjtype = '2') THEN                                                   
    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM mediacontent                                                           
    WHERE mediacontentid = lobjid AND STATUS <>'2';                             
    IF(lcounter <= 0) THEN                                                      
      result := -174114;                                                        
      resultdesc := 'objid not exist in table mediacontent.';                   
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('objid not exist in table mediacontent.');         
        RETURN;                                                                 
    END IF;                                                                     

    SELECT COUNT(1)                                                             
    INTO lcounter                                                               
    FROM mediacontent                                                           
    WHERE mediacontentid = lobjid AND STATUS <>'4';                             
    IF(lcounter > 0) THEN                                                       
      result := 0;                                                              
      resultdesc := 'status not is active.';                                    
        RETURN;                                                                 
    END IF;                                                                     
  elsif (sobjtype = '13') THEN                                                  
     SELECT COUNT(1)                                                            
     INTO lcounter                                                              
     FROM cast                                                                  

     WHERE castid = lobjid AND STATUS <>'9';                                    
     IF(lcounter <= 0) THEN                                                     
        result := -174115;                                                      
        resultdesc := 'objid not exist in table cast.';                         
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('objid not exist in table mediacontent.');         
        RETURN;                                                                 
     END IF;                                                                    
     SELECT COUNT(1)                                                            
     INTO lcounter                                                              
     FROM cast                                                                  
     WHERE castid = lobjid AND STATUS <>'1';                                    
     IF(lcounter > 0) THEN                                                      

       result := 0;                                                             
       resultdesc := 'status not is audit succ.';                               
         RETURN;                                                                
     END IF;                                                                    
   END IF;                                                                      
                                                                                
                                                                                
                                                                                
  --insert OR UPDATE domainobjects                                              
                                                                                
  supdateflag := '0';                                                           
                                                                                
  SELECT COUNT(1)                                                               

  INTO lcounter                                                                 
  FROM domainobjects                                                            
  WHERE domainid = ldomainid                                                    
  AND objid = lobjid                                                            
  AND objtype = sobjtype;                                                       
  IF (lcounter = 1) THEN                                                        
    SELECT domainobjectsid                                                      
    INTO ldomainobjectsid_temp                                                  
    FROM domainobjects                                                          
    WHERE domainid = ldomainid                                                  
    AND objid = lobjid                                                          
    AND objtype = sobjtype;                                                     
    supdateflag := '1';                                                         

  END IF;                                                                       
                                                                                
    SELECT VALUE INTO sstatus_temp FROM moduleconfig WHERE moduleid=320 AND sequ
ence=101;                                                                       
                                                                                
    IF (sstatus IS NOT NULL) THEN                                               
     sstatus_temp := sstatus;                                                   
    END IF;                                                                     
                                                                                
   IF (supdateflag = '1') THEN                                                  
     IF (sstatus IS NULL) THEN                                                  
      UPDATE domainobjects SET dispatchstatus = '1',createdate=SYSDATE WHERE dom
ainobjectsid = ldomainobjectsid_temp;                                           

                                                                                
     ELSE                                                                       
        UPDATE domainobjects SET dispatchstatus = '1',STATUS=sstatus,createdate=
SYSDATE WHERE domainobjectsid = ldomainobjectsid_temp;                          
                                                                                
     END IF;                                                                    
  ELSE                                                                          
    IF (ldomainobjectsid IS NULL) THEN                                          
      SELECT domainobjectsid.nextval INTO ldomainobjectsid_temp FROM DUAL;      
    ELSE                                                                        
      ldomainobjectsid_temp := ldomainobjectsid;                                
    END IF;                                                                     
    select count(*) into dcount from domainobjects where objid=lobjid and objtyp

e = sobjtype;                                                                   
                                                                                
    INSERT INTO domainobjects(domainobjectsid,domainid,objid,objtype,STATUS,disp
atchstatus,createstaffid,lastupdatetime)VALUES(ldomainobjectsid_temp,ldomainid,l
objid,sobjtype,sstatus_temp,'1',lstaffid,sysdate);                              
                                                                                
  END IF;                                                                       
                                                                                
  --insert OR UPDATE nodeobjects                                                
                                                                                
  IF (lnodeid IS NOT NULL) THEN                                                 
    spnodeobjectsrelease(ldomainid,lnodeid,sobjtype,lobjid,lstaffid,iiscommit,re
sult,resultdesc);                                                               

                                                                                
    IF (result != 0) THEN                                                       
      IF (iiscommit = 1) THEN                                                   
        ROLLBACK WORK;                                                          
      END IF;                                                                   
      RETURN;                                                                   
    END IF;                                                                     
  ELSE                                                                          
    OPEN c_childnode;                                                           
    LOOP                                                                        
      BEGIN                                                                     
        FETCH c_childnode INTO ldomainid_temp,lnodeid_temp;                     
        EXIT WHEN c_childnode%notfound;                                         

        spnodeobjectsrelease(ldomainid,lnodeid_temp,sobjtype,lobjid,lstaffid,iis
commit,result,resultdesc);                                                      
                                                                                
        IF (result != 0) THEN                                                   
          CLOSE c_childnode;                                                    
          IF (iiscommit = 1) THEN                                               
            ROLLBACK WORK;                                                      
          END IF;                                                               
          RETURN;                                                               
        END IF;                                                                 
      exception                                                                 
      WHEN others THEN                                                          
        CLOSE c_childnode;                                                      

        IF (iiscommit = 1) THEN                                                 
          ROLLBACK WORK;                                                        
        END IF;                                                                 
        result := -170001;                                                      
        resultdesc := 'oracle error code:'||sqlcode||'error message:'||SUBSTR( s
qlerrm,1,100);                                                                  
                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||SU
BSTR( sqlerrm,1,100));                                                          
                                                                                
        RETURN;                                                                 
      END;                                                                      

    END LOOP;                                                                   
    CLOSE c_childnode;                                                          
  END IF;                                                                       
                                                                                
  --update stockoutflag                                                         
                                                                                
  IF  (sobjtype = '35') THEN                                                    
    UPDATE series SET stockoutflag='1' WHERE seriesid = lobjid;                 
    update series set releaseTime =SysDate where seriesid = lobjid;             
  elsif (sobjtype = '1') THEN                                                   
    UPDATE program SET stockoutflag='1' WHERE programid = lobjid;               
    UPDATE seriesdtl SET stockoutflag='1' WHERE programid = lobjid;             
    update program set releaseTime =SysDate where programid = lobjid;           

  elsif (sobjtype = '12') THEN                                                  
    UPDATE channel SET stockoutflag='1' WHERE channelid = lobjid;               
    update channel set releaseTime=Sysdate where channelid=lobjid;              
  elsif (sobjtype = '25') THEN                                                  
    SELECT COUNT(1)INTO lcounter FROM metapicture WHERE metapictureid=lobjid;   
  elsif (sobjtype = '2') THEN                                                   
    SELECT COUNT(1)INTO lcounter FROM mediacontent WHERE mediacontentid=lobjid; 
  elsif (sobjtype = '13') THEN                                                  
    UPDATE cast SET stockoutflag='1' WHERE castid = lobjid;                     
  END IF;                                                                       
                                                                                
  exception                                                                     
  WHEN others THEN                                                              

    IF (iiscommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||SUBSTR( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||SUBSTR
( sqlerrm,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          

  IF iiscommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
END;                                                                            
procedure spdomainobjectsreclaim                                                
(                                                                               
  ldomainobjectsid                      in number,                              
  ldomainid                             in number,                              
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              

  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  ldomainobjectsid_temp number(9);                                              
  ldomainid_temp number(9);                                                     
  lnodeid_temp number(9);                                                       
  sobjtype_temp varchar(2);                                                     
  lobjid_temp number(9);                                                        

  lcontentserviceid_temp number(9);                                             
  lstockoutflag_temp varchar(1);                                                
  functionname varchar(40) := 'spdomainobjectsreclaim: ';                       
                                                                                
  cursor c_childnode is                                                         
  select distinct domainid,underctmsnodeid from                                 
  (select domainid,underctmsnodeid from underctmsnode where domainid = ldomainid
 and status <> '0'                                                              
                                                                                
  union all select domainid,underctmsnodeid from underctmsnode where domainid in
                                                                                
                                                                                
  (select domainid from domain where parentid=ldomainid) and status <> '0');    

                                                                                
  --cursor c_get_contentservice is                                              
  --select contentserviceid from contentservice                                 
  --where objtype=decode(sobjtype,'35','4','1','3','12','1','-1') and objid=lobj
id;                                                                             
                                                                                
                                                                                
begin                                                                           
  result := 0;                                                                  
                                                                                
  begin                                                                         
                                                                                
  --delete domainobjects                                                        

                                                                                
  if (ldomainobjectsid is null) then                                            
    select count(1)                                                             
    into lcounter                                                               
    from domainobjects                                                          
    where domainid = ldomainid                                                  
    and objid = lobjid                                                          
    and objtype = sobjtype;                                                     
    if (lcounter = 1) then                                                      
      select domainobjectsid,objtype,objid                                      
      into ldomainobjectsid_temp,sobjtype_temp,lobjid_temp                      
      from domainobjects                                                        
      where domainid = ldomainid                                                

      and objid = lobjid                                                        
      and objtype = sobjtype;                                                   
    else                                                                        
      result := 0;                                                              
      resultdesc := 'no records.';                                              
      return;                                                                   
    end if;                                                                     
  else                                                                          
    ldomainobjectsid_temp := ldomainobjectsid;                                  
    select count(1)                                                             
    into lcounter                                                               
    from domainobjects                                                          
    where domainobjectsid = ldomainobjectsid_temp;                              

    if (lcounter = 1) then                                                      
      select objtype,objid                                                      
      into sobjtype_temp,lobjid_temp                                            
      from domainobjects                                                        
      where domainobjectsid = ldomainobjectsid_temp;                            
    else                                                                        
      result := 0;                                                              
      resultdesc := 'no records.';                                              
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  delete from domainobjects where domainobjectsid = ldomainobjectsid_temp;      

                                                                                
  --delete nodeobjects                                                          
                                                                                
  open c_childnode;                                                             
  loop                                                                          
    begin                                                                       
      fetch c_childnode into ldomainid_temp,lnodeid_temp;                       
      exit when c_childnode%notfound;                                           
      spnodeobjectsreclaim(ldomainid,lnodeid_temp,sobjtype_temp,lobjid_temp,lsta
ffid,iiscommit,result,resultdesc);                                              
                                                                                
      if (result != 0) then                                                     
        close c_childnode;                                                      

        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        return;                                                                 
      end if;                                                                   
    exception                                                                   
    when others then                                                            
      close c_childnode;                                                        
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   
      result := -170001;                                                        
      resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sql

errm,1,100);                                                                    
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||subs
tr( sqlerrm,1,100));                                                            
                                                                                
      return;                                                                   
    end;                                                                        
  end loop;                                                                     
  close c_childnode;                                                            
                                                                                
  --update stockoutflag                                                         
                                                                                

  if  (sobjtype_temp = '35') then                                               
         select stockoutflag                                                    
         into lstockoutflag_temp                                                
         from series                                                            
         where  seriesid = lobjid_temp;                                         
         if (lstockoutflag_temp = 3) then   --reclaiming                        
            update series set stockoutflag='1' where seriesid = lobjid_temp;    
         end if;                                                                
    update series set stockoutflag='0' where seriesid = lobjid_temp             
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               
                                                                                
                                                                                

                                                                                
    delete from categorydtl where objid=lobjid_temp and objtype='1'             
    and categoryid in (select categoryid from category where domainid=ldomainid)
;                                                                               
                                                                                
                                                                                
    delete from bundledcontentdtl where objid=lobjid_temp and objtype='4'       
    and bundledcontentid in (select bundledcontentid from bundledcontent where d
omainid=ldomainid);                                                             
                                                                                
                                                                                
    update series set releaseTime=null where seriesid = lobjid_temp             
                                                                                

    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp                                                                           
                                                                                
    and objtype=sobjtype_temp);                                                 
                                                                                
  elsif (sobjtype_temp = '1') then                                              
         select stockoutflag                                                    
         into lstockoutflag_temp                                                
         from program                                                           
         where  programid = lobjid_temp;                                        
         if (lstockoutflag_temp = 3) then   --reclaiming                        
            update program set stockoutflag='1' where programid = lobjid_temp;  
         end if;                                                                

                                                                                
     update program set stockoutflag='0' where programid = lobjid_temp          
     and not exists (select domainobjectsid from domainobjects where objid=lobji
d_temp and objtype=sobjtype_temp);                                              
                                                                                
                                                                                
                                                                                
    update seriesdtl set stockoutflag='0' where programid = lobjid_temp         
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               
                                                                                
                                                                                
    delete from categorydtl where objid=lobjid_temp and objtype='8'             

    and categoryid in (select categoryid from category where domainid=ldomainid)
;                                                                               
                                                                                
                                                                                
    delete from bundledcontentdtl where objid=lobjid_temp and objtype='3'       
    and bundledcontentid in (select bundledcontentid from bundledcontent where d
omainid=ldomainid);                                                             
                                                                                
    update program set releaseTime=null where programid = lobjid_temp           
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               
                                                                                
                                                                                

  elsif (sobjtype_temp = '12') then                                             
    update channel set stockoutflag='0' where channelid = lobjid_temp           
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               
                                                                                
                                                                                
    delete from categorydtl where objid=lobjid_temp and objtype='C'             
    and categoryid in (select categoryid from category where domainid=ldomainid)
;                                                                               
                                                                                
                                                                                
    delete from categorydtl where objid in (select scheduleid from schedule wher
e channelid=lobjid_temp) and objtype='G'                                        

                                                                                
    and categoryid in (select categoryid from category where domainid=ldomainid)
;                                                                               
                                                                                
                                                                                
    delete from bundledcontentdtl where objid=lobjid_temp and objtype='1'       
    and bundledcontentid in (select bundledcontentid from bundledcontent where d
omainid=ldomainid);                                                             
                                                                                
                                                                                
    update channel set releaseTime=null where  channelid = lobjid_temp          
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               

                                                                                
  elsif (sobjtype_temp = '13') then                                             
    update cast set stockoutflag='0' where castid = lobjid_temp                 
    and not exists (select domainobjectsid from domainobjects where objid=lobjid
_temp and objtype=sobjtype_temp);                                               
                                                                                
  end if;                                                                       
                                                                                
 -- open c_get_contentservice;                                                  
   -- loop                                                                      
      --begin                                                                   
       -- fetch c_get_contentservice into lcontentserviceid_temp;               
       -- exit when c_get_contentservice%notfound;                              

       -- spcontentserviceremove(lcontentserviceid_temp,lstaffid,iiscommit,resul
t,resultdesc);                                                                  
                                                                                
       -- if (result != 0) then                                                 
         -- close c_get_contentservice;                                         
         -- if (iiscommit = 1) then                                             
            --rollback work;                                                    
         -- end if;                                                             
        --  return;                                                             
       -- end if;                                                               
     -- exception                                                               
     -- when others then                                                        
       -- close c_get_contentservice;                                           

       -- if (iiscommit = 1) then                                               
        --  rollback work;                                                      
       -- end if;                                                               
       -- result := -170001;                                                    
       -- resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr(
 sqlerrm,1,100);                                                                
                                                                                
      --  dbms_output.put_line(functionname||'result = '||result);              
      --  dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||
substr( sqlerrm,1,100));                                                        
                                                                                
       -- return;                                                               
      ---end;                                                                   

  --  end loop;                                                                 
  --close c_get_contentservice;                                                 
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spcopyrightremove                                                     

(                                                                               
     lcopyrightid                          in number,                           
     lstaffid                              in number,                           
     iiscommit                             in number,                           
     result                                in out number,                       
     resultdesc                            in out varchar2                      
                                                                                
)                                                                               
is                                                                              
    lcounter number(9);                                                         
    sobjtype varchar2(1);                                                       
    lobjid number(9);                                                           
    dcopyrightexpirationtime date;                                              

    functionname varchar(40) := 'spcopyrightremove: ';                          
                                                                                
begin                                                                           
     result :=0;                                                                
     select count(1) into lcounter from COPYRIGHT where COPYRIGHTID = lcopyright
id;                                                                             
                                                                                
                                                                                
     if (lcounter != 1) then                                                    
	result := 0;                                                                   
	resultdesc := 'no affect row.';                                                
	dbms_output.put_line(functionname||'result = '||result);                       
	dbms_output.put_line('no affect row.');                                        

	return;                                                                        
     end if;                                                                    
                                                                                
     begin                                                                      
        select objtype,objid into sobjtype,lobjid from COPYRIGHTMAP where copyri
ghtid = lcopyrightid;                                                           
                                                                                
                                                                                
        delete from assetidmap                                                  
               where assettype = 'D'                                            
        and mamid = lcopyrightid;                                               
                                                                                
	delete from copyrightmap where copyrightid = lcopyrightid;                     

	delete from copyright where copyrightid = lcopyrightid;                        
                                                                                
	spgetprogramcopyright(sobjtype,lobjid,dcopyrightexpirationtime,result,resultdes
c);                                                                             
                                                                                
                                                                                
	  if(sobjtype = '1') then                                                      
             update program set copyrightexpirationtime = dcopyrightexpirationti
me where programid = lobjid;                                                    
                                                                                
	  end if;                                                                      
                                                                                
	  if(sobjtype = '2') then                                                      

	     update series set copyrightexpirationtime = dcopyrightexpirationtime where
 seriesid = lobjid;                                                             
                                                                                
	  end if;                                                                      
                                                                                
     exception                                                                  
     when others then                                                           
        if (iiscommit = 1) then                                                 
           rollback work;                                                       
        end if;                                                                 
        result := -500003;                                                      
        resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( s
qlerrm,1,100);                                                                  

                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||su
bstr( sqlerrm,1,100));                                                          
                                                                                
        return;                                                                 
     end;                                                                       
                                                                                
      if (iiscommit = 1) then                                                   
         commit work;                                                           
      end if;                                                                   
      result := 0;                                                              
