procedure spcopyrightmodify                                                     
(                                                                               
	lcopyrightid				in number,                                                     
	lvspid					in number,                                                          

	scode					in varchar2,                                                         
	scode2					in varchar2,                                                        
	sbegindate				in varchar2,                                                     
	senddate				in varchar2,                                                       
	llifetime				in number,                                                        
	stransmitmode				in varchar2,                                                  
	sauthorizedregion			in varchar2,                                               
	sdescription				in varchar2,                                                   
	lstaffid				in number,                                                         
	iiscommit				in number,                                                        
	result					in out number,                                                      
	resultdesc				in out varchar2                                                  
)                                                                               

is                                                                              
        lcounter number(9);                                                     
	lcopyrightid_temp  number(9);                                                  
       	--scode_temp varchar2(160);                                             
	--scode2_temp varchar2(160);                                                   
	sobjtype varchar2(1);                                                          
	lobjid number(9);                                                              
	dbegindate_temp date;                                                          
	denddate_temp date;                                                            
	dcopyrightexpirationtime date;                                                 
	--scopyrightexpirationtime date;                                               
	functionname varchar(40) := 'spcopyrightmodify: ';                             
begin                                                                           

        result :=0;                                                             
       	lcopyrightid_temp := lcopyrightid;                                      
        select count(1) into lcounter from COPYRIGHT where COPYRIGHTID = lcopyri
ghtid;                                                                          
                                                                                
                                                                                
       if (lcounter != 1) then                                                  
	         result := 0;                                                          
	         resultdesc := 'no affect row.';                                       
	         dbms_output.put_line(functionname||'result = '||result);              
	         dbms_output.put_line('no affect row.');                               
	         return;                                                               
       end if;                                                                  

                                                                                
       if (lvspid is not null) then                                             
	   select count(1) into lcounter from vsp where vspid = lvspid;                
                                                                                
	   if (lcounter <= 0) then                                                     
	      if (iiscommit = 1) then                                                  
		  rollback work;                                                              
	      end if;                                                                  
	      result := -500001;                                                       
	      resultdesc := 'vspid not exist in table vsp.';                           
