	      return;                                                                  

	   end if;                                                                     
       end if;                                                                  
                                                                                
       begin                                                                    
           if (sbegindate is null) then                                         
	       dbegindate_temp := null;                                                
	   else                                                                        
	       select to_date(sbegindate,'yyyymmdd') into dbegindate_temp from dual;   
	   end if;                                                                     
	   if (senddate is null) then                                                  
	       denddate_temp := null;                                                  
	   else                                                                        
	       select to_date(senddate,'yyyymmdd') into denddate_temp from dual;       

	   end if;                                                                     
                                                                                
	   update copyright set                                                        
           code = scode,                                                        
	   code2 = scode2,                                                             
           begindate = dbegindate_temp,                                         
	   enddate = denddate_temp,                                                    
	   lifetime = llifetime,                                                       
	   transmitmode = stransmitmode,                                               
	   authorizedregion = sauthorizedregion,                                       
	   description = sdescription,                                                 
	   lastupdatetime = sysdate                                                    
	   where                                                                       

           copyrightid = lcopyrightid;                                          
                                                                                
          select objtype,objid into sobjtype,lobjid from COPYRIGHTMAP where copy
rightid = lcopyrightid;                                                         
                                                                                
                                                                                
	  spgetprogramcopyright(sobjtype,lobjid,dcopyrightexpirationtime,result,resultd
esc);                                                                           
                                                                                
                                                                                
	  if(sobjtype = '1') then                                                      
             update program set copyrightexpirationtime = dcopyrightexpirationti
me where programid = lobjid;                                                    

                                                                                
	  end if;                                                                      
                                                                                
	  if(sobjtype = '2') then                                                      
	     update series set copyrightexpirationtime = dcopyrightexpirationtime where
 seriesid = lobjid;                                                             
                                                                                
	  end if;                                                                      
                                                                                
       exception                                                                
       when others then                                                         
           if (iiscommit = 1) then                                              
		rollback work;                                                                

	   end if;                                                                     
	   result := -500003;                                                          
	   resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
	   dbms_output.put_line(functionname||'result = '||result);                    
	   dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
	   return;                                                                     
       end;                                                                     
                                                                                
        if (iiscommit = 1) then                                                 

           commit work;                                                         
        end if;                                                                 
        result := 0;                                                            
        resultdesc := to_char(lcopyrightid_temp);                               
        dbms_output.put_line(functionname||'result = '||result);                
end;                                                                            
procedure spcopyrightmapadd                                                     
(                                                                               
     lcopyrightmapid                        in number,                          
     sobjtype                               in varchar2,                        
     lobjid                                 in number,                          
     lcopyrightid                           in number,                          
     lstaffid                               in number,                          

     iiscommit                              in number,                          
     result                                 in out number,                      
     resultdesc                             in out varchar2                     
)                                                                               
is                                                                              
     lcounter number(9);                                                        
     lcopyrightmapid_temp number(9);                                            
     dcopyrightexpirationtime date;                                             
     denddate date;                                                             
     functionname varchar(40) := 'spcopyrightmapadd: ';                         
begin                                                                           
     result := 0;                                                               
     resultdesc := 'successful!';                                               

                                                                                
     select count(1)                                                            
       into lcounter                                                            
       from copyright                                                           
     where copyrightid = lcopyrightid;                                          
                                                                                
  if (lcounter <= 0) then                                                       
    result := -500003;                                                          
    resultdesc := 'copyrightid not exist.';                                     
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('copyrightid not exist.');                             
    return;                                                                     
  end if;                                                                       

                                                                                
                                                                                
  if (lobjid is null) then                                                      
    result := -500004;                                                          
    resultdesc := 'lobjid is not allow empty.';                                 
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('lobjid is not allow empty.');                         
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sobjtype is null) then                                                    
    result := -500005;                                                          
    resultdesc := 'type is not allow empty.';                                   

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('type is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
  if(sobjtype = '1')then                                                        
    select count(1)                                                             
    into lcounter                                                               
    from program                                                                
    where programid = lobjid;                                                   
    if (lcounter <= 0) then                                                     
     	--result := -500006;                                                      
     	result := 0;                                                              

      resultdesc := 'objid not exist in table program.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table program.');                
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if(sobjtype = '2')then                                                        
    select count(1)                                                             
    into lcounter                                                               
    from series                                                                 
    where seriesid = lobjid;                                                    
    if (lcounter <= 0) then                                                     

     	--result := -500006;                                                      
     	result := 0;                                                              
      resultdesc := 'objid not exist in table series.';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
   select count(1) into lcounter from COPYRIGHTMAP where copyrightid=lcopyrighti
d and objtype=sobjtype and objid=lobjid;                                        
                                                                                
  if (lcounter = 1) then                                                        

    --result := -500007;                                                        
    result := 0;                                                                
    resultdesc := 'have affect row.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('have affect row.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    if (lcopyrightmapid is null) then                                           
      select copyrightmapid.nextval into lcopyrightmapid_temp from dual;        
    else                                                                        
      lcopyrightmapid_temp := lcopyrightmapid;                                  

    end if;                                                                     
                                                                                
    insert into copyrightmap(copyrightmapid,objtype,objid,copyrightid)          
    values(lcopyrightmapid_temp,sobjtype,lobjid,lcopyrightid);                  
                                                                                
    select enddate into denddate from copyright where copyrightid = lcopyrightid
;                                                                               
                                                                                
                                                                                
    if(sobjtype = '1') then                                                     
        select copyrightexpirationtime into dcopyrightexpirationtime From  progr
am  where programid = lobjid;                                                   
                                                                                

    end if;                                                                     
                                                                                
    if(sobjtype = '2') then                                                     
         select copyrightexpirationtime into dcopyrightexpirationtime From  seri
es  where seriesid = lobjid;                                                    
                                                                                
    end if;                                                                     
                                                                                
    if(dcopyrightexpirationtime is null or dcopyrightexpirationtime < denddate) 
then                                                                            
                                                                                
       if(sobjtype = '1') then                                                  
          update program set copyrightexpirationtime = denddate where programid 

= lobjid;                                                                       
                                                                                
       end if;                                                                  
                                                                                
       if(sobjtype = '2') then                                                  
	  update series set copyrightexpirationtime = denddate where seriesid = lobjid;
                                                                                
                                                                                
       end if;                                                                  
    end if;                                                                     
 exception                                                                      
  when others then                                                              
    if iiscommit = 1 then                                                       

      rollback work;                                                            
    end if;                                                                     
    result := -500008;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         

    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lcopyrightmapid_temp);                                  
  dbms_output.put_line(functionname||'result = '||result);                      
                                                                                
end;                                                                            
procedure spcopyrightadd                                                        
(                                                                               
	lcopyrightid				in number,                                                     
	lvspid					in number,                                                          
	scode					in varchar2,                                                         
	scode2					in varchar2,                                                        

	sbegindate				in varchar2,                                                     
	senddate				in varchar2,                                                       
	llifetime				in number,                                                        
	stransmitmode				in varchar2,                                                  
	sauthorizedregion			in varchar2,                                               
	sdescription				in varchar2,                                                   
	lstaffid				in number,                                                         
	iiscommit				in number,                                                        
	result					in out number,                                                      
	resultdesc				in out varchar2                                                  
)                                                                               
is                                                                              
	lcounter number(9);                                                            

	lcopyrightid_temp number(9);                                                   
	scode_temp varchar2(160);                                                      
	scode2_temp varchar2(160);                                                     
	dbegindate_temp date;                                                          
	denddate_temp date;                                                            
	functionname varchar(40) := 'spcopyrightadd: ';                                
begin                                                                           
	result :=0;                                                                    
                                                                                
	if (lvspid is not null) then                                                   
		 select count(1) into lcounter from vsp where vspid = lvspid;                 
                                                                                
		if (lcounter <= 0) then                                                       

			if (iiscommit = 1) then                                                      
				rollback work;                                                              
			end if;                                                                      
			result := -500001;                                                           
			resultdesc := 'vspid not exist in table vsp.';                               
			dbms_output.put_line(functionname||'result = '||result);                     
			dbms_output.put_line('vspid not exist in table vsp.');                       
			return;                                                                      
		end if;                                                                       
	end if;                                                                        
                                                                                
	begin                                                                          
		if (sbegindate is null) then                                                  

			dbegindate_temp := null;                                                     
		else                                                                          
			select to_date(sbegindate,'yyyymmdd') into dbegindate_temp from dual;        
		end if;                                                                       
                                                                                
		if (senddate is null) then                                                    
			denddate_temp := null;                                                       
		else                                                                          
			select to_date(senddate,'yyyymmdd') into denddate_temp from dual;            
		end if;                                                                       
	 exception                                                                     
	when others then                                                               
		if (iiscommit = 1) then                                                       

			rollback work;                                                               
		end if;                                                                       
		result := -500002;                                                            
		resultdesc := 'the format of begindate/enddate is not correct.';              
		dbms_output.put_line(functionname||'result = '||result);                      
		dbms_output.put_line('the format of begindate/enddate is not correct.');      
		return;                                                                       
	end;                                                                           
                                                                                
	begin                                                                          
		if (lcopyrightid is null) then                                                
			select copyrightid.nextval into lcopyrightid_temp from dual;                 
		else                                                                          

			 lcopyrightid_temp := lcopyrightid;                                          
		end if;                                                                       
                                                                                
                                                                                
		scode_temp := scode;                                                          
		if (scode is null) then                                                       
			spgetglobalcode(lvspid,ctmsconstant_def.globalcode_copyright,lcopyrightid_tem
p,scode_temp,result);                                                           
                                                                                
			if (result != 0) then                                                        
				if (iiscommit = 1) then                                                     
					rollback work;                                                             
				end if;                                                                     

				return;                                                                     
			end if;                                                                      
		end if;                                                                       
                                                                                
		if (scode2 is null) then                                                      
			scode2_temp := scode_temp;                                                   
		else                                                                          
			scode2_temp := scode2;                                                       
		end if;                                                                       
                                                                                
                                                                                
		insert into copyright(copyrightid, code, code2, begindate, enddate, lifetime, 
transmitmode, authorizedregion, description, createdate, lastupdatetime)        

                                                                                
		values(lcopyrightid_temp, scode_temp , scode2_temp, dbegindate_temp, denddate_
temp, llifetime, stransmitmode, sauthorizedregion, sdescription, sysdate, null);
                                                                                
                                                                                
                                                                                
      exception                                                                 
       when others then                                                         
	if (iiscommit = 1) then                                                        
		rollback work;                                                                
	end if;                                                                        
	result := -500003;                                                             
	resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqlerrm,

1,100);                                                                         
                                                                                
	dbms_output.put_line(functionname||'result = '||result);                       
	dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr( s
qlerrm,1,100));                                                                 
                                                                                
	return;                                                                        
   end;                                                                         
        if (iiscommit = 1) then                                                 
           commit work;                                                         
        end if;                                                                 
        result := 0;                                                            
        resultdesc := to_char(lcopyrightid_temp);                               

        dbms_output.put_line(functionname||'result = '||result);                
end;                                                                            
                                                                                
procedure spconvertdurationtodate                                               
(                                                                               
  sairdate                              in varchar2,                            
  sairtime                              in varchar2,                            
  sduration                             in varchar2,                            
  scheckinput                           in varchar2,                            
  dstarttime                            in out date,                            
  dendtime                              in out date,                            
  result                                in out number,                          
  resultdesc                            in out varchar2                         

)                                                                               
is                                                                              
                                                                                
  ldurationlen number(9);                                                       
  functionname varchar(40) := 'spconvertdurationtodate: ';                      
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  ldurationlen := length(sduration);                                            
  if (scheckinput = '1') then                                                   
    if (sairdate is null or sairtime is null or sduration is null) then         
      result := -170020;                                                        

      resultdesc := 'airdate,airtime,duration is not allow empty.';             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('airdate,airtime,duration is not allow empty.');     
      return;                                                                   
    end if;                                                                     
                                                                                
    if (length(sairdate) != 8) then                                             
      result := -170021;                                                        
      resultdesc := 'the length of airdate should be 8.';                       
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('the length of airdate should be 8.');               
      return;                                                                   
    end if;                                                                     

                                                                                
    if (length(sairtime) != 6) then                                             
      result := -170022;                                                        
      resultdesc := 'the length of airtime should be 6.';                       
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('the length of airtime should be 6.');               
      return;                                                                   
    end if;                                                                     
                                                                                
    if (ldurationlen < 6 or ldurationlen > 9) then                              
      result := -170023;                                                        
      resultdesc := 'the length of duration should be [6,9].';                  
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('the length of duration should be [6,9].');          
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  --convert the datetime of the string format to datetime format.               
  begin                                                                         
    dstarttime := to_date(sairdate||sairtime, 'yyyymmddhh24miss');              
    dendtime := dstarttime+nvl(to_number(substr(sduration,1,ldurationlen-6)),0)+
                                                                                
                                                                                
                           nvl(to_number(substr(sduration,ldurationlen-5,2)),0)/
24+                                                                             

                                                                                
                           nvl(to_number(substr(sduration,ldurationlen-3,2)),0)/
24/60+                                                                          
                                                                                
                           nvl(to_number(substr(sduration,ldurationlen-1,2)),0)/
24/60/60;                                                                       
                                                                                
  exception                                                                     
  when others then                                                              
    result := -170009;                                                          
    resultdesc := 'the format of airdate/airtime/duration is not correct.';     
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the format of airdate/airtime/duration is not correct.

');                                                                             
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
