procedure spcontentservicequery                                                 
(                                                                               
  lcontentserviceid                     in out number,                          
  ldomainid                             in out number,                          
  sname                                 in out varchar2,                        
  scode                                 in out varchar2,                        
  scode2                                in out varchar2,                        
  sobjtype                              in out varchar2,                        
  lobjid                                in out number,                          

  susetype                              in out varchar2,                        
  sdescription                          in out varchar2,                        
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
  lcounter number(9);                                                           
  functionname varchar(40) := 'spcontentservicequery: ';                        
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  begin                                                                         

    select count(1)                                                             
    into lcounter                                                               
    from contentservice                                                         
    where contentserviceid = lcontentserviceid;                                 
    if (lcounter != 1) then                                                     
