procedure spcontentserviceadd                                                   

(                                                                               
  lcontentserviceid                     in number,                              
  ldomainid                             in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              
  susetype                              in varchar2,                            
  sdescription                          in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          

  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
  lcontentserviceid_temp number(9);                                             
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  functionname varchar(40) := 'spcontentserviceadd: ';                          
  ltransactionid  number;                                                       
  lcounter        number;                                                       
                                                                                
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  

                                                                                
  begin                                                                         
    if (lcontentserviceid is null) then                                         
      select contentserviceid.nextval into lcontentserviceid_temp from dual;    
    else                                                                        
      lcontentserviceid_temp := lcontentserviceid;                              
    end if;                                                                     
                                                                                
    if (ldomainid is not null) then                                             
      select count(1)                                                           
      into lcounter                                                             
      from domain                                                               
      where domainid = ldomainid;                                               

                                                                                
      if (lcounter <= 0) then                                                   
        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        result := -174020;                                                      
        resultdesc := 'domainid not exist in table domain.';                    
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('domainid not exist in table domain.');            
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                

    scode_temp := scode;                                                        
    if (scode is null) then                                                     
      spgetglobalcode(null,ctmsconstant_def.globalcode_contentservice,lcontentse
rviceid_temp,scode_temp,result);                                                
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                

    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                
    insert into contentservice(contentserviceid,domainid,name,code,code2,       
                               Objtype,Objid,usetype,description,createstaffid) 
    values(lcontentserviceid_temp,ldomainid,sname,scode_temp,scode2_temp,       
           sobjtype,lobjid,susetype,sdescription,lstaffid);                     
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_contentservice,lcontentserviceid
_temp,scode_temp,scode2_temp,'0',null,null,null,result);                        
                                                                                
    if (result != 0) then                                                       

      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lcontentserviceid_temp);                                
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            

procedure spcheckmulticastip                                                    
(                                                                               
  sip                                   in varchar2,                            
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lipdotloop number(9);                                                         
  lipdotpos number(5);                                                          
  sip_temp varchar2(100);                                                       
  sipsplit varchar2(10);                                                        
  functionname varchar(40) := 'spcheckmulticastip: ';                           

begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  --ip judgement.                                                               
  begin                                                                         
    lipdotloop := 0;                                                            
    sip_temp := sip;                                                            
    if (sip_temp is not null) then                                              
          select instr(sip_temp,'.') into lipdotpos from dual;                  
          select substr(sip_temp,1,lipdotpos-1) into sipsplit from dual;        
          select substr(sip_temp,lipdotpos+1) into sip_temp from dual;          
                                                                                

        if (sipsplit is null or to_number(sipsplit) < 224 or to_number(sipsplit)
 > 239) then                                                                    
                                                                                
          result := -170008;                                                    
          resultdesc := 'multicast ip invalid.';                                
          dbms_output.put_line(functionname||'result = '||result);              
          dbms_output.put_line('multicast ip invalid.');                        
          return;                                                               
        end if;                                                                 
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    result := -170008;                                                          

    resultdesc := 'multicast ip invalid.';                                      
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('multicast ip invalid.');                              
    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spcheckip                                                             
(                                                                               
  sip                                   in varchar2,                            

  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lipdotloop number(9);                                                         
  lipdotpos number(5);                                                          
  sip_temp varchar2(100);                                                       
  sipsplit varchar2(10);                                                        
  functionname varchar(40) := 'spcheckip: ';                                    
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  

                                                                                
  --ip judgement.                                                               
  begin                                                                         
    lipdotloop := 0;                                                            
    sip_temp := sip;                                                            
    if (sip_temp is not null) then                                              
      for lipdotloop in 0..3 loop                                               
        select instr(sip_temp,'.') into lipdotpos from dual;                    
        if (lipdotloop = 3) then                                                
          if (lipdotpos != 0) then                                              
            result := -170007;                                                  
            resultdesc := 'ip invalid.';                                        
            dbms_output.put_line(functionname||'result = '||result);            

            dbms_output.put_line('ip of 2m/4m biterate input invalid.');        
            return;                                                             
          end if;                                                               
          sipsplit := sip_temp;                                                 
          sip_temp := '';                                                       
        else                                                                    
          select substr(sip_temp,1,lipdotpos-1) into sipsplit from dual;        
          select substr(sip_temp,lipdotpos+1) into sip_temp from dual;          
        end if;                                                                 
                                                                                
        if (sipsplit is null or to_number(sipsplit) < 0 or to_number(sipsplit) >
 255) then                                                                      
                                                                                

          result := -170007;                                                    
          resultdesc := 'ip invalid.';                                          
          dbms_output.put_line(functionname||'result = '||result);              
          dbms_output.put_line('ip invalid.');                                  
          return;                                                               
        end if;                                                                 
      end loop;                                                                 
    end if;                                                                     
  exception                                                                     
  when others then                                                              
    result := -170007;                                                          
    resultdesc := 'ip invalid.';                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('ip invalid.');                                        
    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spchannelremove                                                       
(                                                                               
  lchannelid                            in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              

  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spchannelremove: ';                              
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from channel                                                                  

  where backupchannelid = lchannelid                                            
  and status != '9';                                                            
  if (lcounter > 0) then                                                        
    result := -172044;                                                          
    resultdesc := 'can not delete the channel used by another channel.';        
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('can not delete the channel used by another channel.');
                                                                                
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         

                                                                                
    delete from assetidmap                                                      
    where assettype = 'B'                                                       
    and mamid = lchannelid;                                                     
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_channel                        
    and objectid=lchannelid;                                                    
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_physicalchannel                

    and objectid in (select physicalchannelid from physicalchannel where channel
id = lchannelid);                                                               
                                                                                
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_schedule                       
    and objectid in (select scheduleid from schedule where channelid = lchanneli
d);                                                                             
                                                                                
                                                                                
    update channel                                                              
    set status = '9',lastupdatetime=sysdate                                     

    where channelid = lchannelid;                                               
                                                                                
    delete from favoriteobjects                                                 
    where staffid=lstaffid and objid=lchannelid;                                
                                                                                
    delete from categorydtl where objid=lchannelid and objtype='C'              
    and categoryid in (select categoryid from category where domainid is null); 
                                                                                
    delete from bundledcontentdtl where objid=lchannelid and objtype='1'        
    and bundledcontentid in (select bundledcontentid from bundledcontent where d
omainid is null);                                                               
                                                                                
                                                                                

  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                

    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
