  shdtv_temp char(1) := '0';                                                    
  scxinputformat_temp char(1) := '1';                                           
  scxoutputformat_temp char(1) := '2';                                          

  sfilterstartdate_temp date;                                                   
  sfilterenddate_temp date;                                                     
  djoinrecycletime_temp date;                                                   
                                                                                
  ssourcestatus char(1);                                                        
  ssourcetimeshift char(1);                                                     
  lsourcestorageduration number(9);                                             
  lsourceoffsettime number(9);                                                  
  loldstorageduration number(9);                                                
  maxstorageduration number(9);                                                 
  functionname varchar(40) := 'spchannelmodify: ';                              
begin                                                                           
  result := 0;                                                                  

                                                                                
  select count(1) into lcounter from channel where channelid = lchannelid;      
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  select videotype,audiotype,streamtype,channel_drm_type,storageduration        
  into fvideotype_old,faudiotype_old,fstreamtype_old,fchannel_drm_type_old,lolds
torageduration                                                                  

                                                                                
  from channel                                                                  
  where channelid = lchannelid;                                                 
                                                                                
  if (sname is null) then                                                       
    result := -172003;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  

    select count(1) into lcounter from channel where translate(name,'abcdefghijk
lmnopqrstuvwxyz','abcdefghijklmnopqrstuvwxyz') = translate(sname,'abcdefghijklmn
opqrstuvwxyz','abcdefghijklmnopqrstuvwxyz') and status = '4' and vspid = lvspid 
and channelid != lchannelid;                                                    
                                                                                
    if (lcounter > 0) then                                                      
      result := -172004;                                                        
      resultdesc := 'name repeated.';                                           
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('name repeated.');                                   
      return;                                                                   
    end if;                                                                     
  end if;                                                                       

                                                                                
  if (stype is not null) then                                                   
    stype_temp := stype;                                                        
  end if;                                                                       
                                                                                
  if (stimeshift is not null) then                                              
    stimeshift_temp := stimeshift;                                              
  end if;                                                                       
                                                                                
  if (stvodstatus is not null) then                                             
    stvodstatus_temp := stvodstatus;                                            
  end if;                                                                       
                                                                                

  if (ltimeshiftduration is not null) then                                      
    ltimeshiftduration_temp := ltimeshiftduration;                              
  end if;                                                                       
                                                                                
  if (shdtv is not null) then                                                   
    shdtv_temp := shdtv;                                                        
  end if;                                                                       
                                                                                
  if (stype_temp not in ('5','9')) then  --is not web channel/analog channel the
n                                                                               
                                                                                
    sstarttime_temp := sstarttime;                                              
    sendtime_temp := sendtime;                                                  

    if (sstarttime is null) then                                                
      sstarttime_temp := '0000';                                                
    end if;                                                                     
                                                                                
    if (sendtime is null) then                                                  
      sendtime_temp := '2359';                                                  
    end if;                                                                     
                                                                                
    if (length(sstarttime_temp) != 4 or length(sendtime_temp) != 4) then        
      result := -172006;                                                        
      resultdesc := 'starttime or endtime length must be 4.';                   
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('the length of starttime or endtime should be 4.');  

      return;                                                                   
    end if;                                                                     
                                                                                
    if (sfilterflag = '0') then                                                 
      sfilterstartdate_temp := null;                                            
    else                                                                        
      select to_date(sfilterstartdate,'yyyymmddhh24miss') into sfilterstartdate_
temp from dual;                                                                 
                                                                                
    end if;                                                                     
                                                                                
    if (sfilterflag = '0') then                                                 
      sfilterenddate_temp := null;                                              

    else                                                                        
      select to_date(sfilterenddate,'yyyymmddhh24miss') into sfilterenddate_temp
 from dual;                                                                     
                                                                                
    end if;                                                                     
    if (djoinrecycletime is null) then                                          
      djoinrecycletime_temp :=null;                                             
      else                                                                      
        select to_date(djoinrecycletime,'yyyymmddhh24miss') into djoinrecycletim
e_temp from dual;                                                               
                                                                                
    end if;                                                                     
    begin                                                                       

      lhour := to_number(substr(sstarttime_temp,1,2));                          
      lminute := to_number(substr(sstarttime_temp,3,2));                        
      if (lhour < 0 or lhour > 23 or lminute < 0 or lminute > 59) then          
        result := -172007;                                                      
        resultdesc := 'the format of starttime should be hhmm.';                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('the format of starttime format should be hhmm.'); 
        return;                                                                 
      end if;                                                                   
                                                                                
      lhour := to_number(substr(sendtime_temp,1,2));                            
      lminute := to_number(substr(sendtime_temp,3,2));                          
      if (lhour < 0 or lhour > 23 or lminute < 0 or lminute > 59) then          

        result := -172007;                                                      
        resultdesc := 'the format of endtime should be hhmm.';                  
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('the format of endtime should be hhmm.');          
        return;                                                                 
      end if;                                                                   
    exception                                                                   
    when others then                                                            
      result := -172020;                                                        
      resultdesc := 'starttime or endtime must be number.';                     
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('starttime or endtime must be number.');             
      return;                                                                   

    end;                                                                        
                                                                                
    if (scallsign is null) then                                                 
      result := -172010;                                                        
      resultdesc := 'callsign is not allow empty.';                             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('callsign is not allow empty.');                     
      return;                                                                   
    end if;                                                                     
                                                                                
    lstorageduration_temp := 0;                                                 
    if (lstorageduration is not null) then                                      
      lstorageduration_temp := lstorageduration;                                

    end if;                                                                     
  end if;                                                                       
                                                                                
  if (stype_temp = '5') then                                                    
    if (surl is null) then                                                      
      result := -172030;                                                        
      resultdesc := 'url is not allow empty here.';                             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('url is not allow empty here.');                     
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                

  lgridcount_temp := 1;                                                         
  if (stype_temp = '7') then                                                    
    if (lgridcount is null or lgridcount not in(4,9,16)) then                   
      result := -172033;                                                        
      resultdesc := 'when type equal ''7''(gridchannel), gridcount must in (4,9,
16).';                                                                          
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('when type equal ''7''(gridchannel), gridcount must i
n (4,9,16).');                                                                  
                                                                                
      return;                                                                   
    end if;                                                                     

                                                                                
    lgridcount_temp := lgridcount;                                              
  end if;                                                                       
                                                                                
  if (sstatus is not null) then                                                 
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                
  if (sstatus_temp is null or sstatus_temp not in ('4','9')) then               
    result := -172009;                                                          
    resultdesc := 'status must in (''4'',''9'').';                              
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('status must in (''4'',''9'').');                      

    return;                                                                     
  end if;                                                                       
                                                                                
  if (sodcflag is not null) then                                                
    sodcflag_temp := sodcflag;                                                  
  end if;                                                                       
                                                                                
  --web channel default promotion is 2                                          
  if (stype_temp = '5') then                                                    
    schannelpromotion := '2';                                                   
  end if;                                                                       
                                                                                
  if (spromotion is not null) then                                              

    schannelpromotion := spromotion;                                            
  end if;                                                                       
                                                                                
  if (ssubtype is not null) then                                                
    ssubtype_temp := ssubtype;                                                  
  end if;                                                                       
                                                                                
  if (sblockingflag is not null) then                                           
    sblockingflag_temp := sblockingflag;                                        
  end if;                                                                       
                                                                                
  --only live channel can be backup channel.                                    
  if (stype_temp != '1' and sodcflag_temp = '5') then                           

    result := -172040;                                                          
    resultdesc := 'only live channel can be backup channel.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('only live channel can be backup channel.');           
    return;                                                                     
  end if;                                                                       
                                                                                
  if (fstreamtype != 2 and sodcflag_temp = '5') then                            
    result := -172039;                                                          
    resultdesc := 'the stream type of backup channel should be "ts".';          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the stream type of backup channel should be "ts".');  
    return;                                                                     

  end if;                                                                       
                                                                                
  if (sodcflag_temp in ('3','5','6','7') and stimeshift_temp = '1') then        
    result := -172045;                                                          
    resultdesc := 'background/backup/nvod channel can not have timeshift functio
n.';                                                                            
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('background/backup/nvod channel can not have timeshift 
function.');                                                                    
                                                                                
    return;                                                                     
  end if;                                                                       

                                                                                
  if (scgms_a is not null ) then                                                
    scgms_a_temp :=scgms_a;                                                     
  end if;                                                                       
                                                                                
  if (shdcp is not null ) then                                                  
    shdcp_temp :=shdcp;                                                         
  end if;                                                                       
                                                                                
  if (sdownloadplay is not null ) then                                          
    sdownloadplay_temp :=sdownloadplay;                                         
  end if;                                                                       
                                                                                

  if (sscramble is not null ) then                                              
    sscramble_temp :=sscramble;                                                 
  end if;                                                                       
                                                                                
  if (scxinputformat is not null) then                                          
    scxinputformat_temp := scxinputformat;                                      
  end if;                                                                       
                                                                                
  if (scxoutputformat is not null) then                                         
    scxoutputformat_temp := scxoutputformat;                                    
  end if;                                                                       
                                                                                
  if sodcflag_temp = '6' then                                                   

    select count(1)                                                             
    into lcounter                                                               
    from channel                                                                
    where odcflag = '6'                                                         
    and status != '9';                                                          
    if (lcounter > 20) then                                                     
      result := -178707;                                                        
      resultdesc := 'ppv channel can not more than 20';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ppv channel can not more than 20');                 
      return;                                                                   
    end if;                                                                     
  end if;                                                                       

                                                                                
  if (lbackupchannelid is not null) then                                        
    if (sodcflag_temp = '5') then                                               
      result := -172043;                                                        
      resultdesc := 'backup channel can not be used for itself.';               
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('backup channel can not be used for itself.');       
      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from channel                                                                

    where odcflag = '5'                                                         
    and channelid = lbackupchannelid                                            
    and status != '9';                                                          
    if (lcounter = 0) then                                                      
      result := -172041;                                                        
      resultdesc := 'backupchannel not exist.';                                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('backupchannel not exist.');                         
      return;                                                                   
    end if;                                                                     
                                                                                
    select videotype,audiotype,streamtype,channel_drm_type                      
    into fbc_videotype,fbc_audiotype,fbc_streamtype,fbc_channel_drm_type        

    from channel                                                                
    where channelid = lbackupchannelid;                                         
                                                                                
    if (fbc_videotype != fvideotype or                                          
        fbc_audiotype != faudiotype or                                          
        fbc_streamtype != fstreamtype or                                        
        fbc_channel_drm_type != fchannel_drm_type) then                         
      result := -172042;                                                        
      resultdesc := 'videotype/audiotype/streamtype/channel_drm_type not match t
o the backupchannel.';                                                          
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('videotype/audiotype/streamtype/channel_drm_type not 

match to the backupchannel.');                                                  
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
  end if;                                                                       
                                                                                
  if (sodcflag_temp = '5') then                                                 
    select count(1)                                                             
    into lcounter                                                               
    from channel                                                                
    where backupchannelid = lchannelid                                          
    and status != '9';                                                          

    if (lcounter > 0) then                                                      
      if (fvideotype != fvideotype_old or faudiotype != faudiotype_old or       
          fstreamtype != fstreamtype_old or fchannel_drm_type != fchannel_drm_ty
pe_old) then                                                                    
                                                                                
        result := -172046;                                                      
        resultdesc := 'backup channel is used, can not modify videotype/audiotyp
e/streamtype/channel_drm_type.';                                                
                                                                                
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('backup channel is used, can not modify videotype/a
udiotype/streamtype/channel_drm_type.');                                        
                                                                                

        return;                                                                 
      end if;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (stype_temp = 'A') then                                                    
    select status, timeshift, storageduration                                   
    into ssourcestatus, ssourcetimeshift,lsourcestorageduration                 
    from channel where channelid = lsourcechannelid and status != '9';          
                                                                                
    if (ssourcestatus = '9' and sstatus_temp = '4') then                        
      result := -172052;                                                        
      resultdesc := 'source channel status is deactive, so you can not set the d

elay channel status to active.';                                                
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('source channel status is deactive, so you can not se
t the delay channel status to active.');                                        
                                                                                
      return;                                                                   
    end if;                                                                     
  else                                                                          
    select nvl(max(offsettime),0) into lsourceoffsettime from channel where sour
cechannelid = lchannelid;                                                       
                                                                                
    if (lsourceoffsettime > (lstorageduration_temp*3600)) then                  

    result := -172051;                                                          
    resultdesc := 'delaychannel''s offset time is larger than the storageduratio
n.';                                                                            
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('delaychannel''s offset time is larger than the storage
duration.');                                                                    
                                                                                
    return;                                                                     
    end if;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         

    /*if (stype_temp = '7') then                                                
      select gridcount into loldgridcount from channel where channelid = lchanne
lid;                                                                            
                                                                                
                                                                                
      if (loldgridcount > lgridcount_temp) then                                 
        if (lgridcount_temp = 4) then                                           
          delete from gridchanneldetail                                         
          where (xpos > 1 or ypos > 1)                                          
          and channelid = lchannelid;                                           
        elsif (lgridcount_temp = 9) then                                        
          delete from gridchanneldetail                                         
          where (xpos > 2 or ypos > 2)                                          

          and channelid = lchannelid;                                           
        elsif (lgridcount_temp = 16) then                                       
          delete from gridchanneldetail                                         
          where (xpos > 3 or ypos > 3)                                          
          and channelid = lchannelid;                                           
        end if;                                                                 
      end if;                                                                   
    end if;*/                                                                   
                                                                                
    --check ldelaytime and lbackupplayaheadtime                                 
    if ldelaytime != 0 and not (ldelaytime >= 5 and ldelaytime <= 90) then      
      result := -172047; --delay time need be 0 or 5~90 seconds                 
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('delay time need be 0 or 5~90 seconds.');            
      return;                                                                   
    end if;                                                                     
                                                                                
    if not (lbackupplayaheadtime >= 0 and lbackupplayaheadtime <= ldelaytime) th
en                                                                              
                                                                                
      result := -172048; --backup program play time need be 0~delay time        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('backup program play time need be 0~delay time.');   
      return;                                                                   
    end if;                                                                     
                                                                                

    if(loldstorageduration!=lstorageduration_temp)then                          
      if(loldstorageduration>lstorageduration_temp) then                        
        maxstorageduration:=loldstorageduration;                                
      else                                                                      
        maxstorageduration:=lstorageduration_temp;                              
      end if;                                                                   
      update schedule set realstorageduration=lstorageduration_temp,overduedate 
=  airendtime + lstorageduration_temp/24                                        
                                                                                
      where overduedate >= sysdate                                              
      and storageduration <= maxstorageduration and channelid=lchannelid;       
    end if;                                                                     
                                                                                

    update channel                                                              
    set vspid = lvspid,                                                         
        channelnumber = lchannelnumber,                                         
        name = sname,                                                           
        code2 = scode2,                                                         
        timeshift = stimeshift_temp,                                            
        storageduration = lstorageduration_temp,                                
  tvodstatus = stvodstatus_temp,                                                
  timeshiftduration = ltimeshiftduration_temp,                                  
        odcflag = sodcflag_temp,                                                
        description = sdescription,                                             
        callsign = scallsign,                                                   
        timezone = stimezone,                                                   

        type = stype_temp,                                                      
        status = sstatus_temp,                                                  
        starttime = sstarttime_temp,                                            
        endtime = sendtime_temp,                                                
        url = surl,                                                             
        videotype = fvideotype,                                                 
        audiotype = faudiotype,                                                 
        streamtype = fstreamtype,                                               
        bilingual = sbilingual,                                                 
        channel_drm_type = fchannel_drm_type,                                   
        drm_profile_type = fdrm_profile_type,                                   
        promotion = schannelpromotion,                                          
        gridcount = lgridcount_temp,                                            

        --subtype = ssubtype_temp,                                              
        backupchannelid = lbackupchannelid,                                     
        hdtv = shdtv_temp,                                                      
        cgms_a = scgms_a_temp,                                                  
        hdcp = shdcp_temp,                                                      
        downloadplay = sdownloadplay_temp,                                      
        scramble = sscramble_temp,                                              
        watermark = swatermark,                                                 
        fingerprint = sfingerprint,                                             
        delaytime=ldelaytime,                                                   
        backupplayaheadtime=lbackupplayaheadtime,                               
        blockingflag=sblockingflag_temp,                                        
        sourcechannelid = lsourcechannelid,                                     

        offsettime = loffsettime,                                               
        cxinputformat=scxinputformat_temp,                                      
        cxoutputformat=scxoutputformat_temp,                                    
        lastupdatetime=sysdate,                                                 
        scheduleReleaseflag=sscheduleReleaseflag,                               
        filterflag=sfilterflag,                                                 
        filterstartdate=sfilterstartdate_temp,                                  
        filterenddate=sfilterenddate_temp,                                      
        schedulecheckflag=sschedulecheckflag,                                   
        recycleflag=srecycleflag,                                               
        labelids=slabelids,                                                     
        operater=soperater,                                                     
        joinrecycletime=djoinrecycletime_temp                                   

    where channelid = lchannelid;                                               
                                                                                
    update globalcodemap                                                        
    set status = decode(sstatus,'9','1','0')                                    
    where objecttype=ctmsconstant_def.globaltype_channel                        
    and objectid=lchannelid;                                                    
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          

    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  

  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spchanneladd                                                          
(                                                                               
  lchannelid                            in number,                              
  lvspid                                in number,                              
  lchannelnumber                        in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  stimeshift                            in varchar2,                            
  sscheduleReleaseflag                  In Varchar2,                            

  lstorageduration                      in number,                              
  stvodstatus                           in varchar2,                            
  ltimeshiftduration                    in number,                              
  sodcflag                              in varchar2,                            
  sdescription                          in varchar2,                            
  scallsign                             in varchar2,                            
  stimezone                             in varchar2,                            
  stype                                 in varchar2,                            
  sstatus                               in varchar2,                            
  sstarttime                            in varchar2,                            
  sendtime                              in varchar2,                            
  surl                                  in varchar2,                            
  fvideotype                            in number,                              

  faudiotype                            in number,                              
  fstreamtype                           in number,                              
  sbilingual                            in varchar2,                            
  fchannel_drm_type                     in number,                              
  fdrm_profile_type                     in number,                              
  spromotion                            in varchar2,                            
  lgridcount                            in number,                              
  ssubtype                              in varchar2,                            
  lbackupchannelid                      in number,                              
  shdtv                                 in varchar2,                            
  scgms_a                               in varchar2,                            
  shdcp                                 in varchar2,                            
  sdownloadplay                         in varchar2,                            

  sscramble                             in varchar2,                            
  swatermark                            in varchar2,                            
  sfingerprint                          in varchar2,                            
  ldelaytime                            in number,                              
  lbackupplayaheadtime                  in number,                              
  sblockingflag                         in varchar2,                            
  lsourcechannelid                      in number,                              
  loffsettime                           in number,                              
  scxinputformat                        in varchar2,                            
  scxoutputformat                       in varchar2,                            
  sfilterflag                           in varchar2,                            
  sfilterstartdate                      in varchar2,                            
  sfilterenddate                        in varchar2,                            

  srecycleflag                          in varchar2,                            
  slabelids                             in varchar2,                            
  soperater                             in varchar2,                            
  djoinrecycletime                      in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  sschedulecheckflag                   in number,                               
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           

  lhour number(2);                                                              
  lminute number(2);                                                            
  lsecond number(2);                                                            
  lchannelid_temp number(9);                                                    
  lgridcount_temp number(2);                                                    
  stype_temp varchar2(2) := '1';                                                
  ssubtype_temp varchar2(2) := '1';                                             
  sodcflag_temp varchar2(2) := '0';                                             
  sstatus_temp char(1) := '1';                                                  
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sglobalcodemapstatus char(1) := '0';                                          
                                                                                

  schannelpromotion char(1) := '0';                                             
  scgms_a_temp char(1) :='0';                                                   
  shdcp_temp   char(1) :='0';                                                   
  sdownloadplay_temp char(1) :='0';                                             
  sscramble_temp char(1) :='0';                                                 
  sblockingflag_temp char(1) := '0';                                            
  lstorageduration_temp number(9) := 0;                                         
  sstarttime_temp varchar2(8);                                                  
  sendtime_temp varchar2(8);                                                    
  stimeshift_temp char(1) := '0';                                               
  stvodstatus_temp char(1) := '0';                                              
  ltimeshiftduration_temp number(9) := 0;                                       
  shdtv_temp char(1) := '0';                                                    

  scxinputformat_temp char(1) := '1';                                           
  scxoutputformat_temp char(1) := '2';                                          
  sfilterstartdate_temp date;                                                   
  sfilterenddate_temp date;                                                     
  djoinrecycletime_temp date;                                                   
  fbc_videotype        number;                                                  
  fbc_audiotype        number;                                                  
  fbc_streamtype       number;                                                  
  fbc_channel_drm_type number;                                                  
  ssourcestatus char(1);                                                        
  ssourcetimeshift char(1);                                                     
  lsourcestorageduration number(9);                                             
  functionname varchar(40) := 'spchanneladd: ';                                 

begin                                                                           
  result := 0;                                                                  
                                                                                
  if (lvspid is not null) then                                                  
    select count(1)                                                             
    into lcounter                                                               
    from vsp                                                                    
    where vspid = lvspid;                                                       
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   

      result := -170108;                                                        
      resultdesc := 'vspid not exist in table vsp.';                            
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('vspid not exist in table vsp.');                    
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sname is null) then                                                       
    result := -172003;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           

    return;                                                                     
  end if;                                                                       
                                                                                
  if (lvspid is not null) then                                                  
    select count(1) into lcounter from channel where translate(name,'abcdefghijk
lmnopqrstuvwxyz','abcdefghijklmnopqrstuvwxyz') = translate(sname,'abcdefghijklmn
opqrstuvwxyz','abcdefghijklmnopqrstuvwxyz') and status = '4' and vspid = lvspid;
                                                                                
                                                                                
    if (lcounter > 0) then                                                      
      result := -172004;                                                        
      resultdesc := 'name repeated.';                                           
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('name repeated.');                                   
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (stype is not null) then                                                   
    stype_temp := stype;                                                        
  end if;                                                                       
                                                                                
  if (stimeshift is not null) then                                              
    stimeshift_temp := stimeshift;                                              
  end if;                                                                       
                                                                                

  if (stvodstatus is not null) then                                             
    stvodstatus_temp := stvodstatus;                                            
  end if;                                                                       
                                                                                
  if (ltimeshiftduration is not null) then                                      
    ltimeshiftduration_temp := ltimeshiftduration;                              
  end if;                                                                       
                                                                                
  if (shdtv is not null) then                                                   
    shdtv_temp := shdtv;                                                        
  end if;                                                                       
                                                                                
  if (stype_temp not in ('5','9')) then  --is not web channel/analog channel the

n                                                                               
                                                                                
    sstarttime_temp := sstarttime;                                              
    sendtime_temp := sendtime;                                                  
    if (sstarttime is null) then                                                
      sstarttime_temp := '0000';                                                
    end if;                                                                     
                                                                                
    if (sendtime is null) then                                                  
      sendtime_temp := '2359';                                                  
    end if;                                                                     
                                                                                
    if (length(sstarttime_temp) != 4 or length(sendtime_temp) != 4) then        

      result := -172006;                                                        
      resultdesc := 'starttime or endtime length must be 4.';                   
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('the length of starttime or endtime should be 4.');  
      return;                                                                   
    end if;                                                                     
                                                                                
    if (sfilterstartdate is null) then                                          
      sfilterstartdate_temp := null;                                            
    else                                                                        
      select to_date(sfilterstartdate,'yyyymmddhh24miss') into sfilterstartdate_
temp from dual;                                                                 
                                                                                

    end if;                                                                     
                                                                                
    if (sfilterenddate is null) then                                            
      sfilterenddate_temp := null;                                              
    else                                                                        
      select to_date(sfilterenddate,'yyyymmddhh24miss') into sfilterenddate_temp
 from dual;                                                                     
                                                                                
    end if;                                                                     
                                                                                
    if (djoinrecycletime is null) then                                          
      djoinrecycletime_temp := null;                                            
    else                                                                        

      select to_date(djoinrecycletime,'yyyymmddhh24miss') into djoinrecycletime_
temp from dual;                                                                 
                                                                                
    end if;                                                                     
    begin                                                                       
      lhour := to_number(substr(sstarttime_temp,1,2));                          
      lminute := to_number(substr(sstarttime_temp,3,2));                        
      if (lhour < 0 or lhour > 23 or lminute < 0 or lminute > 59) then          
        result := -172007;                                                      
        resultdesc := 'starttime format must be hhmm.';                         
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('starttime format must be hhmm.');                 
        return;                                                                 

      end if;                                                                   
                                                                                
      lhour := to_number(substr(sendtime_temp,1,2));                            
      lminute := to_number(substr(sendtime_temp,3,2));                          
      if (lhour < 0 or lhour > 23 or lminute < 0 or lminute > 59) then          
        result := -172007;                                                      
        resultdesc := 'endtime format must be hhmm.';                           
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('endtime format must be hhmm.');                   
        return;                                                                 
      end if;                                                                   
    exception                                                                   
    when others then                                                            

      result := -172020;                                                        
      resultdesc := 'starttime or endtime must be number.';                     
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('starttime or endtime must be number.');             
      return;                                                                   
    end;                                                                        
                                                                                
    lstorageduration_temp := 0;                                                 
    if (lstorageduration is not null) then                                      
      lstorageduration_temp := lstorageduration;                                
    end if;                                                                     
  end if;                                                                       
                                                                                

  if (stype_temp = '5') then                                                    
    if (surl is null) then                                                      
      result := -172030;                                                        
      resultdesc := 'url is not allow empty here.';                             
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('url is not allow empty here.');                     
      return;                                                                   
    end if;                                                                     
  else                                                                          
    if (scallsign is null) then                                                 
      result := -172010;                                                        
      resultdesc := 'callsign is not allow empty.';                             
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('callsign is not allow empty.');                     
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  lgridcount_temp := 1;                                                         
  if (stype_temp = '7') then                                                    
    if (lgridcount is null or lgridcount not in(4,9,16)) then                   
      result := -172033;                                                        
      resultdesc := 'when type equal ''7''(gridchannel), gridcount must in (4,9,
16).';                                                                          
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('when type equal ''7''(gridchannel), gridcount must i
n (4,9,16).');                                                                  
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
    lgridcount_temp := lgridcount;                                              
  end if;                                                                       
                                                                                
  if (sstatus is not null) then                                                 
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
                                                                                

  if (sstatus_temp = '9') then                                                  
    sglobalcodemapstatus := '1';                                                
  end if;                                                                       
                                                                                
  if (sstatus_temp is null or sstatus_temp not in ('4','9')) then               
    result := -172009;                                                          
    resultdesc := 'status must in (''4'',''9'').';                              
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('status must in (''4'',''9'').');                      
    return;                                                                     
  end if;                                                                       
                                                                                
  if (ssubtype is not null) then                                                

    ssubtype_temp := ssubtype;                                                  
  end if;                                                                       
                                                                                
  if (sodcflag is not null) then                                                
    sodcflag_temp := sodcflag;                                                  
  end if;                                                                       
                                                                                
  --web channel default promotion is 2                                          
  if (stype_temp = '5') then                                                    
    schannelpromotion := '2';                                                   
  end if;                                                                       
                                                                                
  if (spromotion is not null) then                                              

    schannelpromotion := spromotion;                                            
  end if;                                                                       
                                                                                
  if (sblockingflag is not null) then                                           
    sblockingflag_temp := sblockingflag;                                        
  end if;                                                                       
                                                                                
  --the stream type of backup channel should be "ts".                           
  if (fstreamtype != 2 and sodcflag_temp = '5') then                            
    result := -172039;                                                          
    resultdesc := 'the stream type of backup channel should be "ts".';          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('the stream type of backup channel should be "ts".');  

    return;                                                                     
  end if;                                                                       
                                                                                
  --only live channel can be backup channel.                                    
  if (stype_temp != '1' and sodcflag_temp = '5') then                           
    result := -172040;                                                          
    resultdesc := 'only live channel can be backup channel.';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('only live channel can be backup channel.');           
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sodcflag_temp in ('3','5','6','7') and stimeshift_temp = '1') then        

    result := -172045;                                                          
    resultdesc := 'background/backup/nvod channel can not have timeshift functio
n.';                                                                            
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('background/backup/nvod channel can not have timeshift 
function.');                                                                    
                                                                                
    return;                                                                     
  end if;                                                                       
                                                                                
  if sodcflag_temp = '6' then                                                   
    select count(1)                                                             

    into lcounter                                                               
    from channel                                                                
    where odcflag = '6'                                                         
    and status != '9';                                                          
    if (lcounter > 20) then                                                     
      result := -178707;                                                        
      resultdesc := 'ppv channel can not more then 20';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('ppv channel can not more then 20');                 
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                

  if (lbackupchannelid is not null) then                                        
    if (sodcflag_temp = '5') then                                               
      result := -172043;                                                        
      resultdesc := 'backup channel can not be used for itself.';               
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('backup channel can not be used for itself.');       
      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from channel                                                                
    where odcflag = '5'                                                         

    and channelid = lbackupchannelid                                            
    and status != '9';                                                          
    if (lcounter = 0) then                                                      
      result := -172041;                                                        
      resultdesc := 'backupchannel not exist.';                                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('backupchannel not exist.');                         
      return;                                                                   
    end if;                                                                     
                                                                                
    select videotype,audiotype,streamtype,channel_drm_type                      
    into fbc_videotype,fbc_audiotype,fbc_streamtype,fbc_channel_drm_type        
    from channel                                                                

    where channelid = lbackupchannelid;                                         
                                                                                
    if (fbc_videotype != fvideotype or                                          
        fbc_audiotype != faudiotype or                                          
        fbc_streamtype != fstreamtype or                                        
        fbc_channel_drm_type != fchannel_drm_type) then                         
      result := -172042;                                                        
      resultdesc := 'videotype/audiotype/streamtype/channel_drm_type not match t
o the backupchannel.';                                                          
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('videotype/audiotype/streamtype/channel_drm_type not 
match to the backupchannel.');                                                  

                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
  end if;                                                                       
                                                                                
  if (scgms_a is not null ) then                                                
    scgms_a_temp :=scgms_a;                                                     
  end if;                                                                       
                                                                                
  if (shdcp is not null ) then                                                  
    shdcp_temp :=shdcp;                                                         
  end if;                                                                       

                                                                                
  if (sdownloadplay is not null ) then                                          
    sdownloadplay_temp :=sdownloadplay;                                         
  end if;                                                                       
                                                                                
  if (sscramble is not null ) then                                              
    sscramble_temp :=sscramble;                                                 
  end if;                                                                       
                                                                                
  if (scxinputformat is not null) then                                          
    scxinputformat_temp := scxinputformat;                                      
  end if;                                                                       
                                                                                

  if (scxoutputformat is not null) then                                         
    scxoutputformat_temp := scxoutputformat;                                    
  end if;                                                                       
                                                                                
  --check ldelaytime and lbackupplayaheadtime                                   
  if ldelaytime != 0 and not (ldelaytime >= 5 and ldelaytime <= 90) then        
    result := -172047; --delay time need be 0 or 5~90 seconds                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('delay time need be 0 or 5~90 seconds.');              
    return;                                                                     
  end if;                                                                       
                                                                                
  if not (lbackupplayaheadtime >= 0 and lbackupplayaheadtime <= ldelaytime) then

                                                                                
                                                                                
    result := -172048; --backup program play time need be 0~delay time          
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('backup program play time need be 0~delay time.');     
    return;                                                                     
  end if;                                                                       
                                                                                
  if (stype_temp = 'A') then                                                    
    if (lsourcechannelid is null) then                                          
      result := -172050;                                                        
      resultdesc := 'delay channel must define it''s source channel.';          
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('delay channel must define it''s source channel.');  
      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1) into lcounter from channel where channelid = lsourcechanneli
d and status != '9';                                                            
                                                                                
    if (lcounter != 1) then                                                     
      result := -172050;                                                        
      resultdesc := 'source channel not found.';                                
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('source channel not found.');                        
      return;                                                                   

    end if;                                                                     
                                                                                
    select status, timeshift, storageduration                                   
    into ssourcestatus, ssourcetimeshift,lsourcestorageduration                 
    from channel where channelid = lsourcechannelid and status != '9';          
    if (ssourcetimeshift != '1' or ((lsourcestorageduration*3600) < loffsettime)
) then                                                                          
                                                                                
      result := -172051;                                                        
      resultdesc := 'offset time is larger than source channel''s storage durati
on.';                                                                           
                                                                                
      dbms_output.put_line(functionname||'result = '||result);                  

      dbms_output.put_line('offset time is larger than source channel''s storage
 duration.');                                                                   
                                                                                
      return;                                                                   
    end if;                                                                     
                                                                                
  end if;                                                                       
                                                                                
  begin                                                                         
    if (lchannelid is null) then                                                
      spgetobjectid(ctmsconstant_def.objectid_channelid,lchannelid_temp,result,r
esultdesc);                                                                     
                                                                                

      if (result != 0) then                                                     
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('get objectid failed.');                           
        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        return;                                                                 
      end if;                                                                   
    else                                                                        
      lchannelid_temp := lchannelid;                                            
    end if;                                                                     
                                                                                
    scode_temp := scode;                                                        

    if (scode is null) then                                                     
      spgetglobalcode(lvspid,ctmsconstant_def.globalcode_channel,lchannelid_temp
,scode_temp,result);                                                            
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                
    else                                                                        

      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                
    if (stype_temp = 'A') then                                                  
      insert into channel(channelid,vspid,channelnumber,                        
                          name,code,code2,timeshift,storageduration,timeshiftdur
ation,tvodstatus,odcflag,description,                                           
                                                                                
                          callsign,timezone,type,status,starttime,endtime,url,  
                          videotype,audiotype,streamtype,bilingual,             
                          channel_drm_type,drm_profile_type,promotion,gridcount,
                                                                                
                                                                                

                          subtype,backupchannelid,hdtv,                         
                          cgms_a,hdcp,downloadplay,scramble,watermark,fingerprin
t,                                                                              
                                                                                
                          delaytime,backupplayaheadtime,blockingflag,           
                          sourcechannelid,offsettime,cxinputformat,cxoutputforma
t,                                                                              
                                                                                
                          createstaffid,scheduleReleaseflag,filterflag,filtersta
rtdate,                                                                         
                                                                                
                          filterenddate,recycleflag,labelids,operater,joinrecycl
etime)                                                                          

                                                                                
      select lchannelid_temp,lvspid,lchannelnumber,                             
             sname,scode_temp,scode2_temp,stimeshift_temp,lstorageduration_temp,
ltimeshiftduration_temp,stvodstatus_temp,sodcflag_temp,sdescription,            
                                                                                
             scallsign,stimezone,stype_temp,sstatus_temp,sstarttime_temp,sendtim
e_temp,surl,                                                                    
                                                                                
             videotype,audiotype,streamtype,bilingual,                          
             channel_drm_type,drm_profile_type,schannelpromotion,lgridcount_temp
,                                                                               
                                                                                
             ssubtype_temp,lbackupchannelid,hdtv,                               

             cgms_a,hdcp,sdownloadplay_temp,scramble,swatermark,sfingerprint,   
             ldelaytime,lbackupplayaheadtime,sblockingflag_temp,                
             lsourcechannelid,loffsettime,cxinputformat,cxoutputformat,lstaffid,
scheduleReleaseflag,filterflag,filterstartdate,                                 
                                                                                
             filterenddate,srecycleflag,labelids,soperater,djoinrecycletime_temp
                                                                                
                                                                                
      from channel                                                              
      where channelid = lsourcechannelid;                                       
    else                                                                        
      insert into channel(channelid,vspid,channelnumber,                        
                          name,code,code2,timeshift,storageduration,timeshiftdur

ation,tvodstatus,odcflag,description,                                           
                                                                                
                          callsign,timezone,type,status,starttime,endtime,url,  
                          videotype,audiotype,streamtype,bilingual,             
                          channel_drm_type,drm_profile_type,promotion,gridcount,
                                                                                
                                                                                
                          subtype,backupchannelid,hdtv,                         
                          cgms_a,hdcp,downloadplay,scramble,watermark,fingerprin
t,                                                                              
                                                                                
                          delaytime,backupplayaheadtime,blockingflag,           
                          sourcechannelid,offsettime,cxinputformat,cxoutputforma

t,                                                                              
                                                                                
                          createstaffid,scheduleReleaseflag,filterflag,filtersta
rtdate,                                                                         
                                                                                
                          filterenddate,schedulecheckflag,recycleflag,labelids,o
perater,joinrecycletime)                                                        
                                                                                
      values(lchannelid_temp,lvspid,lchannelnumber,                             
             sname,scode_temp,scode2_temp,stimeshift_temp,lstorageduration_temp,
ltimeshiftduration_temp,stvodstatus_temp,sodcflag_temp,sdescription,            
                                                                                
             scallsign,stimezone,stype_temp,sstatus_temp,sstarttime_temp,sendtim

e_temp,surl,                                                                    
                                                                                
             fvideotype,faudiotype,fstreamtype,sbilingual,                      
             fchannel_drm_type,fdrm_profile_type,schannelpromotion,lgridcount_te
mp,                                                                             
                                                                                
             ssubtype_temp,lbackupchannelid,shdtv_temp,                         
             scgms_a_temp,shdcp_temp,sdownloadplay_temp,sscramble_temp,swatermar
k,sfingerprint,                                                                 
                                                                                
             ldelaytime,lbackupplayaheadtime,sblockingflag_temp,                
             lsourcechannelid,loffsettime,scxinputformat_temp,scxoutputformat_te
mp,lstaffid,                                                                    

                                                                                
             sscheduleReleaseflag,sfilterflag,sfilterstartdate_temp,sfilterendda
te_temp,                                                                        
                                                                                
             sschedulecheckflag,srecycleflag,slabelids,soperater,djoinrecycletim
e_temp);                                                                        
                                                                                
    end if;                                                                     
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_channel,lchannelid_temp,scode_te
mp,scode2_temp,sglobalcodemapstatus,null,null,null,result);                     
                                                                                
    if (result != 0) then                                                       

      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                

    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lchannelid_temp);                                       
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            

procedure spcategoryupdatestatus                                                
(                                                                               
  lcategoryid                           in number,                              
  sstatus                               in varchar2,                            
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lchildclassid number(9);                                                      
  lcounter number(9);                                                           

  functionname varchar(40) := 'spcategoryupdatestatus: ';                       
                                                                                
  /*                                                                            
  cursor c_childclass is                                                        
  select categoryid                                                             
  from category                                                                 
  where parentid = lcategoryid;                                                 
  */                                                                            
begin                                                                           
  result := 0;                                                                  
                                                                                
  begin                                                                         
    if (sstatus is null or sstatus not in ('0','1')) then                       

      result := -174005;                                                        
      resultdesc := 'status is empty or not in (''0'',''1'').';                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('status is empty or not in (''0'',''1'').');         
      return;                                                                   
