procedure spcategoryremove                                                      
(                                                                               

  lcategoryid                           in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lcontentserviceid_temp number(9);                                             
  functionname varchar(40) := 'spcategoryremove: ';                             
                                                                                
  cursor c_get_contentservice is                                                

  select contentserviceid from contentservice where objtype='5' and objid=lcateg
oryid;                                                                          
                                                                                
                                                                                
begin                                                                           
  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from category where categoryid = lcategoryid;   
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('no row affected.');                                   

    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from category                                                               
    where parentid = lcategoryid;                                               
    if (lcounter > 0) then                                                      
      update category set parentid=null where parentid = lcategoryid;           
    end if;                                                                     
                                                                                

  update upperctmsnode set rootcategoryid = null where rootcategoryid = lcategor
yid;                                                                            
                                                                                
    delete from categorydtl where categoryid = lcategoryid;                     
    delete from picturemap where objtype = '3' and objid = lcategoryid;         
    delete from assetidmap where assettype = 'A' and mamid=lcategoryid;         
    delete from staffcategoryassign where categoryid  = lcategoryid;            
    delete from rolecategoryassign where categoryid  = lcategoryid;             
    delete from staffdataprivilege where objecttype= '1' and objectid = lcategor
yid;                                                                            
                                                                                
    delete from roledataprivilege where objecttype= '1' and objectid = lcategory
id;                                                                             

                                                                                
    delete from category where categoryid = lcategoryid;                        
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_category                       
    and objectid=lcategoryid;                                                   
                                                                                
    open c_get_contentservice;                                                  
      loop                                                                      
        begin                                                                   
          fetch c_get_contentservice into lcontentserviceid_temp;               
          exit when c_get_contentservice%notfound;                              

          spcontentserviceremove(lcontentserviceid_temp,lstaffid,iiscommit,resul
t,resultdesc);                                                                  
                                                                                
          if (result != 0) then                                                 
            close c_get_contentservice;                                         
            if (iiscommit = 1) then                                             
              rollback work;                                                    
            end if;                                                             
            return;                                                             
          end if;                                                               
        exception                                                               
        when others then                                                        
          close c_get_contentservice;                                           

          if (iiscommit = 1) then                                               
            rollback work;                                                      
          end if;                                                               
          result := -170001;                                                    
          resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr(
 sqlerrm,1,100);                                                                
                                                                                
          dbms_output.put_line(functionname||'result = '||result);              
          dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||
substr( sqlerrm,1,100));                                                        
                                                                                
          return;                                                               
        end;                                                                    

      end loop;                                                                 
    close c_get_contentservice;                                                 
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
