	sEXTENDFIELD4                         in out varchar2,                         
	sEXTENDFIELD5                         in out varchar2,                         
	sVspid                         		in out number,                                
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spcategoryquery: ';                              
begin                                                                           
  result := 0;                                                                  
                                                                                

  begin                                                                         
    select count(1)                                                             
