    from category                                                               
    where categoryid = lcategoryid;                                             
    if (lcounter != 1) then                                                     
      result := -170003;                                                        
      resultdesc := 'query record not found.';                                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('query record not found.');                          
      return;                                                                   
    end if;                                                                     
                                                                                

    select parentid,domainid,                                                   
           name,code,code2,seq,description,status,internalcode,lockflag,guilockf
lag,maxdtlcount,tabled, to_char(cenddate,'yyyymmddhh24miss'), to_char(cstartdate
,'yyyymmddhh24miss'),labelid,releasetype,programautoreleasedomains,existchildand
dtl,CATEGORYTYPE,TEMPLATE,EXTENDFIELD1,EXTENDFIELD2,EXTENDFIELD3,EXTENDFIELD4,EX
TENDFIELD5,Vspid                                                                
                                                                                
    into lparentid,ldomainid,                                                   
         sname,scode,scode2,lseq,sdescription,sstatus,sinternalcode,slockflag,sg
uilockflag,smaxdtlcount,stabled,dcenddate,dcstartdate,llabelid,sreleasetype,spro
gramautoreleasedomains,sexistchildanddtl,sCATEGORYTYPE,sTEMPLATE,sEXTENDFIELD1,s
EXTENDFIELD2,sEXTENDFIELD3,sEXTENDFIELD4,sEXTENDFIELD5,sVspid                   
                                                                                

    from category                                                               
    where categoryid = lcategoryid;                                             
                                                                                
  exception                                                                     
  when others then                                                              
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                

    return;                                                                     
  end;                                                                          
                                                                                
  result := 0;                                                                  
  resultdesc := to_char(lcategoryid);                                           
  dbms_output.put_line(functionname||'result = '||result);                      
