(                                                                               

  lcategorydtlid                        in number,                              
  lsequence                             in number,                              
  lcategoryid                           in number,                              
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              
  lsequence2                            in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                

  lsequence_temp number(9);                                                     
  lsequence2_temp number(9);                                                    
  lcategorydtlid_temp number(9);                                                
  functionname varchar(40) := 'spcategorydtlmodify ';                           
  lcounter       number;                                                        
                                                                                
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
                                                                                
                                                                                
  if (lcategorydtlid is null) then                                              

	    select count(1) into lcounter from categorydtl                             
	    where categoryid = lcategoryid and objtype=sobjtype and objid=lobjid ;     
	    if (lcounter != 1) then                                                    
	      result := 0;                                                             
	      resultdesc := 'no row affected.';                                        
	      dbms_output.put_line(functionname||'result = '||result);                 
	      dbms_output.put_line('no row affected.');                                
	      return;                                                                  
	    end if;                                                                    
  	select categorydtlid into lcategorydtlid_temp from categorydtl               
  	where categoryid = lcategoryid and objtype=sobjtype and objid=lobjid ;       
  else                                                                          
  	lcategorydtlid_temp := lcategorydtlid;                                       

  end if;                                                                       
                                                                                
  if (lsequence is null) then                                                   
    lsequence_temp := 9999;                                                     
  else                                                                          
    lsequence_temp := lsequence;                                                
  end if;                                                                       
  if (lsequence2 is null) then                                                  
    lsequence2_temp := 0;                                                       
  else                                                                          
    lsequence2_temp := lsequence2;                                              
  end if;                                                                       
                                                                                

  begin                                                                         
                                                                                
    update categorydtl                                                          
    set sequence = lsequence_temp,                                              
        sequence2 = lsequence2_temp,                                            
        updatetime = sysdate                                                    
    where categorydtlid = lcategorydtlid_temp;                                  
                                                                                
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            

    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
                                                                                
  if iiscommit = 1 then                                                         

    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lcategorydtlid);                                        
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spcategorydtladd                                                      
(                                                                               
  lcategorydtlid                        in number,                              
  lsequence                             in number,                              
  lcategoryid                           in number,                              
  sobjtype                              in varchar2,                            
  lobjid                                in number,                              

  lsequence2                            in number,                              
  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcategorydtlid_temp number(9);                                                
  lsequence_temp number(9);                                                     
  lsequence2_temp number(9);                                                    
  supdateflag char(1);                                                          
  lcounter number(9);                                                           

  ldomainid number(9);                                                          
  functionname varchar(40) := 'spcategorydtladd: ';                             
                                                                                
  --starttime number(9);                                                        
  --currtime number(9);                                                         
                                                                                
begin                                                                           
  result := 0;                                                                  
 --select  dbms_utility.get_time into starttime from dual;                      
                                                                                
  select count(1)                                                               
  into lcounter                                                                 
  from category                                                                 

  where categoryid = lcategoryid;                                               
  if (lcounter <= 0) then                                                       
    result := -174101;                                                          
    resultdesc := 'categoryid not exist.';                                      
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('categoryid not exist.');                              
    return;                                                                     
  end if;                                                                       
                                                                                
  if (lobjid is null) then                                                      
    result := -174102;                                                          
    resultdesc := 'lobjid is not allow empty.';                                 
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('lobjid is not allow empty.');                         
    return;                                                                     
  end if;                                                                       
                                                                                
  if (sobjtype is null) then                                                    
    result := -174103;                                                          
    resultdesc := 'type is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('type is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
                                                                                
	select domainid into ldomainid from category where categoryid = lcategoryid;   

/*                                                                              
  if (ldomainid is null) then                                                   
    result := -174104;                                                          
    resultdesc := 'domainid is not allow empty.';                               
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('type is not allow empty.');                           
    return;                                                                     
  end if;                                                                       
*/                                                                              
  if  (sobjtype = '1') then                                                     
    select count(1)                                                             
    into lcounter                                                               
    from series                                                                 

    where seriesid = lobjid;                                                    
    if (lcounter <= 0) then                                                     
      --result := -174110;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table series.';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   
    end if;                                                                     
  if (ldomainid Is Not null) then                                               
    select count(1)                                                             
    into lcounter                                                               
    from domainobjects                                                          

    where domainid = ldomainid                                                  
    and objtype = 35                                                            
    and objid = lobjid;                                                         
    if (lcounter <= 0) then                                                     
      --result := -174117;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table domainobjects.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   
    end if;                                                                     
  End If;                                                                       
  elsif (sobjtype = '8') then                                                   

    select count(1)                                                             
    into lcounter                                                               
    from program                                                                
    where programid = lobjid;                                                   
    if (lcounter <= 0) then                                                     
      --result := -174108;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table program.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('lobjid not exist in table program.');               
      return;                                                                   
    end if;                                                                     
  if (ldomainid Is Not null) then                                               

    select count(1)                                                             
    into lcounter                                                               
    from domainobjects                                                          
    where domainid = ldomainid                                                  
    and objtype = 1                                                             
    and objid = lobjid;                                                         
    if (lcounter <= 0) then                                                     
      --result := -174117;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table domainobjects.';                  
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   

    end if;                                                                     
  End if ;                                                                      
  elsif (sobjtype = 'A') then                                                   
    select count(1)                                                             
    into lcounter                                                               
    from bundledcontent                                                         
    where bundledcontentid = lobjid;                                            
    if (lcounter <= 0) then                                                     
      --result := -174111;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table bundledcontent.';                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table bundledcontent.');         

      return;                                                                   
    end if;                                                                     
  elsif (sobjtype = 'C') then                                                   
    select count(1)                                                             
    into lcounter                                                               
    from channel                                                                
    where channelid = lobjid;                                                   
    if (lcounter <= 0) then                                                     
      --result := -174112;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table channel.';                        
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table channel.');                

      return;                                                                   
    end if;                                                                     
    if (ldomainid is Not null) then                                             
    select count(1)                                                             
    into lcounter                                                               
    from domainobjects                                                          
    where domainid = ldomainid                                                  
    and objtype = 12                                                            
    and objid = lobjid;                                                         
    if (lcounter <= 0) then                                                     
      --result := -174117;                                                      
      result := 0;                                                              
      resultdesc := 'objid not exist in table domainobjects.';                  

      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table series.');                 
      return;                                                                   
    end if;                                                                     
    End If;                                                                     
  elsif (sobjtype = 'G') then                                                   
    select count(1)                                                             
    into lcounter                                                               
    from schedule                                                               
    where scheduleid = lobjid;                                                  
    if (lcounter <= 0) then                                                     
      --result := -174116;                                                      
      result := 0;                                                              

      resultdesc := 'objid not exist in table schedule.';                       
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('objid not exist in table schedule.');               
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (lsequence is null) then                                                   
    lsequence_temp := 9999;                                                     
  else                                                                          
    lsequence_temp := lsequence;                                                
  end if;                                                                       
  if (lsequence2 is null) then                                                  

    lsequence2_temp := 0;                                                       
  else                                                                          
    lsequence2_temp := lsequence2;                                              
  end if;                                                                       
  begin                                                                         
    supdateflag := '0';                                                         
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from categorydtl                                                            
    where categoryid = lcategoryid                                              
    and objid = lobjid                                                          
    and objtype = sobjtype;                                                     

    if (lcounter = 1) then                                                      
      select categorydtlid                                                      
      into lcategorydtlid_temp                                                  
      from categorydtl                                                          
      where categoryid = lcategoryid                                            
      and objid = lobjid                                                        
      and objtype = sobjtype;                                                   
      supdateflag := '1';                                                       
    end if;                                                                     
                                                                                
    if (supdateflag = '1') then                                                 
      update categorydtl                                                        
      set sequence = lsequence_temp where categorydtlid = lcategorydtlid_temp;  

    else                                                                        
      if (lcategorydtlid is null) then                                          
        select categorydtlid.nextval into lcategorydtlid_temp from dual;        
      else                                                                      
        lcategorydtlid_temp := lcategorydtlid;                                  
      end if;                                                                   
                                                                                
                                                                                
                                                                                
      insert into categorydtl(categorydtlid,sequence,categoryid,objid,objtype,se
quence2,updatetime)                                                             
                                                                                
      values(lcategorydtlid_temp,lsequence_temp,lcategoryid,lobjid,sobjtype,lseq

uence2_temp,sysdate);                                                           
                                                                                
                                                                                
    end if;                                                                     
                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      

                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     
  end;                                                                          
  --select  dbms_utility.get_time into currtime from dual;                      
  --insert into testexec(flag, sec) values (lcategorydtlid ||'ADD_2',(currtime -
 starttime));                                                                   
                                                                                
                                                                                
  if iiscommit = 1 then                                                         

    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lcategorydtlid_temp);                                   
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spcategoryadd                                                         
(                                                                               
  lcategoryid                           in number,                              
  lparentid                             in number,                              
  ldomainid                             in number,                              
  sname                                 in varchar2,                            
  scode                                 in varchar2,                            

  scode2                                in varchar2,                            
  lseq                                  in number,                              
  sdescription                          in varchar2,                            
  sstatus                               in varchar2,                            
  sinternalcode                         in varchar2,                            
  slockflag                             in varchar2,                            
  sguilockflag                          in varchar2,                            
  smaxdtlcount                          in number,                              
  stabled                               in varchar2,                            
  dcenddate                             in varchar2,                            
  dcstartdate                           in varchar2,                            
  llabelid                              in number,                              
  sreleasetype                          in varchar2,                            

  sprogramautoreleasedomains            in varchar2,                            
  sorderflag                            in varchar2,                            
  sexistchildanddtl                     in varchar2,                            
	sCATEGORYTYPE                         in number,                               
	sTEMPLATE                             in varchar2,                             
	sEXTENDFIELD1                         in varchar2,                             
	sEXTENDFIELD2                         in varchar2,                             
	sEXTENDFIELD3                         in varchar2,                             
	sEXTENDFIELD4                         in varchar2,                             
	sEXTENDFIELD5                         in varchar2,                             
	sVspid                         in number,                                      
  lstaffid                              in number,                              
  iiscommit                             in number,                              

  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcategoryid_temp number(9);                                                   
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sstatus_temp varchar2(2) := '0';                                              
  lcounter number(9);                                                           
  slockflag_temp varchar2(2) := '0';                                            
  sguilockflag_temp varchar2(2) := '0';                                         
  stabled_temp  varchar2(2) := '0';                                             

  dcenddate_temp date;                                                          
  dcstartdate_temp date;                                                        
  smaxdtlcount_temp number(4);                                                  
  functionname varchar(40) := 'spcategoryadd: ';                                
begin                                                                           
  result := 0;                                                                  
                                                                                
                                                                                
  if (sname is null) then                                                       
    result := -174002;                                                          
    resultdesc := 'name is not allow empty.';                                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('name is not allow empty.');                           

    return;                                                                     
  end if;                                                                       
                                                                                
  if (stabled is not null) then                                                 
    stabled_temp := stabled;                                                    
  end if;                                                                       
  if (sstatus is not null) then                                                 
    sstatus_temp := sstatus;                                                    
  end if;                                                                       
  if (dcstartdate is null) then                                                 
      dcstartdate_temp := null;                                                 
    else                                                                        
      select to_date(dcstartdate,'yyyymmddhh24miss') into dcstartdate_temp from 

dual;                                                                           
                                                                                
  end if;                                                                       
  if (dcenddate is null) then                                                   
      dcenddate_temp := null;                                                   
    else                                                                        
      select to_date(dcenddate,'yyyymmddhh24miss') into dcenddate_temp from dual
;                                                                               
                                                                                
  end if;                                                                       
                                                                                
                                                                                
  if (sguilockflag is not null) then                                            

    sguilockflag_temp := sguilockflag;                                          
  end if;                                                                       
                                                                                
  if (ldomainid is not null) then                                               
    select count(1)                                                             
    into lcounter                                                               
    from domain                                                                 
    where domainid = ldomainid;                                                 
                                                                                
    if (lcounter <= 0) then                                                     
      if (iiscommit = 1) then                                                   
        rollback work;                                                          
      end if;                                                                   

      result := -174020;                                                        
      resultdesc := 'domainid not exist in table domain.';                      
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('domainid not exist in table domain.');              
      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  if (sstatus_temp is null or sstatus_temp not in ('0','1')) then               
    result := -174005;                                                          
    resultdesc := 'status is empty or not in (''0'',''1'').';                   
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('status is empty or not in (''0'',''1'').');           

    return;                                                                     
  end if;                                                                       
                                                                                
  if (lparentid is not null) then                                               
    select count(1)                                                             
    into lcounter                                                               
    from category                                                               
    where categoryid = lparentid;                                               
    if (lcounter <= 0) then                                                     
      result := -174006;                                                        
      resultdesc := 'parentid not exist.';                                      
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('parentid not exist.');                              

      return;                                                                   
    end if;                                                                     
                                                                                
    select count(1)                                                             
    into lcounter                                                               
    from category                                                               
    where parentid = lparentid                                                  
    and name = sname;                                                           
    if (lcounter > 0) then                                                      
      result := -174010;                                                        
      resultdesc := 'name repeated at the same level.';                         
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('name repeated at the same level.');                 

      return;                                                                   
    end if;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
    if (lcategoryid is null) then                                               
      select categoryid.nextval into lcategoryid_temp from dual;                
    else                                                                        
      lcategoryid_temp := lcategoryid;                                          
    end if;                                                                     
                                                                                
    scode_temp := scode;                                                        
    if (scode is null) then                                                     

      spgetglobalcode(null,ctmsconstant_def.globalcode_category,lcategoryid_temp
,scode_temp,result);                                                            
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     
                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                
    else                                                                        
      scode2_temp := scode2;                                                    

    end if;                                                                     
                                                                                
                                                                                
    if (slockflag is null) then                                                 
      slockflag_temp := '0';                                                    
    else                                                                        
      slockflag_temp := slockflag;                                              
    end if;                                                                     
                                                                                
    if(smaxdtlcount is null) then                                               
      smaxdtlcount_temp := 999;                                                 
    else                                                                        
      smaxdtlcount_temp := smaxdtlcount;                                        

    end if;                                                                     
                                                                                
                                                                                
    insert into category(categoryid,parentid,domainid,status,                   
                             name,code,code2,seq,description,internalcode,create
staffid,lockflag,guilockflag,maxdtlcount,tabled,cenddate,cstartdate,labelid,rele
asetype,programautoreleasedomains,orderflag,existchildanddtl,                   
                                                                                
CATEGORYTYPE,TEMPLATE,EXTENDFIELD1,EXTENDFIELD2,EXTENDFIELD3,EXTENDFIELD4,EXTEND
FIELD5,Vspid)                                                                   
                                                                                
    values(lcategoryid_temp,lparentid,ldomainid,sstatus_temp,                   
           sname,scode_temp,scode2_temp,lseq,sdescription,sinternalcode,lstaffid

,slockflag_temp,sguilockflag_temp,smaxdtlcount_temp,stabled_temp,dcenddate_temp,
dcstartdate_temp,llabelid,sreleasetype,sprogramautoreleasedomains,sorderflag,sex
istchildanddtl,sCATEGORYTYPE,sTEMPLATE,sEXTENDFIELD1,sEXTENDFIELD2,sEXTENDFIELD3
,sEXTENDFIELD4,sEXTENDFIELD5,sVspid);                                           
                                                                                
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_category,lcategoryid_temp,scode_
temp,scode2_temp,'0',null,null,null,result);                                    
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     

                                                                                
  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              

                                                                                
    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lcategoryid_temp);                                      
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
PROCEDURE spCastRoleRemove                                                      
(                                                                               
  lCASTROLEID                           IN number,                              

  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              
  lCounter number(9);                                                           
  sSql Varchar2(1024);                                                          
  FunctionName varchar(40) := 'spCastRoleRemove: ';                             
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter from CastRole where CASTROLEID = lCASTROLEID;   

  IF (lCounter != 1) THEN                                                       
    result := 0;                                                                
    ResultDesc := 'no row affected.';                                           
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('no row affected.');                                   
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  IF (lCASTROLEID in (1,2,3) or lCASTROLEID > 999999000) THEN                   
    result := -170803;                                                          
    ResultDesc := 'Can not delete the system castrole.';                        
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Can not delete the system castrole.');                

    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  select count(1) into lCounter from CastActRole where CASTROLEID = lCASTROLEID;
                                                                                
                                                                                
  IF (lCounter > 0) THEN                                                        
    result := -170804;                                                          
    ResultDesc := 'related record in table CastActRole.';                       
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record in table CastActRole.');               
    RETURN;                                                                     
  END IF;                                                                       

                                                                                
  BEGIN                                                                         
    delete from CastRole where CASTROLEID = lCASTROLEID;                        
                                                                                
                                                                                
                                                                                
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER

RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  

  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
PROCEDURE spCastRoleQuery                                                       
(                                                                               
  lCASTROLEID                           IN OUT number,                          
  sNAME                                 IN OUT Varchar2,                        
  lSEQUENCE                             IN OUT number,                          
  sDESCRIPTION                          IN OUT Varchar2,                        
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              
  lCounter number(9);                                                           

  FunctionName varchar(40) := 'spCastRoleQuery: ';                              
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  BEGIN                                                                         
    select count(1)                                                             
    into lCounter                                                               
    from CastRole                                                               
    where CastRoleID = lCastRoleID;                                             
    IF (lCounter != 1) THEN                                                     
      result := -170003;                                                        
      ResultDesc := 'Query record not found.';                                  
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  

      DBMS_OUTPUT.PUT_LINE('Query record not found.');                          
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    select NAME,SEQUENCE,DESCRIPTION                                            
    into sNAME,lSEQUENCE,sDESCRIPTION                                           
    from CastRole                                                               
    where CastRoleID = lCastRoleID;                                             
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      

                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
