  --  RETURN;                                                                   
  --END IF;                                                                     
                                                                                
  BEGIN                                                                         
    update CastRole                                                             
    set NAME = sNAME,                                                           
        SEQUENCE = lSEQUENCE,                                                   
        DESCRIPTION = sDESCRIPTION,                                             
        CREATEDATE = sysdate,                                                   
        CREATESTAFFID = lSTAFFID                                                
    where CASTROLEID = lCASTROLEID;                                             
                                                                                
	/*                                                                             

    select substr(' update CastRole set '||                                     
                     ' NAME='''||sNAME||''','||                                 
                     ' SEQUENCE='||nvl(to_char(lSEQUENCE),'null')||','||        
                     ' DESCRIPTION='''||sDESCRIPTION||''','||                   
                     ' CREATEDATE='''||sysdate||''','||                         
                     ' CREATESTAFFID='||nvl(to_char(lSTAFFID),'null')||' '||    
    'where CASTROLEID = '||nvl(to_char(lCASTROLEID),'null')||';',1,1024)        
    into sSql from dual;*/                                                      
                                                                                
                                                                                
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     

      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         

    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
