PROCEDURE spCastRemove                                                          
(                                                                               
  lCASTID                               IN number,                              
  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         

)                                                                               
IS                                                                              
  lCounter number(9);                                                           
  FunctionName varchar(40) := 'spCastRemove: ';                                 
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter from Cast where CASTID = lCASTID;               
  IF (lCounter != 1) THEN                                                       
    result := 0;                                                                
    ResultDesc := 'no row affected.';                                           
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('no row affected.');                                   

    RETURN;                                                                     
  END IF;                                                                       
                                                                                
 --select count(1) into lCounter from ContentClassMap                           
 /* where OBJECTID = lCASTID                                                    
  and TYPE = '7';                                                               
  IF (lCounter > 0) THEN                                                        
    result := -170603;                                                          
    ResultDesc := 'related record exists in Table ContentClassMap.';            
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record exists in Table ContentClassMap.');    
    RETURN;                                                                     
  END IF;*/                                                                     

                                                                                
  select count(1)                                                               
  into lCounter                                                                 
  from ProgramCasts a, Castactrole b                                            
  where a.castactroleid = b.castactroleid                                       
  and b.castid = lCASTID;                                                       
  IF (lCounter > 0) THEN                                                        
    result := -170604;                                                          
    ResultDesc := 'related record exists in Table ProgramCasts.';               
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record exists in Table ProgramCasts.');       
    RETURN;                                                                     
  END IF;                                                                       

                                                                                
  select count(1)                                                               
  into lCounter                                                                 
  from Seriescasts a, Castactrole b                                             
  where a.castactroleid = b.castactroleid                                       
  and b.castid = lCASTID;                                                       
  IF (lCounter > 0) THEN                                                        
    result := -170605;                                                          
    ResultDesc := 'related record exists in Table Seriescasts.';                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record exists in Table Seriescasts.');        
    RETURN;                                                                     
  END IF;                                                                       

                                                                                
  BEGIN                                                                         
    delete from picturemap p where p.objtype = '7' and p.objid = lCASTID;       
	delete from metapicture m where m.metapictureid in (select p.metapictureid from
 picturemap p where p.objtype = '7' and p.objid=lCASTID);                       
                                                                                
                                                                                
                                                                                
    delete from AssetidMap                                                      
    where AssetType = 'E'                                                       
    and mamid in                                                                
    (                                                                           
      select CastActRoleID                                                      

      from CastActrole                                                          
      where CastID = lCASTID                                                    
    );                                                                          
                                                                                
    update GlobalCodeMap                                                        
    set Status = '1'                                                            
    where OBJECTTYPE=CTMSCONSTANT_DEF.GlobalType_CastRoleMap                    
    and OBJECTID in (select CastActRoleID from CastActrole where CASTID = lCASTI
D);                                                                             
                                                                                
                                                                                
    delete from CastActrole where CASTID = lCASTID;                             
                                                                                

    delete from AssetidMap                                                      
    where AssetType = '3'                                                       
    and mamid = lCASTID;                                                        
                                                                                
    update GlobalCodeMap                                                        
    set Status = '1'                                                            
    where OBJECTTYPE=CTMSCONSTANT_DEF.GlobalType_Cast                           
    and OBJECTID=lCASTID;                                                       
                                                                                
    --delete from Cast where CASTID = lCASTID;                                  
    update cast set status = '9' where castid = lCASTID;                        
                                                                                
  EXCEPTION                                                                     

  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     

  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
