  sPERSON_SEARCHNAME                    IN OUT Varchar2,                        
  sLASTNAME                             IN OUT Varchar2,                        
  sMIDDLENAME                           IN OUT Varchar2,                        
  sFIRSTNAME                            IN OUT Varchar2,                        
  sCode                                 IN OUT Varchar2,                        
  sSEX                                  IN OUT Varchar2,                        
  sBIRTHDAY                             IN OUT Varchar2,                        
  sHOMETOWN                             IN OUT Varchar2,                        
  sEDUCATION                            IN OUT Varchar2,                        
  fHEIGHT                               IN OUT number,                          

  fWEIGHT                               IN OUT number,                          
