  sMARRIAGE                             IN OUT Varchar2,                        
  sFAVORITE                             IN OUT Varchar2,                        
  sWEBPAGE                              IN OUT Varchar2,                        
  sDESCRIPTION                          IN OUT Varchar2,                        
  sCODE2                                IN OUT Varchar2,                        
  lSTAFFID                              IN OUT Number,                          
