  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              

  lCounter number(9);                                                           
  FunctionName varchar(40) := 'spCastQuery: ';                                  
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  BEGIN                                                                         
    select count(1)                                                             
    into lCounter                                                               
    from Cast                                                                   
    where CASTID = lCASTID;                                                     
    IF (lCounter != 1) THEN                                                     
      result := -170003;                                                        
      ResultDesc := 'Query record not found.';                                  

      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('Query record not found.');                          
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    select NAME,LANGUAGE,STATUS,PERSONDISPLAYNAME,PERSONSORTNAME,               
                     PERSONSEARCHNAME,LASTNAME,MIDDLENAME,FIRSTNAME,            
                     SEX,BIRTHDAY,HOMETOWN,EDUCATION,                           
                     HEIGHT,WEIGHT,BLOODGROUP,MARRIAGE,FAVORITE,WEBPAGE,        
                     DESCRIPTION,CODE,Code2                                     
    into sPERSONNAME,sLANGUAGE,sSTATUS,sPERSONNAME_DISPLAY,sPERSON_SORTNAME,    
         sPERSON_SEARCHNAME,sLASTNAME,sMIDDLENAME,sFIRSTNAME,                   
         sSEX,sBIRTHDAY,sHOMETOWN,sEDUCATION,                                   

         fHEIGHT,fWEIGHT,sBLOODGROUP,sMARRIAGE,sFAVORITE,sWEBPAGE,              
         sDESCRIPTION,sCODE,sCODE2                                              
    from Cast                                                                   
    where CastID = lCastID;                                                     
                                                                                
   -- spGetCode2(CTMSCONSTANT_DEF.GlobalType_Cast, lCastID, sCode2);            
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    

    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
                                                                                
  result := 0;                                                                  
  ResultDesc := to_char(lCASTID);                                               
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
