    sCode_Temp Varchar2(160);                                                   
    lCounter number(9);                                                         
    lCASTID_TEMP number(9);                                                     
    sPERSONNAME_DISPLAY_Temp varchar2(64);                                      
    sCode2_Temp Varchar2(160);                                                  
    sSql Varchar2(5012);                                                        
    FunctionName varchar(40) := 'spCastModify: ';                               
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter from Cast where CASTID = lCASTID;               

  IF (lCounter != 1) THEN                                                       
    result := 0;                                                                
    ResultDesc := 'no row affected.';                                           
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('no row affected.');                                   
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  IF (sFIRSTNAME is null) THEN                                                  
    result := -170601;                                                          
    ResultDesc := 'FIRSTNAME is not allow empty.';                              
