    DBMS_OUTPUT.PUT_LINE('FIRSTNAME is not allow empty.');                      

    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  sPERSONNAME_DISPLAY_Temp := sPERSONNAME_DISPLAY;                              
