    END IF;                                                                     
                                                                                
    sCode_Temp := sCode;                                                        
    IF (sCODE is null) THEN                                                     
      spGetGlobalCode(999999999,CTMSCONSTANT_DEF.GlobalCode_Cast,lCASTID_TEMP,sC
ode_Temp,result);                                                               
                                                                                
