                     DESCRIPTION,Code,Code2,Createstaffid)                      
    values(lCASTID_TEMP,sPERSONNAME_DISPLAY_Temp,sLANGUAGE,sSTATUS,sPERSONNAME_D
ISPLAY_Temp,sPERSON_SORTNAME,                                                   
                                                                                

           sPERSON_SEARCHNAME,sLASTNAME,sMIDDLENAME,sFIRSTNAME,                 
           sSEX,to_date(sBIRTHDAY,'yyyy-mm-ddhh24miss'),sHOMETOWN,sEDUCATION,   
           fHEIGHT,fWEIGHT,sBLOODGROUP,sMARRIAGE,sFAVORITE,sWEBPAGE,            
           sDESCRIPTION,sCode_Temp,sCode2_Temp,lSTAFFID);                       
                                                                                
    spAddGlobalCode(CTMSCONSTANT_DEF.GlobalType_Cast,lCASTID_TEMP,sCode_Temp,sCo
de2_Temp,'0',null,null,null,result);                                            
                                                                                
    IF (result != 0) THEN                                                       
      rollback;                                                                 
