                              'FAVORITE,'||                                     
                              'WEBPAGE,'||                                      
                              'CODE,'||                                         
                              'CODE2,'||                                        
                              'DESCRIPTION) '||                                 
                  'values('||                                                   

                    nvl(to_char(lCASTID_TEMP),'null')||','||                    
                    ''''||sPERSONNAME||''','||                                  
                    ''''||sLANGUAGE||''','||                                    
                    ''''||sSTATUS||''','||                                      
                    ''''||sPERSONNAME_DISPLAY_Temp||''','||                     
                    ''''||sPERSON_SORTNAME||''','||                             
