PROCEDURE spCastActRoleRemove                                                   
(                                                                               
  lCASTACTROLEID                        IN number,                              
  lCASTID                               IN number,                              
  lCASTROLEID                           IN number,                              

  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               
IS                                                                              
  lCounter number(9);                                                           
  lCASTACTROLEID_TEMP number(9);                                                
  FunctionName varchar(40) := 'spCastActRoleRemove: ';                          
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  IF (lCASTACTROLEID is null) THEN                                              

    select count(1)                                                             
    into lCounter                                                               
    from CastActRole                                                            
    where CASTID = lCASTID                                                      
    and CASTROLEID = lCASTROLEID;                                               
    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                

    select CASTACTROLEID                                                        
    into lCASTACTROLEID_TEMP                                                    
    from CastActRole                                                            
    where CASTID = lCASTID                                                      
    and CASTROLEID = lCASTROLEID;                                               
  ELSE                                                                          
    lCASTACTROLEID_TEMP := lCASTACTROLEID;                                      
  END IF;                                                                       
                                                                                
  select count(1)                                                               
  into lCounter                                                                 
  from ProgramCasts a, Castactrole b                                            
  where a.castactroleid = b.castactroleid                                       

  and a.castactroleid = lCASTACTROLEID_TEMP;                                    
  IF (lCounter > 0) THEN                                                        
    result := -170614;                                                          
    ResultDesc := 'related record exists in Table ProgramCasts.';               
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record exists in Table ProgramCasts.');       
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  select count(1)                                                               
  into lCounter                                                                 
  from Seriescasts a, Castactrole b                                             
  where a.castactroleid = b.castactroleid                                       

  and a.castactroleid = lCASTACTROLEID_TEMP;                                    
  IF (lCounter > 0) THEN                                                        
    result := -170615;                                                          
    ResultDesc := 'related record exists in Table Seriescasts.';                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('related record exists in Table Seriescasts.');        
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  BEGIN                                                                         
    select count(1) into lCounter from CastActRole where CASTACTROLEID = lCASTAC
TROLEID_TEMP;                                                                   
                                                                                

    IF (lCounter != 1) THEN                                                     
      result := 0;                                                              
      ResultDesc := 'no row affected.';                                         
      DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                  
      DBMS_OUTPUT.PUT_LINE('no row affected.');                                 
      RETURN;                                                                   
    END IF;                                                                     
                                                                                
    delete from AssetidMap                                                      
    where AssetType = 'E'                                                       
    and mamid = lCASTACTROLEID_TEMP;                                            
                                                                                
    update GlobalCodeMap                                                        

    set Status = '1'                                                            
    where OBJECTTYPE=CTMSCONSTANT_DEF.GlobalType_CastRoleMap                    
    and OBJECTID=lCASTACTROLEID_TEMP;                                           
                                                                                
    delete from CastActRole where CASTACTROLEID = lCASTACTROLEID_TEMP;          
  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      

                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                
    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result :=0;                                                                   
  ResultDesc := 'Successful!';                                                  
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      

END;                                                                            
PROCEDURE spCastActRoleAdd                                                      
(                                                                               
  lCASTACTROLEID                        IN number,                              
  lCASTID                               IN number,                              
  lCASTROLEID                           IN number,                              
  sCode                                 IN Varchar2,                            
  sCode2                                IN Varchar2,                            
  lSTAFFID                              IN Number,                              
  iIsCommit                             IN Number,                              
  result                                IN OUT Number,                          
  ResultDesc                            IN OUT Varchar2                         
)                                                                               

IS                                                                              
  lCounter number(9);                                                           
  lCASTACTROLEID_TEMP number(9);                                                
  sCode_Temp varchar2(160);                                                     
  sCode2_Temp varchar2(160);                                                    
  FunctionName varchar(40) := 'spCastActRoleAdd: ';                             
BEGIN                                                                           
  result :=0;                                                                   
                                                                                
  select count(1) into lCounter FROM Cast                                       
  where CASTID = lCASTID;                                                       
  IF (lCounter <= 0) THEN                                                       
    result := -170901;                                                          

    ResultDesc := 'CASTID not found.';                                          
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('CASTID not found.');                                  
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  select count(1) into lCounter FROM CASTROLE                                   
  where CASTROLEID = lCASTROLEID;                                               
  IF (lCounter <= 0) THEN                                                       
    result := -170902;                                                          
    ResultDesc := 'CASTROLEID not found.';                                      
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('CASTROLEID not found.');                              

    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  select count(1) into lCounter FROM CastActRole                                
  where CASTROLEID = lCASTROLEID and CASTID = lCASTID;                          
  IF (lCounter > 0) THEN                                                        
    RETURN;                                                                     
  END IF;                                                                       
                                                                                
  BEGIN                                                                         
    IF (lCASTACTROLEID is null) THEN                                            
      select CASTACTROLEID.nextval into lCASTACTROLEID_TEMP from dual;          
    ELSE                                                                        

      lCASTACTROLEID_TEMP := lCASTACTROLEID;                                    
    END IF;                                                                     
                                                                                
    sCode_Temp := sCode;                                                        
    IF (sCODE is null) THEN                                                     
      spGetGlobalCode(999999999,CTMSCONSTANT_DEF.globalcode_castactrole,lCASTACT
ROLEID_TEMP,sCode_Temp,result);                                                 
                                                                                
      IF (result != 0) THEN                                                     
        IF (iIsCommit = 1) THEN ROLLBACK WORK; END IF;                          
        RETURN;                                                                 
      END IF;                                                                   
    END IF;                                                                     

                                                                                
    sCode2_Temp := sCode2;                                                      
    IF (sCode2 is null) THEN                                                    
      spGetGlobalCode(999999999,CTMSCONSTANT_DEF.globalcode_castactrole,lCASTACT
ROLEID_TEMP,sCode2_Temp,result);                                                
                                                                                
      IF (result != 0) THEN                                                     
        IF (iIsCommit = 1) THEN ROLLBACK WORK; END IF;                          
        RETURN;                                                                 
      END IF;                                                                   
    END IF;                                                                     
                                                                                
    spAddGlobalCode(CTMSCONSTANT_DEF.GlobalType_CastRoleMap,lCASTACTROLEID_TEMP,

sCode_Temp,sCode2_Temp,'0',null,null,null,result);                              
                                                                                
    IF (result != 0) THEN                                                       
      rollback;                                                                 
      return;                                                                   
    END IF;                                                                     
                                                                                
    insert into CastActRole(CASTACTROLEID,CASTID,CASTROLEID,Code,Code2,createdat
e)                                                                              
                                                                                
    values(lCASTACTROLEID_TEMP,lCASTID,lCASTROLEID,sCode_Temp,sCode2_Temp,sysdat
e);                                                                             
                                                                                

  EXCEPTION                                                                     
  WHEN OTHERS THEN                                                              
    IF (iIsCommit = 1) THEN                                                     
      ROLLBACK WORK;                                                            
    END IF;                                                                     
    result := -170001;                                                          
    ResultDesc := 'Oracle error code:'||SQLCODE||'error message:'||SUBSTR( SQLER
RM,1,100);                                                                      
                                                                                
    DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                    
    DBMS_OUTPUT.PUT_LINE('Oracle error code:'||SQLCODE||'error message:'||SUBSTR
( SQLERRM,1,100));                                                              
                                                                                

    RETURN;                                                                     
  END;                                                                          
  IF iIsCommit = 1 THEN                                                         
    COMMIT WORK;                                                                
  END IF;                                                                       
  result := 0;                                                                  
  ResultDesc := to_char(lCASTACTROLEID_TEMP);                                   
  DBMS_OUTPUT.PUT_LINE(FunctionName||'result = '||result);                      
END;                                                                            
procedure spbundledcontentupdatestatus                                          
(                                                                               
  lbundledcontentid                     in number,                              
  sstatus                               in varchar2,                            

  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spbundledcontentupdatestatus: ';                 
                                                                                
begin                                                                           
  result := 0;                                                                  
                                                                                

  begin                                                                         
    if (sstatus is null or sstatus not in ('0','1')) then                       
      result := -174005;                                                        
      resultdesc := 'status is empty or not in (''0'',''1'').';                 
      dbms_output.put_line(functionname||'result = '||result);                  
      dbms_output.put_line('status is empty or not in (''0'',''1'').');         
      return;                                                                   
    end if;                                                                     
                                                                                
    update bundledcontent                                                       
    set status = sstatus,lastupdatetime=sysdate                                 
    where bundledcontentid = lbundledcontentid;                                 
                                                                                

  exception                                                                     
  when others then                                                              
    if (iiscommit = 1) then                                                     
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                

    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spbundledcontentremove                                                
(                                                                               
  lbundledcontentid                     in number,                              
  lstaffid                              in number,                              

  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  lcontentserviceid_temp number(9);                                             
  functionname varchar(40) := 'spbundledcontentremove: ';                       
                                                                                
  cursor c_get_contentservice is                                                
  select contentserviceid from contentservice where objtype='6' and objid=lbundl
edcontentid;                                                                    

                                                                                
                                                                                
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  select count(1) into lcounter from bundledcontent where bundledcontentid = lbu
ndledcontentid;                                                                 
                                                                                
  if (lcounter != 1) then                                                       
    result := 0;                                                                
    resultdesc := 'no row affected.';                                           
    dbms_output.put_line(functionname||'result = '||result);                    

    dbms_output.put_line('no row affected.');                                   
    return;                                                                     
  end if;                                                                       
                                                                                
  begin                                                                         
                                                                                
    update globalcodemap                                                        
    set status = '1'                                                            
    where objecttype=ctmsconstant_def.globaltype_bundledcontent                 
    and objectid=lbundledcontentid;                                             
                                                                                
    delete from picturemap where objtype = '1' and objid = lbundledcontentid;   
    delete from assetidmap where assettype = '6' and mamid=lbundledcontentid;   

    delete from bundledcontentdtl where bundledcontentid = lbundledcontentid;   
    delete from staffbunndledcontentassign where bundledcontentid = lbundledcont
entid;                                                                          
                                                                                
    delete from rolebunndledcontentassign where bundledcontentid = lbundledconte
ntid;                                                                           
                                                                                
    delete from staffdataprivilege where objecttype= '2' and objectid = lbundled
contentid;                                                                      
                                                                                
    delete from roledataprivilege where objecttype= '2' and objectid = lbundledc
ontentid;                                                                       
                                                                                

    delete from bundledcontent where bundledcontentid = lbundledcontentid;      
    delete from categorydtl where objid = lbundledcontentid and objtype = 'A';  
                                                                                
                                                                                
    open c_get_contentservice;                                                  
      loop                                                                      
        begin                                                                   
          fetch c_get_contentservice into lcontentserviceid_temp;               
          exit when c_get_contentservice%notfound;                              
          spcontentserviceremove(lcontentserviceid_temp,lstaffid,iiscommit,resul
t,resultdesc);                                                                  
                                                                                
          if (result != 0) then                                                 

            close c_get_contentservice;                                         
            if (iiscommit = 1) then                                             
              rollback work;                                                    
            end if;                                                             
            return;                                                             
          end if;                                                               
        exception                                                               
        when others then                                                        
          close c_get_contentservice;                                           
          if (iiscommit = 1) then                                               
            rollback work;                                                      
          end if;                                                               
          result := -170001;                                                    

          resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr(
 sqlerrm,1,100);                                                                
                                                                                
          dbms_output.put_line(functionname||'result = '||result);              
          dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||
substr( sqlerrm,1,100));                                                        
                                                                                
          return;                                                               
        end;                                                                    
      end loop;                                                                 
    close c_get_contentservice;                                                 
                                                                                
  exception                                                                     

  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                
    return;                                                                     

  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spbundledcontentquery                                                 
(                                                                               
  lbundledcontentid                     in out number,                          
  ldomainid                             in out number,                          
  sname                                 in out varchar2,                        

  scode                                 in out varchar2,                        
  scode2                                in out varchar2,                        
  spackagetype                          in out varchar2,                        
  sstatus                               in out varchar2,                        
