procedure spbundledcontentadd                                                   
(                                                                               
  lbundledcontentid                     in number,                              
  ldomainid                             in number,                              
  sname                                 in varchar2,                            

  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  spackagetype                          in varchar2,                            
  sstatus                               in varchar2,                            
  flistprice                            in number,                              
  sdescription                          in varchar2,                            
  isequence                             in number,                              
  sinternalcode                         in varchar2,                            
  sguilockflag                          in varchar2,                            
  sbasepackage                          in varchar2,                            
  sOrdernumber                          in varchar2,                            
  dLicensingwindowstart                 in varchar2,                            
  dLicensingwindowend                   in varchar2,                            

  lstaffid                              in number,                              
  iiscommit                             in number,                              
  result                                in out number,                          
  resultdesc                            in out varchar2                         
)                                                                               
is                                                                              
                                                                                
  lbundledcontentid_temp number(9);                                             
  fprice_temp number(12,2) := 0.0;                                              
  scode_temp varchar2(160);                                                     
  scode2_temp varchar2(160);                                                    
  sguilockflag_temp varchar2(2) :=0;                                            
  lcounter number(9);                                                           

  sbasepackage_temp  varchar2(2) := '0';                                        
  functionname varchar(40) := 'spbundledcontentadd: ';                          
begin                                                                           
  result := 0;                                                                  
  resultdesc := 'successful!';                                                  
                                                                                
  begin                                                                         
    if (sbasepackage is not null) then                                          
      sbasepackage_temp := sbasepackage;                                        
    end if;                                                                     
  	if (lbundledcontentid is null) then                                          
      select bundledcontentid.nextval into lbundledcontentid_temp from dual;    
    else                                                                        

      lbundledcontentid_temp := lbundledcontentid;                              
    end if;                                                                     
                                                                                
    if (flistprice is not null) then                                            
    	fprice_temp := flistprice;                                                 
  	end if;                                                                      
                                                                                
    if (sguilockflag is not null) then                                          
    	sguilockflag_temp := sguilockflag;                                         
    end if;                                                                     
                                                                                
    if (ldomainid is not null) then                                             
      select count(1)                                                           

      into lcounter                                                             
      from domain                                                               
      where domainid = ldomainid;                                               
                                                                                
      if (lcounter <= 0 And ldomainid != 0) then                                
        if (iiscommit = 1) then                                                 
          rollback work;                                                        
        end if;                                                                 
        result := -174020;                                                      
        resultdesc := 'domainid not exist in table domain.';                    
        dbms_output.put_line(functionname||'result = '||result);                
        dbms_output.put_line('domainid not exist in table domain.');            
        return;                                                                 

      end if;                                                                   
    end if;                                                                     
                                                                                
  	scode_temp := scode;                                                         
    if (scode is null) then                                                     
      spgetglobalcode(null,ctmsconstant_def.globalcode_bundledcontent,lbundledco
ntentid_temp,scode_temp,result);                                                
                                                                                
      if (result != 0) then                                                     
        if (iiscommit = 1) then rollback work; end if;                          
        return;                                                                 
      end if;                                                                   
    end if;                                                                     

                                                                                
    if (scode2 is null) then                                                    
      scode2_temp := scode_temp;                                                
    else                                                                        
      scode2_temp := scode2;                                                    
    end if;                                                                     
                                                                                
    insert into bundledcontent(bundledcontentid,domainid,name,code,code2,       
      status,packagetype,listprice,description,createstaffid,sequence,internalco
de,guilockflag,basepackage,                                                     
                                                                                
      ordernumber,licensingwindowstart,licensingwindowend)                      
    values(lbundledcontentid_temp,ldomainid,sname,scode_temp,scode2_temp,       

           sstatus,spackagetype,fprice_temp,sdescription,lstaffid,isequence,sint
ernalcode,sguilockflag_temp,sbasepackage_temp,                                  
                                                                                
           sordernumber,dLicensingwindowstart,dLicensingwindowend);             
                                                                                
    spaddglobalcode(ctmsconstant_def.globaltype_bundledcontent,lbundledcontentid
_temp,scode_temp,scode2_temp,'0',null,null,null,result);                        
                                                                                
    if (result != 0) then                                                       
      rollback;                                                                 
      return;                                                                   
    end if;                                                                     
                                                                                

  exception                                                                     
  when others then                                                              
    if iiscommit = 1 then                                                       
      rollback work;                                                            
    end if;                                                                     
    result := -170001;                                                          
    resultdesc := 'oracle error code:'||sqlcode||'error message:'||substr( sqler
rm,1,100);                                                                      
                                                                                
    dbms_output.put_line(functionname||'result = '||result);                    
    dbms_output.put_line('oracle error code:'||sqlcode||'error message:'||substr
( sqlerrm,1,100));                                                              
                                                                                

    return;                                                                     
  end;                                                                          
  if iiscommit = 1 then                                                         
    commit work;                                                                
  end if;                                                                       
  result := 0;                                                                  
  resultdesc := to_char(lbundledcontentid_temp);                                
  dbms_output.put_line(functionname||'result = '||result);                      
end;                                                                            
procedure spaddglobalcode                                                       
(                                                                               
  sobjecttype                           in varchar2,                            
  lobjectid                             in number,                              

  scode                                 in varchar2,                            
  scode2                                in varchar2,                            
  sstatus                               in varchar2,                            
  iownertype	                          in number,                               
  iownerid                              in number,                              
  fprice                                in number,                              
  result                                in out number                           
)                                                                               
is                                                                              
                                                                                
  lcounter number(9);                                                           
  functionname varchar(40) := 'spaddglobalcode: ';                              
begin                                                                           

  result := 0;                                                                  
                                                                                
  select count(1) into lcounter from globalcodemap where code = scode and status
 = '1';                                                                         
                                                                                
  if (lcounter > 0) then                                                        
    delete from globalcodemap where code = scode and status = '1';              
  end if;                                                                       
                                                                                
  select count(1) into lcounter from globalcodemap where code2 = scode2 and stat
us = '1';                                                                       
                                                                                
  if (lcounter > 0) then                                                        

    delete from globalcodemap where code2 = scode2 and status = '1';            
  end if;                                                                       
                                                                                
  insert into globalcodemap(objecttype,objectid,code,code2,status,price,ownertyp
e,ownerid,createdate)                                                           
                                                                                
  values(sobjecttype,lobjectid,scode,scode2,sstatus,fprice,iownertype,iownerid,s
ysdate);                                                                        
                                                                                
                                                                                
  result := 0;                                                                  
  dbms_output.put_line(functionname||'result = '||result);                      
exception                                                                       

when others then                                                                
  result := -170017;                                                            
  dbms_output.put_line(functionname||'result = '||result);                      
  return;                                                                       
end;                                                                            
